INSERT INTO v2.psc_codes (code, name, start_date, end_date, full_name, includes, excludes, notes, parent_code, category, level_1_code, level_1_name, level_2_code, level_2_name) VALUES
  ('10', 'WEAPONS', '1979-10-01', null, null, null, null, 'This group includes combat weapons as well as weapon-like noncombat items, such as line throwing devices and pyrotechnic pistols. Also included in this group are weapon neutralizing equipment, such as degaussers, and deception equipment, such as camouflage nets. Excluded from this group are fire control and night devices classifiable in groups 12 or 58.', null, null, null, null, null, null),
  ('1005', 'GUNS, THROUGH 30MM', '2011-10-01', null, 'Guns, through 30 mm', 'Machine guns; Brushes, Machine Gun and Pistol.', 'Turrets, Aircraft.', null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.4', 'Guns'),
  ('1010', 'GUNS, OVER 30MM UP TO 75MM', '2011-10-01', null, 'Guns, over 30 mm up to 75 mm', 'Breech Mechanisms; Mounts Grenade Launchers for Integral-Cartridge Grenades, Single-Shot or Auto-Loading or Automatic-Firing.', null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.4', 'Guns'),
  ('1015', 'GUNS, 75MM THROUGH 125MM', '2011-10-01', null, 'Guns, 75 mm through 125 mm', 'Breech Mechanisms; Mounts; Rammers.', null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.4', 'Guns'),
  ('1020', 'GUNS, OVER 125MM THROUGH 150MM', '2011-10-01', null, 'Guns, over 125 mm through 150 mm Includes Breech Mechanisms, Power Drives; Gun Shields.', 'Includes Breech Mechanisms, Power Drives; Gun Shields.', null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.4', 'Guns'),
  ('1025', 'GUNS, OVER 150MM THROUGH 200MM', '2011-10-01', null, 'Guns, over 150 mm through 200 mm Includes Firing Platforms; Mounts; Gun Shields.', '[Firing Platforms; Mounts; Gun Shields.]', null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.4', 'Guns'),
  ('1030', 'GUNS, OVER 200MM THROUGH 300MM', '2011-10-01', null, 'Guns, over 200 mm through 300 mm Includes Gun Yokes; Rammers; Reflectors.', 'Includes Gun Yokes; Rammers; Reflectors.', null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.4', 'Guns'),
  ('1035', 'GUNS, OVER 300MM', '2011-10-01', null, 'Guns, over 300 mm', 'Breech Mechanisms; Training Gears; Power Drives.', null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.4', 'Guns'),
  ('1040', 'CHEMICAL WEAPONS AND EQUIPMENT', '1978-10-15', null, 'Chemical Weapons and Equipment', 'Flame Throwers; Smoke Generators.', null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.6', 'Weapons'),
  ('1045', 'LAUNCHERS, TORPEDO AND DEPTH CHARGE', '1978-10-15', null, 'Launchers, Torpedo and Depth Charge', 'Depth Charge Tracks; Torpedo Tubes.', null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.6', 'Weapons'),
  ('1055', 'LAUNCHERS, ROCKET AND PYROTECHNIC', '1978-10-15', null, 'Launchers, Rocket and Pyrotechnic', 'Airborne Rocket Launchers adaptable to guided missile use.', 'Specifically designed Airborne Guided Missile Launchers; Jettisonable Rocket Launchers; Launcher Fairings designed for specific airframes; Rifle Grenade Launchers; Grenade Launchers for Integral-Cartridge Grenades, Single-Shot or Auto Loading or Automatic Firing.', null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.6', 'Weapons'),
  ('1070', 'NETS AND BOOMS, ORDNANCE', '1978-12-15', null, 'Nets and Booms, Ordnance', null, null, 'This class includes nets and booms for harbor defense only.', '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.6', 'Weapons'),
  ('1075', 'DEGAUSSING AND MINE SWEEPING EQUIPMENT', '2011-10-01', null, 'Degaussing and Mine Sweeping Equipment', null, null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.6', 'Weapons'),
  ('1080', 'CAMOUFLAGE AND DECEPTION EQUIPMENT', '1978-10-15', null, 'Camouflage and Deception Equipment', 'Dummy Artillery, Aircraft and Vehicles; Garnished Nets.', null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.6', 'Weapons'),
  ('1090', 'ASSEMBLIES INTERCHANGEABLE BETWEEN WEAPONS IN TWO OR MORE CLASSES', '2011-10-01', null, 'Assemblies Interchangeable Between Weapons in Two or More Classes', 'Components and Accessories used on or with weapons falling in two or more classes of [G]group 10.', null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.6', 'Weapons'),
  ('1095', 'MISCELLANEOUS WEAPONS', '1978-10-15', null, 'Miscellaneous Weapons', 'Line Throwing Guns; Catapult Guns; Bayonets; Saluting Guns; Signal Guns; Flare Guns; Barrage Balloons; Accessories, not elsewhere classifiable, for Weapons in this group; Expendable Bomb Dispensers.', null, null, '10 - WEAPONS', null, '12.0', 'Weapons & Ammunition', '12.6', 'Weapons'),
  ('11', 'NUCLEAR ORDNANCE', '1979-10-01', null, null, null, null, 'This group includes, in particular, nuclear ordnance training weapons, practice ballistic units, and all components specially designed therefore, when not specifically classified elsewhere. Also included in the group are specially designed simulators and mockups, which are integral parts of the above. Excluded from this group are general purpose nose cones, case sections, flare sections or center sections designed to carry payloads other than nuclear and/or for use on a missile, rocket, or re-entry vehicle to attain the necessary aerodynamic configuration.', null, null, null, null, null, null),
  ('1105', 'NUCLEAR BOMBS', '1978-12-15', null, 'Nuclear Bombs', 'Ballistic cases, tail assemblies, retardation devices, and other peculiar components which are not classifiable elsewhere.', 'Parachute canopies and canopy hardware.', 'This class includes nuclear weapons (including bombs), which are designed to be dropped from an aircraft.', '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('1110', 'NUCLEAR PROJECTILES', '1980-01-15', null, 'Nuclear Projectiles', 'Ogive sections, body sections, bases, and other peculiar components which are not classifiable elsewhere.', null, 'This class includes nuclear weapons which are designed to be propelled from a recoilless rifle, gun, howitzer, or the like, and which are not designed to be self propelled.', '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('1115', 'NUCLEAR WARHEADS AND WARHEAD SECTIONS', '2011-10-01', null, 'Nuclear Warheads and Warhead Sections', 'Components and parts peculiar to the warhead or warhead section, which are not classifiable in more specific classes.', 'Such components as fuzing and firing devices, nuclear components, high explosive components, classifiable in more specific classes, and items such as projectiles and bombs which include the entire outer case of a weapon.', 'This class includes nuclear warheads (without or assembled with case sections, adaption kits, and/or fuzing and firing components) which are to be used in or with bombs, rockets, projectiles, missiles, demolition charges, or the like. Also includes case sections, nose cones, flare sections, center sections, and auxiliary structural components of missiles, rockets, and re-entry vehicles which are designed or constructed for exclusive use with or for housing of nuclear warheads and/or warhead sections.', '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('1120', 'NUCLEAR DEPTH CHARGES', '1985-01-15', null, 'Nuclear Depth Charges', null, null, 'This class includes nuclear weapons which consist of depth charge bodies assembled with nuclear warheads. It includes training weapons and all specially designed components which are not classifiable elsewhere.', '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('1125', 'NUCLEAR DEMOLITION CHARGES', '1991-10-01', null, 'Nuclear Demolition Charges', 'Outer cases, case sections and other peculiar components, which are not classifiable elsewhere.', null, 'This class includes nuclear weapons which are designed to be emplaced in or near a structure, area or the like, which is to be destroyed. The weapons may include accessories.', '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('1127', 'NUCLEAR ROCKETS', '1982-09-15', null, 'Nuclear Rockets', 'Components peculiar to assembled rockets which are not classifiable elsewhere.', 'Rocket Motors; Warhead Components; Rocket Components classified in other FSC classes.', 'This class includes nuclear weapons, consisting of rocket bodies assembled with nuclear warheads, which comprise a single item of supply and are issued as such.', '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('1130', 'CONVERSION KITS, NUCLEAR ORDNANCE', '1979-06-15', null, 'Conversion Kits, Nuclear Ordnance', null, null, 'This class Includes collections of items used for the purpose of converting nuclear weapons from one configuration to another.', '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('1135', 'FUZING AND FIRING DEVICES, NUCLEAR ORDNANCE', '2011-10-01', null, 'Fuzing and Firing Devices, Nuclear Ordnance', 'Such items as fuzes, power supplies, firing sets, X-units, cables, safing devices, adaption kits, and re-entry vehicle nuclear ordnance arming and fuzing systems.', null, null, '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('1140', 'NUCLEAR COMPONENTS', '1978-10-15', null, 'Nuclear Components', 'All components which contain or simulate nuclear active materials.', 'End items, such as bombs, projectiles, warheads, and the like.', null, '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('1145', 'EXPLOSIVE AND PYROTECHNIC COMPONENTS, NUCLEAR ORDNANCE', '2011-10-01', null, 'Explosive and Pyrotechnic Components, Nuclear Ordnance', null, null, 'This class includes actual and simulated explosive and pyrotechnic components peculiar to all nuclear ordnance end items such as bombs, demolition charges, rockets, projectiles, warheads, and related systems. Excluded from this class are all explosive and pyrotechnic components designed for other than nuclear ordnance applications.', '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('1190', 'SPECIALIZED TEST AND HANDLING EQUIPMENT, NUCLEAR ORDNANCE', '2011-10-01', null, 'Specialized Test and Handling Equipment, Nuclear Ordnance', 'Specially designed trucks and trailers for nuclear ordnance; Specially designed slings and hoists; Operational, test, and setting devices, and cradles; Conditioning Kits and Sets, Controlled Environment.', 'Hand tools; Instruments for use on both nuclear ordnance and other equipment; Basic types of electrical and electronic test instruments, including those specially designed, such as ammeters, voltmeters, ohmmeters, multimeters, and similar instruments, as shown in the indexes in the FSC.', null, '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('1195', 'MISCELLANEOUS NUCLEAR ORDNANCE', '1978-10-15', null, 'Miscellaneous Nuclear Ordnance', 'Items common to more than one class or items not properly fitting into the foregoing classes of nuclear ordnance', null, null, '11 - NUCLEAR ORDNANCE', null, '12.0', 'Weapons & Ammunition', '12.5', 'Nuclear Ordnance'),
  ('12', 'FIRE CONTROL EQPT.', '1979-10-01', null, null, null, null, 'Fire Control assemblies, subassemblies, and components are classified: a. In appropriate classes of this group when: (1) Designed for multiple applications to different kinds of fire control equipment. (2) Modified for use with guided missile remote control systems. (3) Designed specifically for shipborne guided missile remote control systems. (4) Radar equipment, designed specifically for fire control systems. (5) Both day and night viewing characteristics are incorporated into an integral unit. b. In class 1270 or 1280, when designed specifically for aircraft gunnery or aircraft bombing fire control, respectively. c. In class 1430, when designed specifically for guided missile remote control systems, except shipboard type. d. In appropriate classes of group 58, when designed for multiple applications to both fire control and communication equipment. e. In appropriate classes of group 58 when designed for night vision.', null, null, null, null, null, null),
  ('1210', 'FIRE CONTROL DIRECTORS', '1978-10-15', null, 'Fire Control Directors', null, null, null, '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('1220', 'FIRE CONTROL COMPUTING SIGHTS AND DEVICES', '2011-10-01', null, 'Fire Control Computing Sights and Devices', null, null, null, '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('1230', 'FIRE CONTROL SYSTEMS, COMPLETE', '1978-10-15', null, 'Fire Control Systems, Complete', null, null, 'This class includes only complete fire control systems. Anything less than a complete system, such as individual end items, assemblies, parts, attachments, or accessories for use in fire control systems are classified in classes other than this class.', '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('1240', 'OPTICAL SIGHTING AND RANGING EQUIPMENT', '2011-10-01', null, 'Optical Sighting and Ranging Equipment', 'Periscopes for Submarines; Range and Height Finders; Telescopic Sights; Optical Instruments Integrated with Fire Control Equipment.', null, null, '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('1250', 'FIRE CONTROL STABILIZING MECHANISMS', '1978-10-15', null, 'Fire Control Stabilizing Mechanisms', null, null, null, '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('1260', 'FIRE CONTROL DESIGNATING AND INDICATING EQUIPMENT', '2011-10-01', null, 'Fire Control Designating and Indicating Equipment', 'Turret, Gun, Torpedo Mount, and Searchlight Indicating Equipment; Target Designating Equipment; Synchro Systems.', null, null, '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('1265', 'FIRE CONTROL TRANSMITTING AND RECEIVING EQUIPMENT, EXCEPT AIRBORNE', '2011-10-01', null, 'Fire Control Transmitting and Receiving Equipment, except Airborne', 'Fire Control Transmitters, Transmitter-Receivers, Receivers, Receiver-Regulators.', 'Fire Control Transmitting and Receiving Equipment, Specially Designed for use on or with Fire Control Radar Equipment.', null, '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('1270', 'AIRCRAFT GUNNERY FIRE CONTROL COMPONENTS', '2011-10-01', null, 'Aircraft Gunnery Fire Control Components', 'Turrets, Aircraft; Computers, specifically designed; Complete Gyro Mechanisms.', 'Gun Chargers; Ammunition Boxes; Gun Heaters; Field and Link Chutes; Ammunition Boosters; Gyro Components; Complete Fire Control Systems.', null, '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('1280', 'AIRCRAFT BOMBING FIRE CONTROL COMPONENTS', '2011-10-01', null, 'Aircraft Bombing Fire Control Components', 'Computers, specifically designed; Complete Gyro Mechanisms; Optical Instruments for Bombing Fire Control.', 'Gyro Components; Optical Elements, such as Lens, Prisms, Filters.', null, '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('1285', 'FIRE CONTROL RADAR EQUIPMENT, EXCEPT AIRBORNE', '2011-10-01', null, 'Fire Control Radar Equipment, except Airborne', 'Radar Sets, Assemblies, Subassemblies, and Components Specially Designed for use on or with Fire Control Equipment.', null, null, '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('1287', 'FIRE CONTROL SONAR EQUIPMENT', '1979-01-15', null, 'Fire Control Sonar Equipment', null, null, 'This class includes airborne, shipborne, and submarineborne sonar sets, assemblies, subassemblies, and components designed specifically for use with underwater fire control equipment.', '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('1290', 'MISCELLANEOUS FIRE CONTROL EQUIPMENT', '2011-10-01', null, 'Miscellaneous Fire Control Equipment', 'Fuze Setters; Ordnance Cable Systems; Aiming Circles; Flash and Sound Ranging Sets; Fire Control Components and Subassemblies Not Classifiable in other classes of group 12.', null, null, '12 - FIRE CONTROL EQPT.', null, '12.0', 'Weapons & Ammunition', '12.2', 'Fire Control'),
  ('13', 'AMMUNITION AND EXPLOSIVES', '1979-10-01', null, null, null, null, 'Excluded from this group are items specially designed for nuclear ordnance application.', null, null, null, null, null, null),
  ('1305', 'AMMUNITION, THROUGH 30MM', '2011-10-01', null, 'Ammunition, through 30 mm', 'Components.', null, null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1310', 'AMMUNITION, OVER 30MM UP TO 75MM', '2011-10-01', null, 'Ammunition, over 30 mm up to 75 mm', 'Components, except Fuzes and Primers; Chemical Warfare Cartridges.', 'Fuzes and Primers.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1315', 'AMMUNITION, 75MM THROUGH 125MM', '2011-10-01', null, 'Ammunition, 75 mm through 125 mm.', 'Components except Fuzes and Primers; Pyrotechnic Cartridges and Projectiles; Chemical Warfare Cartridges and Projectiles', 'Fuzes and Primers.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1320', 'AMMUNITION, OVER 125MM', '2011-10-01', null, 'Ammunition, over 125 mm', 'Components, except Fuzes and Primers; Chemical Warfare Projectiles.', 'Fuzes and Primers.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1325', 'BOMBS', '1978-11-15', null, 'Bombs', 'Components; Photoflash Bombs; Chemical Warfare Bombs; Bomb Clusters.', null, null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1330', 'GRENADES', '1978-10-15', null, 'Grenades', 'Components; Hand and Rifle Grenades; Smoke Grenades.', 'Firing Devices (Launchers).', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1336', 'GUIDED MISSILE WARHEADS AND EXPLOSIVE COMPONENTS', '2011-10-01', null, 'Guided Missile Warheads and Explosive Components', 'Warheads Containing Military Chemical Agents; Exercise Heads, Guided Missile.', 'Atomic Ordnance Warheads; All other Warheads for use on other than guided missiles; Liquid Propulsion Units; Rocket Engines (Liquid Propellent Units); JATO Units; Rocket Motors (Solid Propellant Units) for Guided Missiles; Solid Fuel Propulsion Units; Propellant Chemicals encased in consumable containers, such as squibs and cartridges for insertion into missile propulsion systems as integral parts.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1337', 'GUIDED MISSILE AND SPACE VEHICLE EXPLOSIVE PROPULSION UNITS, SOLID FUEL; AND COMPONENTS', '2011-10-01', null, 'Guided Missile and Space Vehicle Explosive Propulsion Units, Solid Fuel; and components', 'Rocket Motors (Solid Propellant Units) for Guided Missiles, Explosive- Loaded; All Explosive Components for Guided Missile and Space Vehicle Solid Fuel Propulsion Units; Solid Propellants encased in consumable containers, such as squibs and cartridges, intended for insertion into missile propulsion systems as integral parts.', 'Rocket Motors (Solid Propellant Units) for Guided Missiles, Inert-Loaded or Empty; All Inert (Nonexplosive) Components for Guided Missile and Space Vehicle Solid Fuel Propulsion Units; Guided Missile Warheads and Components; Rocket Propulsion Units; Rocket Motors (Solid Propellent Units) for Rockets; Solid Propellants predetermined to specific quantity and quality, but packaged in reusable containers.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1338', 'GUIDED MISSILE AND SPACE VEHICLE INERT PROPULSION UNITS, SOLID FUEL; AND COMPONENTS', '2011-10-01', null, 'Guided Missile and Space Vehicle Inert Propulsion Units, Solid Fuel; and components', 'Rocket Motors (Solid Propellant Units) for guided Missiles, Inert-Loaded or Empty; All Inert (Nonexplosive) Components for Guided Missile and Space Vehicle Solid Fuel Propulsion Units.', 'Rocket Motors (Solid Propellant Units) for Guided Missiles, Explosive-Loaded; Guided Missile Warheads and Components; Rocket Propulsion Units; Rocket Motors (Solid Propellant Units) for Rockets.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1340', 'ROCKETS, ROCKET AMMUNITION AND ROCKET COMPONENTS', '2011-10-01', null, 'Rockets, Rocket Ammunition and Rocket Components', 'Complete Rounds; Explosive Components, Including Warheads; Pyrotechnic Rockets; Solid Fuel JATO Units; Rocket Motors (Solid Propellant Units) for Rockets; Covers, Protective Rocket Warhead; Jettisonable Rocket Launchers; Conditioning Kits and Sets, Controlled Environment; and other peculiar components which are not classified elsewhere.', 'Nuclear rockets, Nuclear warheads; all other warheads for use on other than rockets; and rockets with built-in guiding devices.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1345', 'LAND MINES', '1978-11-15', null, 'Land Mines', 'Components; Antipersonnel Mines; Antitank Mines; Fuzes.', null, null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1346', 'REMOTE MUNITIONS', '2005-05-01', null, 'Munitions items-systems that are not held by the soldier but are deployed for future activation.', null, null, null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1350', 'UNDERWATER MINE AND COMPONENTS, INERT', '2011-10-01', null, 'Underwater Mine Inert Components', 'Parachute Packs; Inert Mine Cases; Booster Cans; Clock Delays; Clock Starters; Search Coils; Extenders.', null, null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1351', 'UNDERWATER MINES AND COMPONENTS, EXPLOSIVE', '2011-10-01', null, 'Underwater Mine Explosive Components', 'Loaded Cases; Boosters; Detonators.', null, null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1352', 'UNDERWATER MINE DISPOSAL INERT DEVICES', '2011-10-01', null, 'Version of Underwater Mine Disposal Explosive Device without destructive charge.', 'Complete operating units, such as an underwater mine reconnaissance device, as well as component parts, practice, training, blank, and dummies.', 'Torpedo Inert components, depth charges, and underwater mines.', 'Intended for underwater mine hunting and reconnaissance. May also be used for training purposes.', '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1353', 'UNDERWATER MINE DISPOSAL EXPLOSIVE DEVICES', '2011-10-01', null, 'Complete explosive devices, including destructive charge.', 'Complete explosive device, including ammunition, detonating charge, and component parts.', 'Underwater Mine Explosive Components (FSC 1351), Torpedo Explosive Components (FSC 1356), Military Chemical Agents (FSC 1365).', 'It is fired, guided to target and detonated from a vessel or other remote site.', '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1355', 'TORPEDOS AND COMPONENTS, INERT', '2011-10-01', null, 'Torpedo Inert Components', null, null, null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1356', 'TORPEDOS AND COMPONENTS, EXPLOSIVE', '2011-10-01', null, 'Torpedo Explosive Components', 'Warheads; Boosters; Detonators.', null, null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1360', 'DEPTH CHARGES AND COMPONENTS, INERT', '2011-10-01', null, 'Depth Charge Inert Components', 'Inert Firing Mechanisms; Pistols without Detonators; Extenders.', null, null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1361', 'DEPTH CHARGES AND COMPONENTS, EXPLOSIVE', '2011-10-01', null, 'Depth Charge Explosive Components', 'Cases; Boosters; Detonator.', null, null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1365', 'MILITARY CHEMICAL AGENTS', '1978-11-15', null, 'Military Chemical Agents', 'War Gases; Screening Smokes; Incendiary and thickening Agents; Signaling Smokes.', 'Ammunition containing Military Chemical Agents.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1367', 'TACTICAL SETS, KITS, AND OUTFITS', '2005-05-01', null, 'A collection of items, which are used for a specific purpose.', 'Each collection must include at least one item of ordnance classified in Group 13. Ordnance may be non-lethal (as defined in the Department of Defense Directive 3000.3)', null, 'These sets, kits and outfits may include such items as uniforms, weapons, body armor, and the like. By themselves, each of these components belongs in an FSC other than 1367.', '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1370', 'PYROTECHNICS', '1978-10-15', null, 'Pyrotechnics', 'Flares; Signals; Fireworks; Pistol Rocket Signals.', 'Pyrotechnic Cartridges and Projectiles; Photoflash Bombs; Pyrotechnic Rockets.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1375', 'DEMOLITION MATERIALS', '1978-11-15', null, 'Demolition Materials', 'Items for construction, quarrying and demolition work such as Dynamite and other explosives packed in cylindrical paper cartridges or in bags, Demolition Charges; Blasting Caps; Blasting Time Fuses; Detonating Cord; Demolition Firing Devices; Booby Trap Mechanisms; Bangalore Torpedoes; Inert accessories and components such as Blasting Machines, Priming Adapters, and Detonating Cord Clips.', 'Liquid Propellant Fuels and Oxidizers; Solid Propellants encased in consumable containers, for insertion into missile propulsion systems as integral parts; Guided Missile Explosive Devices; Safety-in-Flight Explosive Items and Devices such as, Impulse Cartridges, Delay Cartridges, Aircraft Ejection Seat Catapults, Aircraft Canopy Removers, and similar items, as shown in the indexes to the FSC; Solid Propellants, predetermined to specific quantity and quality, packaged in reusable containers; Nuclear Ordnance Components; Rocket and Guided Missile Motors, Warheads, and Propulsion Sections.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1376', 'BULK EXPLOSIVES', '1978-12-15', null, 'Bulk Explosives', 'Solid Propellants, predetermined to specific quantity and quality, packaged in reusable containers; Explosive Loaded Devices and Components as shown in the indexes to the FSC.', 'Liquid Propellant Fuels and Oxidizers; Solid Propellants encased in consumable containers, for insertion into missile propulsion systems as integral parts; Guided Missile Explosive Devices; Blasting and Demolition Materials; Safety-in-Flight Explosive Items and Devices such as Impulse Cartridges, Delay Cartridges, Aircraft Ejection Seat Catapults, Aircraft Canopy Removers; Rocket and Guided Missile Motors, Warheads, and Propulsion Sections; similar items, as shown in the indexes to the FSC.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1377', 'CARTRIDGE AND PROPELLANT ACTUATED DEVICES AND COMPONENTS', '2011-10-01', null, 'Cartridge and Propellant Actuated Devices and Components', 'Impulse Cartridges; Delay Cartridges; Engine Starter Cartridges (explosive filled); Fire Extinguisher Cartridges (used to activate by remote control); Aircraft Ejection Seat Catapults; Rocket Motors (Solid Propellant Units) for Aircraft Ejection Seats; Aircraft Canopy Removers; Thrusters, propellant and cartridge actuated; Initiators; Explosive Bolts and Explosive Bolt Cartridges; Cutters, cartridge or propellant actuated, Reefing Line; Powder actuated Tool Cartridges; Explosive Loaded Devices and Components which are not specifically classified elsewhere.', 'Liquid Propellant Fuels and Oxidizers; Solid Propellants, encased in consumable containers for insertion into missile propulsion systems as an integral part; Guided Missile Explosive Devices; Bulk and Solid Propellants, predetermined to specific quantity and quality, packaged in reusable containers; Blasting and Demolition Materials; Rocket Motors, Warheads and Propulsion Sections for Rockets and Guided Missiles.', 'This class includes safety-in-flight explosive items, consisting of a quantity of propellant (either encased in a cartridge or in molded form) and a means of activation, designed to be inserted into or attached to one or more devices to provide the energy required to operate devices requiring a time delay, or not requiring a time delay, in their operating sequence. Also included are devices designed to utilize energy generated by the items described above.', '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1385', 'SURFACE USE EXPLOSIVE ORDNANCE DISPOSAL TOOLS AND EQUIPMENT', '2011-10-01', null, 'Surface Use Explosive Ordnance Disposal Tools and Equipment', 'Nonspecialized or common tools and equipment not developed exclusively for use by qualified EOD personnel; specialized demolition material; explosive loaded shaped charges.', 'Nonspecialized or common tools and equipment not developed exclusively for use by qualified EOD personnel; specialized demolition material; explosive loaded shaped charges.', 'This class includes only specialized tools and equipment developed for and used by qualified Explosive Ordnance Disposal (EOD) personnel.', '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1386', 'UNDERWATER USE EXPLOSIVE ORDNANCE DISPOSAL AND SWIMMER WEAPONS SYSTEMS TOOLS AND EQUIPMENT', '2011-10-01', null, 'Underwater Use Explosive Ordnance disposal and Swimmer Weapons Systems Tools and Equipment.', null, null, 'This class includes only specialized tools and equipment developed for and used by qualified Explosive Ordnance Disposal (EOD) personnel, Underwater Demolition Teams (UDT), and/or Sea-Air-Land (SEAL) personnel. Excludes Nonspecialized or common tools not developed exclusively for use by qualified EOD, UDT, and/or SEAL personnel; specialized demolition material; explosive loaded shaped charges.', '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1390', 'FUZES AND PRIMERS', '1978-10-15', null, 'Fuzes and Primers', 'Fuzes and Primers for ammunition not classified in classes 1310, 1315, and 1320.', 'Fuzes and Primers for ammunition not classified in classes 1310, 1315, and 1320.', 'This class includes only fuzes and primers for use in ammunition classified in classes 1310, 1315, and 1320.', '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1395', 'MISCELLANEOUS AMMUNITION', '1978-10-15', null, 'Miscellaneous Ammunition', 'Ammunition Shapes, such as Blanks, Disks, Slugs, Cups, and Rotating Bands (Shell Bands).', null, null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('1398', 'SPECIALIZED AMMUNITION HANDLING AND SERVICING EQUIPMENT', '2011-10-01', null, 'Specialized Ammunition Handling and Servicing Equipment.', 'Handling and servicing equipment specially designed for use on or with rockets and conventional ammunition.', 'Handling and servicing equipment specially designed for use on or with rocket and pyrotechnic launchers; Ammunition maintenance and repair shop specialized equipment; Handling equipment specially designed for aircraft or airfield use.', null, '13 - AMMUNITION AND EXPLOSIVES', null, '12.0', 'Weapons & Ammunition', '12.1', 'Ammunition & Explosives'),
  ('14', 'GUIDED MISSLES', '1979-10-01', null, null, null, null, 'This group includes missiles (with or without warheads or explosive components) incorporating mechanisms capable of altering normal flight paths. Radar and infrared assemblies and components designed specifically for use with guided missiles are classified in the appropriate classes of this group. Excluded from this group are case sections, nose cones, flare sections, center sections, warheads, explosive components, rockets, and auxiliary components of missiles and re-entry vehicles which are designed or constructed for exclusive use with or for housing of nuclear warheads and/or warhead sections. Also excluded are space vehicle nose cones and space capsules specifically designed to carry loads peculiar to space research and space travel', null, null, null, null, null, null),
  ('1410', 'GUIDED MISSILES', '1978-10-15', null, 'Guided Missiles', 'Complete Drones, initially designed as missiles, but converted to drone use.', null, 'This class includes only complete guided missiles, with or without warheads and explosive components, whether in assembled or unassembled form. End items, assemblies, parts, attachments, or accessories for use in or on guided missiles are classified in classes other than this class.', '14 - GUIDED MISSLES', null, '12.0', 'Weapons & Ammunition', '12.3', 'Guided Missiles'),
  ('1420', 'GUIDED MISSILE COMPONENTS', '1978-10-15', null, 'Guided Missile Components', 'Structural Components; Components and Accessories Specially Designed for use on or with guided missiles, including Complete Gyro Mechanisms, Hydraulic Pumps, Automatic Pilot Mechanisms and Specially Designed Assemblies, and Electronic Guidance Equipment installed in missiles.', 'Electronic Remote Guidance Equipment used to guide missiles; Solid and Liquid Propellant Units; Components of Gyro Mechanisms.', null, '14 - GUIDED MISSLES', null, '12.0', 'Weapons & Ammunition', '12.3', 'Guided Missiles'),
  ('1425', 'GUIDED MISSILE SYSTEMS, COMPLETE', '1978-10-15', null, 'Guided Missile Systems, Complete', 'Guided Missile Subsystems.', 'Guided Missile Subsystems.', 'This class includes only complete guided missile systems. Anything less than a complete system, such as individual end items, assemblies, parts, attachments, or accessories for use in guided missile systems are classified in classes other than this class.', '14 - GUIDED MISSLES', null, '12.0', 'Weapons & Ammunition', '12.3', 'Guided Missiles'),
  ('1427', 'GUIDED MISSILE SUBSYSTEMS', '1978-10-15', null, 'Guided Missile Subsystems', 'Complete Guided Missile Systems.', 'Complete Guided Missile Systems.', 'This class includes only combinations or assemblies of two or more end items, each of which is properly classified in other classes of this group, identified as single items of supply. Excluded from this class are individual end items, assemblies, subassemblies, attachments, accessories or parts classified in other classes of this group, not combined as single items of supply.', '14 - GUIDED MISSLES', null, '12.0', 'Weapons & Ammunition', '12.3', 'Guided Missiles'),
  ('1430', 'GUIDED MISSILE REMOTE CONTROL SYSTEMS', '2011-10-01', null, 'Guided Missile Remote Control Systems', 'Specially Designed Components of Guided Missile Remote Control Systems.', 'Guided Missile Internal (Built-in) Control Systems; Components used in both guided missiles and other than guided missiles (including fire control components).', 'This class includes airborne and nonairborne guided missile remote control systems, components, and accessories, designed specifically for use therewith. Excluded from this class are fire control assemblies, subassemblies, and components modified for use with guided missile remote control systems, and fire control assemblies designed specifically for shipboard use.', '14 - GUIDED MISSLES', null, '12.0', 'Weapons & Ammunition', '12.3', 'Guided Missiles'),
  ('1440', 'LAUNCHERS, GUIDED MISSILE', '1978-10-15', null, 'Launchers, Guided Missile', 'Airborne and Nonairborne Guided Missile Launchers.', 'Aircraft Launchers; Rocket Launchers.', null, '14 - GUIDED MISSLES', null, '12.0', 'Weapons & Ammunition', '12.3', 'Guided Missiles'),
  ('1450', 'GUIDED MISSILE HANDLING AND SERVICING EQUIPMENT', '2011-10-01', null, 'Guided Missile Handling and Servicing Equipment', 'Specially Designed Trucks and Trailers for use in transporting guided missiles; Specially Designed Slings, Hoists, Jacks, and Blowers; Self-propelled Vehicles and Trailers, Specially Designed for Guided Missile Handling or Servicing; Covers, Guided Missile; Conditioning Kits and Sets, Controlled Environment.', 'Guided Missile Launchers (FSC 1440); Aircraft Handling and Servicing Equipment (FSC 1730).', null, '14 - GUIDED MISSLES', null, '12.0', 'Weapons & Ammunition', '12.3', 'Guided Missiles'),
  ('15', 'AEROSPACE CRAFT AND STRUCTURAL COMPONENTS', '2015-10-01', null, null, null, null, null, null, null, null, null, null, null),
  ('1510', 'AIRCRAFT, FIXED WING', '1978-10-15', null, 'Aircraft, Fixed Wing', null, null, 'This class includes only complete aircraft. End items, assemblies, parts, attachments, or accessories for use in or on fixed wing aircraft are classified in classes other than this class.', '15 - AEROSPACE CRAFT AND STRUCTURAL COMPONENTS', null, '11.0', 'Aircraft, Ships/Submarines & Land Vehicles', '11.1', 'Aircraft'),
  ('1520', 'AIRCRAFT, ROTARY WING', '1978-10-15', null, 'Aircraft, Rotary Wing', 'Helicopters.', null, 'This class includes only complete aircraft. End items, assemblies, parts, attachments, or accessories for use in or on rotary wing aircraft are classified in classes other than this class.', '15 - AEROSPACE CRAFT AND STRUCTURAL COMPONENTS', null, '11.0', 'Aircraft, Ships/Submarines & Land Vehicles', '11.1', 'Aircraft'),
  ('1540', 'GLIDERS', '1979-05-15', null, 'Gliders', 'Motorized Gliders.', null, 'This class includes only complete gliders. End items, assemblies, parts, attachments, or accessories for use in or on gliders are classified in classes other than this class.', '15 - AEROSPACE CRAFT AND STRUCTURAL COMPONENTS', null, '11.0', 'Aircraft, Ships/Submarines & Land Vehicles', '11.1', 'Aircraft'),
  ('1550', 'UNMANNED AIRCRAFT', '2011-10-01', null, 'Drones', 'Drones specifically designed for such uses as targets, training, surveillance, missile evaluation, and photographic reconnaissance.', 'Piloted aircraft and guided missiles converted to drone use.', 'This class includes only complete drones. End items, assemblies, parts, attachments, or accessories for use in or on drones are classified in classes other than this class.', '15 - AEROSPACE CRAFT AND STRUCTURAL COMPONENTS', null, '14.0', 'Sustainment S&E', '14.1', 'Drones'),
  ('1555', 'SPACE VEHICLES', '2015-10-01', null, null, null, null, 'This class includes only complete space vehicles in assembled or unassembled form.', '15 - AEROSPACE CRAFT AND STRUCTURAL COMPONENTS', null, '11.0', 'Aircraft, Ships/Submarines & Land Vehicles', '11.1', 'Aircraft'),
  ('1560', 'AIRFRAME STRUCTURAL COMPONENTS', '1978-10-15', null, 'Airframe Structural Components', 'Flight Control Surfaces, internal and external Auxiliary Fuel Tanks; Exhaust Systems, Pylons, Trim Tabs; Aircraft.', 'Fitted Covers; Helicopter Rotor Brake System and Components; Aircraft Loose Equipment and Alternate Mission Configuration Equipment stored on board the Aircraft.', 'This class includes fabricated system parts that are permanently attached or peculiar to the integral airframe of an aircraft, such as support structural components, spars, ribs, ailerons, stabilizers, bulkheads.', '15 - AEROSPACE CRAFT AND STRUCTURAL COMPONENTS', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('16', 'AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', '2015-10-01', null, null, null, null, null, null, null, null, null, null, null),
  ('1610', 'AIRCRAFT PROPELLERS AND COMPONENTS', '1978-10-15', null, 'Aircraft Propellers and Components', 'Aircraft Propellers; Propeller Blades, Cams, Cones, Hubs, Nuts, and Spinners; Test Clubs; Synchronizers; Power Control Units; Integral Oil Control Measures and Propeller Governors.', 'Rotary Rudder and Rotary Wing Blades (FSC 1615).', null, '16 - AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1615', 'HELICOPTER ROTOR BLADES, DRIVE MECHANISMS AND COMPONENTS', '2011-10-01', null, 'Helicopter Rotor Blades, Drive Mechanisms and Components', 'Helicopter dynamic components and specially designed parts that transmit power from the aircraft power plant to the rotary wing and rotary rudder. Also included in this class are Rotors; Blades; Rotor Blade, Trim, Tabs; Blade Sets; Yokes; Clutches and Transmissions.', 'Propellers (FSC 1610); Rotor Brake Systems Components (FSC 1630); Rotor Blade Hydraulic Folding System Components (FSC 1650); Hydraulic Servo System Components (FSC 1650).', 'This class includes miscellaneous component parts specifically designed for, and used exclusively in, helicopter drive mechanisms and rotor blades when not specifically classified elsewhere in the FSC indexes.', '16 - AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1620', 'AIRCRAFT LANDING GEAR COMPONENTS', '1978-10-15', null, 'Aircraft Landing Gear Components', 'Shock Struts and Components; Installation Elements, such as Torsion Bars, Vibration Links, Drag Struts; Landing Gear Trunions, Axles and Shimmy Dampeners; Specially designed hydraulic power steering system components.', 'Mounting Braces and Mounting Plates permanently installed on aircraft (FSC 1680); Landing Wheels, Skis, and Floats (FSC 1630); Wheel Brakes and Wheel Brake Cylinders (FSC 1630).', null, '16 - AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1630', 'AIRCRAFT WHEEL AND BRAKE SYSTEMS', '1978-10-15', null, 'Aircraft Wheel and Brake Systems', 'Skis; Floats; Tracks; Landing Wheel Skid Detectors; Valves specifically designed for use with hydraulic or pneumatic wheel and brake systems; Helicopter Rotor Brake System Components.', 'Landing Gear Axles (FSC 1620).', null, '16 - AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1640', 'AIRCRAFT CONTROL CABLE PRODUCTS', '2005-05-01', null, 'Missing code added for DOD Migration purpose only', 'Wire Rope; Single Leg Wire Assemblies; Wire Strands; Control Pulleys; Turnbuckle Lock Clips and other wire rope attachments and terminations.', 'General use Chain and Wire Rope (FSC 4010); general use Pulleys(FSC 3020);general use Miscellaneous Hardware (FSC 5340); general use Fittings for Rope, Cable and Chain (FSC 4030).', 'Wire rope, with attachments or terminations and pulleys, used in aircraft control applications, will be classified in this class', '16 - AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1650', 'AIRCRAFT HYDRAULIC, VACUUM, AND DE-ICING SYSTEM COMPONENTS', '2011-10-01', null, 'Aircraft Hydraulic, Vacuum and De-icing System Components', 'Hydraulic and Pneumatic Accumulators, Pumps, Motors, Actuating Cylinders, and Filters; De-icing Boots; Fluid Type De-icing Pumps, Valves and Filters; Vacuum System Oil Separators; Pneumatic Pressurization Equipment other than that for pressurizing cabins and compartments.', 'Jet Engine Hydraulic Components (FSC 2840); Valves specifically designed for air conditioning, heating. ventilating, cabin pressurizing, and thermal de-icing (FSC 1660); Valves specifically designed for use with Aircraft Engines (FSC 2840); Guided Missiles and Guided Missile Engines (FSC 1338); Landing Gear (FSC 1620), Wheel and Brake System Components (FSC 1630); Oxygen Breathing System Components (FSC 1660); In-flight Refueling System Hydraulic components (FSC 1680); Specifically designed hydraulic power steering system components (FSC 1620).', 'This class includes only those components specifically designed for aircraft use.', '16 - AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1660', 'AIRCRAFT AIR CONDITIONING, HEATING, AND PRESSURIZING EQUIPMENT', '2011-10-01', null, 'Aircraft Air Conditioning, Heating, and Pressurizing Equipment', 'Cabin Supercharging Equipment; Canisters; Cylinder Assemblies; Masks; Fixed Oxygen Systems; Specially Designed Aircraft Valves; Cabin Pressure Regulators; Heat Exchangers; Air Expansion Turbines; Aircraft Heaters; Ventilating System Components; Air Conditioning and Heating Duct Assemblies; Thermal De-icing Equipment; Cabin and Compartment Pressurizing Equipment; Air Diffusers; Cabin Pressure Selectors; Liquid Oxygen Converters.', 'Oxygen Pressure Signals and Warning Devices; Tubing; Ground Type Heaters and Coolers; Pressurizing Equipment other than that used for Cabin and Compartment Pressurization; Fluid De-icing Equipment; Valves specifically designed for use with Aircraft Engines, Guided Missiles, and Guided Missile Engines.', 'This class includes components specifically designed for use in aircraft air conditioning, heating, and pressurizing equipment. Also included are specially designed components of oxygen breathing systems used in aircraft.', '16 - AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1670', 'PARACHUTES; AERIAL PICK UP, DELIVERY, RECOVERY SYSTEMS; AND CARGO TIE DOWN EQUIPMENT', '2011-10-01', null, 'Parachutes; Aerial Pick Up, Delivery, Recovery Systems; Cargo Tie Down Equipment', 'Fitting Assemblies built into the aircraft structure.', 'Fitting Assemblies built into the aircraft structure.', 'Includes specifically designed items, sets, and systems for air-to-air, air-to-surface, and surface-to-air delivery, pick up and recovery operations, unless parts, attachments, assemblies, for use in or on such systems (i.e. space vehicle aerial recovery systems) are specifically indexed to other classes of the FSC (i.e., transmitting radio buoys and direction finding subsystem components).', '16 - AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1675', 'SPACE VEHICLE COMPONENTS', '2015-10-01', null, 'Space Vehicle Components', 'Structural components; Components and Accessories Specially Designed for installation in or on Space Vehicles; Internal (Built-In) Control Systems.', 'Remote Guidance Equipment.', null, '16 - AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1677', 'SPACE VEHICLE REMOTE CONTROL SYSTEMS', '2015-10-01', null, 'Space Vehicle Remote Control Systems', 'Specifically designed Components of Space Vehicle Remote Control Systems.', 'Internal (built-in) Control Systems; Components designed for use with both Guided Missile and Space Vehicle Systems.', null, '16 - AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1680', 'MISCELLANEOUS AIRCRAFT ACCESSORIES AND COMPONENTS', '2011-10-01', null, 'Miscellaneous Aircraft Accessories and Components', 'Control Assemblies, Push-Pull; Brace, Positioning Cargo Ramp Stowed on Board; Cockpit Mounted Control Quadrants; Actuators, Electromechanical and Mechanical; Ventilators; Relief Tubes; Map Holders; Aerial Glider Towing Accessories Attached to Aircraft; Belts, Safety and Lap; Harness, Shoulder and Safety; Litter Attaching Supports; Electric Windshield Wipers; Aircraft Onboard Inert Gas Generators; Aircraft Furniture; Aircraft Mounted Winches and Hoists; In-Flight Refueling System Components, including Fuel Components; Aircraft Curtains; Cable Tension Regulators; Sun Visors; Rear-View Mirrors; Mechanical Transmissions, Gearboxes and Constant Speed Drives Specially Designed for Aircraft.', 'Engine Mounted Control Assemblies; Fitted Covers, Aircraft Pylons; Helicopter Rotor Brake System Components; Helicopter Automatic Stabilization Equipment.', null, '16 - AEROSPACE CRAFT COMPONENTS AND ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('17', 'AEROSPACE CRAFT LAUNCHING, LANDING, GROUND HANDLING AND SERVICING EQUIPMENT', '2015-10-01', null, 'AEROSPACE CRAFT LAUNCHING, LANDING, GROUND HANDLING AND SERVICING EQUIPMENT', null, null, 'Excluded from this group are trucks, trailers, and servicing equipment specially designed for guided missile or atomic ordnance use.', null, null, null, null, null, null),
  ('1710', 'AIRCRAFT LANDING EQUIPMENT', '1978-10-15', null, 'Aircraft Landing Equipment', 'Aircraft Arresting Barriers.', 'Airport Runway Marker Lights (see FSC Class 6220).', null, '17 - AEROSPACE CRAFT LAUNCHING, LANDING, GROUND HANDLING AND SERVICING EQUIPMENT', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1720', 'AIRCRAFT LAUNCHING EQUIPMENT', '1978-10-15', null, 'Aircraft Launching Equipment', 'Catapults.', 'Guided Missile Launchers (FSC Class 1440) and Space Vehicle Launchers (FSC Class 1840).', null, '17 - AEROSPACE CRAFT LAUNCHING, LANDING, GROUND HANDLING AND SERVICING EQUIPMENT', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1725', 'SPACE VEHICLE LAUNCHERS', '2015-10-01', null, 'Space Vehicle Launchers', 'Launchers specifically designed for Space Vehicles', 'Launchers used with both Guided Missile and Space Vehicles.', null, '17 - AEROSPACE CRAFT LAUNCHING, LANDING, GROUND HANDLING AND SERVICING EQUIPMENT', null, '14.0', 'Sustainment S&E', null, null),
  ('1730', 'AIRCRAFT GROUND SERVICING EQUIPMENT', '1978-10-15', null, 'Aircraft Ground Servicing Equipment', 'Energizers; Engine Preheaters; Mooring Assemblies; Wheel Chocks; Beaching Equipment; Aileron, Elevator, and Rudder Locks; Passenger Loading Ramps; Maintenance Platforms; Aircraft Maintenance and Boarding Ladders; Aircraft Maintenance Slings and Hoists; Aircraft Fin Tilting Jacks; Airfield Specialized Lift Trucks and Trailers; Fitted Covers for Airframe Components; Aircraft Engine Covers.', 'Airfield Specialized Trucks and Trailers designed primarily for transporting aircraft assemblies (FSC 1740); Maintenance Stands designed for support of aircraft assemblies during repair or overhaul (FSC 4920); Test Stands (FSC 4920); General Purpose Jacks (FSC 5120); Slings (FSC 3940), and Hoists (FSC 3950); Trailers (FSC 2330), Liquid Oxygen, Aircraft Servicing (FSC 1660).', 'This class excludes "vehicular components" such as those listed under FSCs 2520, 2530, 2540, 2590.', '17 - AEROSPACE CRAFT LAUNCHING, LANDING, GROUND HANDLING AND SERVICING EQUIPMENT', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1735', 'SPACE VEHICLE HANDLING AND SERVICING EQUIPMENT', '2015-10-01', null, 'Space Vehicle Handling and Servicing Equipment', 'Specially designed Trucks and Trailers for sue in transporting Space Vehicles; Specially designed Slings, Hoists, Jacks, Blowers, Self-propelled Vehicles, Specially designed for space vehicle handling or servicing; Covers, space vehicle.', 'Equipment used in handling or servicing both Guided Missiles and Space Vehicles.', 'This class does not include space vehicle aerial recovery systems which are classified in class 1670.', '17 - AEROSPACE CRAFT LAUNCHING, LANDING, GROUND HANDLING AND SERVICING EQUIPMENT', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('1740', 'AIRFIELD SPECIALIZED TRUCKS AND TRAILERS', '2011-10-01', null, 'Airfield Specialized Trucks and Trailers', 'Airfield Specialized Trucks and Trailers designed primarily for transporting aircraft assemblies; Trailers: Afterburner, Engine, Propeller, Fuselage, and Wing; Trucks, Aircraft Fuselage and Aircraft Wing; Skids, Engine transport; Stands, Engine Transport; Bomb Trailers, Airfield; Trucks, Crashed Aircraft Removing.', 'Airfield Specialized Lift Trucks (FSC 3930), and Trailers (FSC 2330); Highway Type Trucks (FSC 2320), and Trailers (FSC 2330); Cargo Loading and Unloading Trailers (FSC 2330) and Trucks (FSC 2320).', 'This class excludes "vehicular components" such as those listed under FSCs 2520, 2530, 2590.', '17 - AEROSPACE CRAFT LAUNCHING, LANDING, GROUND HANDLING AND SERVICING EQUIPMENT', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('19', 'SHIPS, SMALL CRAFT, PONTOON, DOCKS', '1979-10-01', null, null, null, null, 'Only complete ships, small craft, floating docks, floating drydocks, and dredges (with or without hull) are classified in this group. End items, assemblies, parts, attachments, or accessories for use in or on the above are classified in group 20-Ship and Marine Equipment, unless other classes (outside of group 19) are applicable.', null, null, null, null, null, null),
  ('1905', 'COMBAT SHIPS AND LANDING VESSELS', '1978-10-15', null, 'Combat Ships and Landing Vessels', 'Aircraft Carriers; Battleships; Cruises; Destroyers; Submarines; Frigates and Corvettes; Gunboats; Motor Torpedo Boats; Subchasers; Landing Barges; Minelaying and Mine Sweeping Craft.', null, null, '19 - SHIPS, SMALL CRAFT, PONTOON, DOCKS', null, '11.0', 'Aircraft, Ships/Submarines & Land Vehicles', '11.3', 'Ships & Submarines'),
