  ('22', 'RAILWAY EQUIPMENT', '1979-10-01', null, null, null, null, null, null, null, null, null, null, null),
  ('2210', 'LOCOMOTIVES', '1978-10-15', null, 'Locomotives', 'Self-Propelled Cars.', 'Self-Propelled Cars.', 'This class includes only complete locomotives and tenders. End items, assemblies, parts, attachments, or accessories for use in or on locomotives and tenders are classified in classes other than this class.', '22 - RAILWAY EQUIPMENT', null, '7.0', 'Transportation and Logistics Services', '7.6', 'Transportation Equipment'),
  ('2220', 'RAIL CARS', '1978-10-15', null, 'Rail Cars', 'Trailed Cars; Self-Propelled Cars.', 'Aerial Tramway Cars.', 'This class includes only complete rail cars. End items, assemblies, parts, attachments, or accessories for use in or on rail cars are classified in classes other than this class.', '22 - RAILWAY EQUIPMENT', null, '7.0', 'Transportation and Logistics Services', '7.6', 'Transportation Equipment'),
  ('2230', 'RIGHT-OF-WAY CONSTRUCTION AND MAINTENANCE EQUIPMENT, RAILROAD', '2011-10-01', null, 'Right-of-Way Construction and Maintenance Equipment, Railroad', 'Rail Laying, Joining, and Shifting Equipment; Self Propelled and Car Mounted Cranes.', 'Hand Tools (FSG 51).', null, '22 - RAILWAY EQUIPMENT', null, '7.0', 'Transportation and Logistics Services', '7.6', 'Transportation Equipment'),
  ('2240', 'LOCOMOTIVE AND RAIL CAR ACCESSORIES AND COMPONENTS', '2011-10-01', null, 'Locomotive and Rail Car Accessories and Components', 'Brake Beams and Components; Couplers; Trucks and Components; Journals and Components; Wheel Sets and Components.', 'Railroad Furniture (FSG 71).', null, '22 - RAILWAY EQUIPMENT', null, '7.0', 'Transportation and Logistics Services', '7.6', 'Transportation Equipment'),
  ('2250', 'TRACK MATERIAL, RAILROAD', '1978-12-15', null, 'Track Material, Railroad', 'Railroad Rails; Railroad Tie Plates; Railroad Turnouts and Components; Railroad Spikes.', 'Ballast (FSC 5610); Railroad Ties (FSC 5510).', null, '22 - RAILWAY EQUIPMENT', null, '7.0', 'Transportation and Logistics Services', '7.6', 'Transportation Equipment'),
  ('23', 'MOTOR VEHICLES, CYCLES, TRAILERS', '1979-10-01', null, null, null, null, null, null, null, null, null, null, null),
  ('2305', 'GROUND EFFECT VEHICLES', '1978-11-15', null, 'Ground Effect Vehicles', null, null, null, '23 - MOTOR VEHICLES, CYCLES, TRAILERS', null, '7.0', 'Transportation and Logistics Services', '7.5', 'Motor Vehicles'),
  ('2310', 'PASSENGER MOTOR VEHICLES', '1978-10-15', null, 'Passenger Motor Vehicles', 'Cars, Motor, Highway; Buses; Chassis, Passenger Motor Vehicle; Hearses; Ambulances.', 'Amphibious Personnel Carriers; All Truck Chassis.', 'This class includes only complete passenger motor vehicles, and chassis therefor. Any end items, assemblies, parts, attachments, or accessories, other than complete chassis, for use in or on passenger motor vehicles are classified in classes other than this class.', '23 - MOTOR VEHICLES, CYCLES, TRAILERS', null, '7.0', 'Transportation and Logistics Services', '7.5', 'Motor Vehicles'),
  ('2320', 'TRUCKS AND TRUCK TRACTORS, WHEELED', '1978-10-15', null, 'Trucks and Truck Tractors, Wheeled', 'Panel, Delivery and Pick Up Trucks, Tactical and Administrative Military Cargo Carrying Vehicles, including Wheel Mounted Amphibian Vehicles; Truck Tractor and Trailer Combinations; Armored Cars.', 'Fire Trucks; Special Construction Type Earth and Rock Hauling Trucks; Motorized Air Compressors; Motorized Concrete Mixers; Construction Specialized Machinery Generally; Specially designed trucks for use in and around, airfields, hangars, and warehouses; Tracked and Halftracked Vehicles.', 'This class includes only complete wheel mounted trucks and truck tractors, and chassis therefore. Any end items, assemblies, parts, attachments, or accessories other than complete chassis, for use in or on such trucks or truck tractors are classified in classes other than this class. The combined chassis and body of a special purpose truck, such as a machine shop, mobile laundry, or dental laboratory, is classified in this class. The complete mobile unit, consisting of chassis, body, and additional equipment, as in an equipped truck mounted machine shop, is excluded from this class.', '23 - MOTOR VEHICLES, CYCLES, TRAILERS', null, '7.0', 'Transportation and Logistics Services', '7.5', 'Motor Vehicles'),
  ('2330', 'TRAILERS', '1978-10-15', null, 'Trailers', 'Semitrailers; Semitrailer Dollies; Cargo Trailers; Passenger and House Trailers; Special Purpose Trailers, such as Ammunition.', 'Fire Fighting Trailers; Specially designed trailers for use in and around airfields, hangars, and warehouses.', 'This class includes only complete trailers, and chassis therefor. Any end items, assemblies, parts, attachments, or accessories, other than complete chassis, for use in or on trailers are classified in classes other than this class. The combined chassis and body of a special purpose trailer, such as a machine shop, mobile laundry, or dental laboratory, is classified in this class. The complete mobile unit, consisting of chassis, body, and additional equipment, as in an equipped trailer-mounted machine shop, is excluded from this class.', '23 - MOTOR VEHICLES, CYCLES, TRAILERS', null, '7.0', 'Transportation and Logistics Services', '7.6', 'Transportation Equipment'),
  ('2340', 'MOTORCYCLES, MOTOR SCOOTERS, AND BICYCLES', '2011-10-01', null, 'Motorcycles, Motor Scooters, and Bicycles', 'Sidecars; Tricycles.', 'Children''s Wheeled Goods.', 'This class includes only complete motorcycles, complete motor scooters, and complete bicycles. End items, assemblies, parts, attachments, or accessories for use in or on motorcycles, motor scooters, or bicycles are classified in classes other than this class.', '23 - MOTOR VEHICLES, CYCLES, TRAILERS', null, '7.0', 'Transportation and Logistics Services', '7.6', 'Transportation Equipment'),
  ('2350', 'COMBAT, ASSAULT, AND TACTICAL VEHICLES, TRACKED', '2011-10-01', null, 'Combat, Assault, and Tactical Vehicles, Tracked', 'Tanks and Tracked Self-Propelled Weapons and Vehicles with or without amphibian capabilities; Armored Halftracks; Self-Propelled Sleds; and Self-Propelled Flame Throwers.', 'Wheel Mounted Vehicles', 'This class includes only complete combat, assault, and tactical tracked vehicles, and chassis therefor. Any end items, assemblies, parts, attachments, or accessories, other than complete chassis, for use in or on such vehicles are classified in classes other than this class.', '23 - MOTOR VEHICLES, CYCLES, TRAILERS', null, '11.0', 'Aircraft, Ships/Submarines & Land Vehicles', '11.2', 'Land Combat Vehicles'),
  ('2355', 'COMBAT, ASSAULT, AND TACTICAL VEHICLES, WHEELED', '2011-10-01', null, 'Combat, Assault, and Tactical Vehicles, Wheeled', 'Wheeled Self-Propelled Weapons and combat vehicles with or without amphibian capabilities; Armored Wheeled Vehicles; Self-Propelled Wheeled Sleds; and Self-Propelled Wheeled Flame Throwers.', 'Track Mounted Vehicles not specifically designed for combat, assault, tactical situations; Passenger Motor Vehicles (FSC 2310)', 'This class includes only complete combat, assault, and tactical wheeled vehicles and chassis. Any end items, assemblies, parts, attachments, or accessories, other than complete chassis, for use in or on such vehicles are classified in classes other than this class.', '23 - MOTOR VEHICLES, CYCLES, TRAILERS', null, '11.0', 'Aircraft, Ships/Submarines & Land Vehicles', '11.2', 'Land Combat Vehicles'),
  ('24', 'TRACTORS', '1979-10-01', null, null, null, null, 'This group includes only complete tractors and tractor chassis. Assemblies, subassemblies, parts, attachments or accessories are excluded from this group.', null, null, null, null, null, null),
  ('2410', 'TRACTOR, FULL TRACKED, LOW SPEED', '2011-10-01', null, 'Tractors, Full Tracked, Low Speed', 'High Speed Tractors (FSC Class 2430 Armored Dozer-Scraper Combination Tractors (FSC Class 2350).', 'High Speed Tractors (FSC Class 2430 Armored Dozer-Scraper Combination Tractors (FSC Class 2350).', 'This class includes only complete low speed, full track tractors, and chassis therefor. Any end items, assemblies, parts, attachments, or accessories, other than complete chassis, for use in or on low speed, full track tractors are classified in classes other than this class.', '24 - TRACTORS', null, '7.0', 'Transportation and Logistics Services', '7.6', 'Transportation Equipment'),
  ('2420', 'TRACTORS, WHEELED', '1978-10-15', null, 'Tractors, Wheeled', 'Agricultural Tractors; High Speed Tractors; Industrial Tractors.', 'Aircraft Towing Tractors and Crashed Aircraft Moving Tractors (FSC Class 1740); Aircraft Towing-Power Servicing Tractors (FSC Class 1730); Warehouse Tractors (FSC Class 3930).', 'This class includes only complete wheeled tractors, and chassis therefor. Any end items, assemblies, parts, attachments, or accessories, other than complete chassis, for use in or on wheeled tractors, are classified in classes other than this class.', '24 - TRACTORS', null, '7.0', 'Transportation and Logistics Services', '7.6', 'Transportation Equipment'),
  ('2430', 'TRACTORS, FULL TRACKED, HIGH SPEED', '1978-11-15', null, 'Tractors, Full Tracked, High Speed', 'Low Speed Tractors (FSC Class 2410); Armored Dozer-Scraper Combination Tractors (FSC Class 2350).', 'Low Speed Tractors (FSC Class 2410); Armored Dozer-Scraper Combination Tractors (FSC Class 2350).', 'This class includes only complete high speed track laying tractors, and chassis therefor. Any end items. assemblies, parts, attachments, or accessories, other than complete chassis, for use in or on high speed track laying tractors, are classified in classes other than this class.', '24 - TRACTORS', null, '7.0', 'Transportation and Logistics Services', '7.6', 'Transportation Equipment'),
  ('25', 'VEHICULAR EQUIPMENT COMPONENTS', '1979-10-01', null, null, null, null, 'The term "vehicular", as delimited for group 25, is applicable to those vehicles. And tractors included in groups 23 and 24, construction vehicles included in group 38, and warehouse trucks, tractors, and trailers included in group 39. It does not apply to railway vehicles (group 22), aircraft (group 15), or watercraft (group 19). An item of supply which is a "vehicular" component, within the scope delimited above, is classified in this group, regardless of whether it has additional applications on vehicles outside the delimitations for this group.', null, null, null, null, null, null),
  ('2510', 'VEHICULAR CAB, BODY, AND FRAME STRUCTURAL COMPONENTS', '2011-10-01', null, 'Vehicular Cab, Body, and Frame Structural Components', 'Leaf Type Vehicular Springs; Suspension Type Shock Absorbers.', 'Vehicular Hardware (FSG 53); Specialized Vehicular Furniture (FSC 2540).', null, '25 - VEHICULAR EQUIPMENT COMPONENTS', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2520', 'VEHICULAR POWER TRANSMISSION COMPONENTS', '2011-10-01', null, 'Vehicular Power Transmission Components', 'Transfer Transmission Assemblies; Clutch Assemblies; Universal Joints; Propeller Shafts; Automotive Torque Converters; Power Takeoffs.', null, null, '25 - VEHICULAR EQUIPMENT COMPONENTS', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2530', 'VEHICULAR BRAKE, STEERING, AXLE, WHEEL, AND TRACK COMPONENTS', '2011-10-01', null, 'Vehicular Brake, Steering, Axle, Wheel, and Track Components', 'Turret Brakes; Clutch Brakes, Tank Turret.', null, null, '25 - VEHICULAR EQUIPMENT COMPONENTS', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2540', 'VEHICULAR FURNITURE AND ACCESSORIES', '1978-10-15', null, 'Vehicular Furniture and Accessories', 'Automobile Seat Covers; Shock Absorber, Bumper; Windshield Wipers; Bumper Guards; Mirrors, Rear View and Side View; Vehicle Heaters.', 'Speedometers (FSC 6680); Suspension Type Shock Absorbers (FSC 2510).', null, '25 - VEHICULAR EQUIPMENT COMPONENTS', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2541', 'WEAPONS SYSTEMS SPECIFIC VEHICULAR ACCESSORIES', '2011-10-01', null, 'Weapons Systems Specific Vehicular Accessories', 'Accessory Kits and Boxes, Parts Kits, and individual components used in the repair and/or modification of Weapons System type Vehicles such as Tanks, Personnel Carriers, Mobile Howitzers, and the like.', 'Items used in the repair and/or modifications of Commercial Type Vehicles (FSC 2540), vehicular type light fixtures (FSC 6220), and electronic switches, parts kits, and modification kits (FSG 59).', null, '25 - VEHICULAR EQUIPMENT COMPONENTS', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2590', 'MISCELLANEOUS VEHICULAR COMPONENTS', '1978-10-15', null, 'Miscellaneous Vehicular Components', 'Attachments for Tanks, Self-propelled Weapons, and High Speed Tractors; A-frames and Winches specifically designed for truck mounting; Cranes and Crane Booms for Wrecker Trucks.', null, null, '25 - VEHICULAR EQUIPMENT COMPONENTS', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
