  ('2835', 'GAS TURBINES AND JET ENGINES; NON-AIRCRAFT PRIME MOVER, AIRCRAFT NON-PRIME MOVER, AND COMPONENTS', '2011-10-01', null, 'Gas Turbines and Jet Engines, Non-Aircraft; and Components', 'Airflow Deflectors; Turbine Cases; Turbine Housings; Compressor and Turbine Rotors; Compressor and Turbine Rotor Blades; Combustion Chamber; Accessory Gear Box; Turbine Disks and Hubs; Turbine Vanes.', 'Engine Fuel System Components (FSC 2910); Engine electrical System Components (FSC 2920); Engine Cooling System Components (FSC 2930); Engine Air/Oil Cleaners/Filters/Strainers (FSC 2940); Engine Accessories (Air Duct Heaters, Engine Mounted Control Assemblies) (FSC 2990).', 'Engines and Components classified in this FSC are primarily for use on non-aircraft equipment but can also be used on aircraft ground support equipment.', '28 - ENGINES AND TURBINES AND COMPONENT', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2840', 'GAS TURBINES AND JET ENGINES, AIRCRAFT, PRIME MOVING; AND COMPONENTS', '2011-10-01', null, 'Gas Turbines and Jet Engines, Aircraft, Prime Moving; and Components', 'Compressor and Turbine Rotors; Blades; Combustion Chamber; Accessory Gear Box; Afterburner; Exhaust Cone; Reservoirs, Hydraulic; Tank, Oil.', 'Oil, Air, Anti-icing, and Hydraulic Regulators, Valves, and Pumps specially designed for Gas Turbines and Jet Engines (FSC 2995); Control Assemblies, Push-Pull (FSC 2995); Engine Mounted Control Assemblies (FSC 2995); Fuel System Components (FSC 2915); Engine Electrical System Components (FSC 2925); Engine Cooling System Components (FSC 2935); Engine Air/Oil Cleaner/Filter/Strainers (FSC 2945).', 'Engines and Components classified in this FSC are intended for use as/on aircraft and/or guided missile prime movers.', '28 - ENGINES AND TURBINES AND COMPONENT', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2845', 'ROCKET ENGINES AND COMPONENTS', '1978-11-15', null, 'Rocket Engines and Components', 'Rocket Prime Movers, Liquid Type, including Liquid Jet Assisted Takeoff (JATO) Units, for use in aircraft, rockets, and guided missiles; Liquid Propellants encased in consumable containers, intended for insertion into missile propulsion systems as integral parts.', 'Rocket Motors (Solid Propellant Units) (FSC 1337); Liquid Propellants predetermined to specific quantity and quality, but packaged in reusable containers; Solid Propellant Squibs and Cartridges, whether intended for insertion into Liquid Propellant Systems or not (FSC 1337).', null, '28 - ENGINES AND TURBINES AND COMPONENT', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2850', 'GASOLINE ROTARY ENGINES AND COMPONENTS', '2011-10-01', null, 'Gasoline Rotary Engines and Components', null, null, null, '28 - ENGINES AND TURBINES AND COMPONENT', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2895', 'MISCELLANEOUS ENGINES AND COMPONENTS', '2011-10-01', null, 'Miscellaneous Engines and Components', 'Wind and Compressed Air Engines.', null, null, '28 - ENGINES AND TURBINES AND COMPONENT', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('29', 'ENGINE ACCESSORIES', '1979-10-01', null, null, null, null, 'Unless specifically excluded, engine accessories for all vehicles, such as aircraft, motor vehicles, ships, tractors, and construction vehicles, as well as accessories for stationary engines, are classified in this group.', null, null, null, null, null, null),
  ('2910', 'ENGINE FUEL SYSTEM COMPONENTS, NONAIRCRAFT', '2011-10-01', null, 'Engine Fuel System Components, Nonaircraft', 'Carburetors; Fuel Pumps; Engine Fuel Filters; Fuel Tanks; Components for all engines except Aircraft and Guided Missile Prime Moving.', null, null, '29 - ENGINE ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2915', 'ENGINE FUEL SYSTEM COMPONENTS, AIRCRAFT AND MISSILE PRIME MOVERS', '2011-10-01', null, 'Engine Fuel System Components, Aircraft and Missile Prime Movers', 'Carburetors; Fuel Pumps; Engine Fuel Filters; Fuel Controls, Jet Engine; Fuel Primers; Water Injection Controls and Valves; Fuel Valves; Fuel Flow Regulators; Components of Smoke Abatement Systems.', 'Aircraft Fuel Tanks (FSC 1560); In-flight Refueling System Fuel Components (FSC 1680). Fuel System Components not specifically designed for use with Aircraft Engines or Missile Prime movers.', 'Fuel components specially designed for propulsion fuel systems, aircraft and missiles are to be placed in this FSC.', '29 - ENGINE ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2920', 'ENGINE ELECTRICAL SYSTEM COMPONENTS, NONAIRCRAFT', '2011-10-01', null, 'Engine Electrical System Components, Nonaircraft', 'Generators, Magnetos, Spark Plugs; Ignition Coils; Ignition Distributors; Engine Voltage Regulators; Ignition Harness Assemblies; Starting Motors for Engines.', 'Vehicular Lighting Fixtures (FSC 6220) and Aircraft Generators (FSC 2925).', null, '29 - ENGINE ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2925', 'ENGINE ELECTRICAL SYSTEM COMPONENTS, AIRCRAFT PRIME MOVING', '2011-10-01', null, 'Engine Electrical System Components, Aircraft Prime Moving', 'Magnetos; Igniters (Spark Plugs); Ignition Coils; Ignition Distributors; Engine Voltage Regulators; Ignition Harness Assemblies; Starting Motors for Engines; Engine Accessory Generators.', 'Aircraft Lighting Fixtures (FSC 6220); and Auxiliary Aircraft Generators (FSC 6115).', 'Items designed for specific use on aircraft and guided missile prime movers are to be placed in this FSC.', '29 - ENGINE ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2930', 'ENGINE COOLING SYSTEM COMPONENTS, NONAIRCRAFT', '2011-10-01', null, 'Engine Cooling System Components, Nonaircraft', 'Cooling Pans; Radiators; Water Pumps; Water Hose Assemblies; Engine Coolant Filters; Components for all Engines except Aircraft and Guided Missile Prime Moving.', null, null, '29 - ENGINE ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2935', 'ENGINE SYSTEM COOLING COMPONENTS, AIRCRAFT PRIME MOVING', '2011-10-01', null, 'Engine System Cooling Components, Aircraft Prime Moving', 'Radiators; Cooling System Pumps; Water Hose Assemblies; Lubricating Oil Coolers and Control Valves; Oil Temperature Regulators.', 'Cooling System Components not specifically designed for use with Aircraft Engines.', 'This class includes only cooling system components for aircraft and/or guided missile prime movers only.', '29 - ENGINE ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2940', 'ENGINE AIR AND OIL FILTERS, STRAINERS, AND CLEANERS, NONAIRCRAFT', '2011-10-01', null, 'Engine Air and Oil Filters, Strainers, and Cleaners, Nonaircraft', 'Components for all Engines except Aircraft and Guided Missile Prime Moving.', 'Air and Oil Filters (FSC 4310, 4330), Strainers (FSC 4730), and Cleaners (FSC 4310) not specifically designed for use with engines.', null, '29 - ENGINE ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2945', 'ENGINE AIR AND OIL FILTERS, CLEANERS, AIRCRAFT PRIME MOVING', '2011-10-01', null, 'Engine Air and Oil Filters, Cleaners, Aircraft Prime Moving', 'Air Filters; Oil Filters; Strainers; Cleaners.', 'Fuel Filters (FSC 2915); Items designed for other than Engines.', 'Items placed in this FSC should be specifically designed for use on aircraft or guided missile prime movers only.', '29 - ENGINE ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2950', 'TURBOSUPERCHARGER AND COMPONENTS', '2011-10-01', null, 'Turbosuperchargers and components', 'Turbosupercharged Regulators; Ground and Aircraft Engine Turbosuperchargers.', 'Engine Integrated Superchargers (FSG 28).', 'All turbosuperchargers and their components not elsewhere classifiable will be classified in this FSC.', '29 - ENGINE ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2990', 'MISCELLANEOUS ENGINE ACCESSORIES, NONAIRCRAFT', '2011-10-01', null, 'Miscellaneous Engine Accessories, Nonaircraft', 'Engine Dynafocal Suspension Mounts; Engine Driven Superchargers (not integrated with engine); Starter Cranks; Engine Starter Ropes; Exhaust Mufflers; Hand Inertia Starters; Air Duct Heaters; Engine Governors; Intake Mufflers; Combustion Type Starters; Miscellaneous Accessories for all Engines except Aircraft and Guided Missile Prime Moving.', 'Electrical Starters Non-Aircraft (FSC 2920); Aircraft (FSC 2925).', null, '29 - ENGINE ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
  ('2995', 'MISCELLANEOUS ENGINE ACCESSORIES, AIRCRAFT', '2011-10-01', null, 'Miscellaneous Engine Accessories, Aircraft', 'Engine Dynafocal Suspension Mounts; Engine Cowling Mounts; Engine Mounted Control Assemblies; Pneumatic Starters; Push-Pull Control Assemblies; Specially designed Jet Engine Air, Oil, Anti-icing and Hydraulic Regulators; Valves and Pumps; Starting Units.', 'Exhaust System; (FSC 1560); Jet Engine Hydraulic Reservoirs (FSC 2840); Jet Engine Oil Tanks (FSC 2840); Electrical Starters (FSC 2925); Cockpit Mounted Control Quadrants (FSC 1680); Aircraft Engine Covers (FSC 1730).', 'Items classified in this class must be specifically designed for use with aircraft or guided missile prime-movers only.', '29 - ENGINE ACCESSORIES', null, '14.0', 'Sustainment S&E', '14.2', 'Engines, Components & Spt Eq'),
