  ('31', 'BEARINGS', '1979-10-01', null, null, null, null, 'All bearings, including specially designed, lubricated, and/or selected, are to be classified in the appropriate classes of this group. Bearings are parts that support another part which rotates, slides, or oscillates in or on it.', null, null, null, null, null, null),
  ('3110', 'BEARINGS, ANTIFRICTION, UNMOUNTED', '1978-10-15', null, 'Bearings, Antifriction, Unmounted', 'Ball Bearings; Roller Bearings: Balls; Races.', 'Plain Bearings (FSC 3120); Jewel Bearings (FSC 3120).', 'This class includes bearings that generally have roller or balls confined by an inner and outer ring to relieve friction in/on/around rotating/moving mechanisms.', '31 - BEARINGS', null, '5.0', 'Industrial Products & Services', '5.1', 'Machinery & Components'),
  ('3120', 'BEARINGS, PLAIN, UNMOUNTED', '1978-10-15', null, 'Bearings, Plain, Unmounted', 'Sleeve Bearings; Split Bearings; Washer Type Bearings; Jewel Bearings.', 'Antifriction Bearings (FSC 3110); Mounted Bearings (FSC 3130).', 'Bearings in this class are generally one piece that retain and position moving and/or rotating parts. They may have lubrication grooves/fitting/facilities or include pre-lubrication.', '31 - BEARINGS', null, '5.0', 'Industrial Products & Services', '5.1', 'Machinery & Components'),
  ('3130', 'BEARINGS, MOUNTED', '1978-11-15', null, 'Bearings, Mounted', 'Pillow Block Units; Cartridge Units; Flange Units; Takeup Units; Hanger Box Units; Flat Box Units; Step Box Units.', 'Antifriction Bearings (FSC 3110); Plain Unmounted Bearings (FSC 3120).', 'Bearings in this class may be plain bearings or anti-friction bearings that are housed and/or mounted in a supporting device for mounting purposes.', '31 - BEARINGS', null, '5.0', 'Industrial Products & Services', '5.1', 'Machinery & Components'),
