  ('5180', 'SETS, KITS, AND OUTFITS OF HAND TOOLS', '2011-10-01', null, 'Sets, Kits, and Outfits of Hand Tools', null, null, 'This class includes sets, kits, and outfits consisting of several different item classifiable either in a single class or in several classes. Excluded from this class are sets, kits, and outfits consisting of variations (such as size or color) of an item. Classify these items in the same class as the individual item.', '51 - HAND TOOLS', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('52', 'MEASURING TOOLS', '1979-10-01', null, null, null, null, null, null, null, null, null, null, null),
  ('5210', 'MEASURING TOOLS, CRAFTSMEN''S', '1978-10-15', null, 'Measuring Tools, Craftsmen''s', 'Calipers; Levels; Micrometers; Plumb Bobs; Precision Tapes; Squares; Angle Gages; Center Gages; Depth Gages; Draw Gages; Drill Point Gages; Fillet and Radius Gages; Glaziers'' Gages; Height Gages (Vernier); Planer Gages; Rivet Selector Gages; Saw Tooth Set Gages; Screw Pitch Gages; Surface Gages; Telescoping Gages; Thickness Gages; Tube Bead Gages; Tube Flare Gages; Twist Drill Gages; Twist Drill and Rod Gages; Twist Drill and Tap Gages; Taper-Wire-Thickness Gages; Wire Gages; Tool Setting Planer and Shaper Gages; Gage Blocks.', null, 'This class does not include special inspection gages, which are classified in class 5220.', '52 - MEASURING TOOLS', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5220', 'INSPECTION GAGES AND PRECISION LAYOUT TOOLS', '2011-10-01', null, 'Inspection Gages and Precision Layout Tools', 'Go and Not-Go Gages, including Plug, Ring, Snap, Thread, and Length Gages; Profile Gages; Fixture Gages; Special Inspection Gages.', null, 'Special inspection gages are included in this class.', '52 - MEASURING TOOLS', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
