  ('53', 'HARDWARE AND ABRASIVES', '1979-10-01', null, null, null, null, null, null, null, null, null, null, null),
  ('5305', 'SCREWS', '1978-10-15', null, 'Screws', null, null, null, '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5306', 'BOLTS', '1978-10-15', null, 'Bolts', null, null, null, '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5307', 'STUDS', '1978-10-15', null, 'Studs', null, null, null, '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5310', 'NUTS AND WASHERS', '1978-10-15', null, 'Nuts and Washers', 'Locknuts; Eye Nuts; Plain Nuts; Castellated Nuts; Wing Nuts; Plate Nuts; Push on Nuts; Concave and Convex Washers; Flat Washers; Keyed Washers; Lock Washers; Shouldered Washers; Split Washers.', 'Bearing Thrust Washers (FSC 3120); Shims (FSC 5365); Ring Spacers (FSC 5365); Plate Spacers (FSC 5365); Lock Rings (FSC 5365).', 'Nuts and washers, including specially designed, are to be classified in this FSC. a. Nuts are a small metal block made in a variety of shapes such as square and hexagonal which is drilled and internally threaded. b. Washers are a perforated piece of metal, leather, or other materials of various shapes or forms. They are used primarily as a seat for a bolt, nut, screw, rivet or nail to distribute pressure and prevent endwise motion over an area and/or to prevent movement between two parts by means of restraining features created by the shape of its edges.', '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5315', 'NAILS, MACHINE KEYS, AND PINS', '1978-10-15', null, 'Nails, Machine Keys, and Pins', 'Dowel Pins, Split Pins; Spikes; Tacks; Nonoffice Type Staples; Machine Keys; Brads; Shouldered Pins; Cotter Pins; Nails.', 'Shafts (FSC 3040); Lock Keys (FSC 5340).', 'Nails, machine keys, and pins, including specially designed, will be classified in this FSC. a. Nails are slender, usually pointed fasteners with a head, and designed for insertion by impact. b. Machine keys are items generally inserted between two items, usually in a groove, to prevent relative rotation, e.g., shaft and hub, c. Pins are cylindrical items of various materials used to align/attach two or more parts together and may allow for angular movement.', '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5320', 'RIVETS', '1978-10-15', null, 'Rivets', null, null, null, '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5325', 'FASTENING DEVICES', '1978-10-15', null, 'Fastening Devices', 'Eyelets; Grommets; Aircraft Cowling Fasteners; Textile Fasteners; Retaining Rings; Threaded Inserts.', null, null, '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5330', 'PACKING AND GASKET MATERIALS', '1978-10-15', null, 'Packing and Gasket Materials', 'General Purpose Oil Grease, Air, Liquid, Gas, and chemical Seals; Oakum; Prefabricated Gaskets and Seals designed for a single specific application.', 'O-Rings (FSC 5331); Bulk material items, such as; Rubber, Cork, and Asbestos Sheets and Strips (FSG 93); Liquid Gasket Materials (RTV), Permatex, etc.) (FSG 80); RFI and EMI Seals and Gaskets (FSC 5999), and all Seal Retainers.', 'This FSC includes only seals and gaskets designed for standard use. Seals, gaskets and packing are made from materials specifically designed and constructed to resist deterioration from the action of heat, gas, chemicals, liquids, and used to fill a cavity and create a tight seal. Similar materials used to make seals, gaskets and packing are available in bulk form, refer to FSG 93, FSG 80, and FSG 83.', '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5331', 'O-RING', '1998-10-01', null, 'O-Ring', null, 'Packing and Gasket Material (FSC 5330).', null, '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5335', 'METAL SCREENING', '1978-10-15', null, 'Metal Screening', 'Insect Screening; Industrial Metal Cloth; Industrial Metal Mesh.', 'Fencing (FSC 5660).', 'Metal Screening is a perforated plate or cylinder or a meshed wire fabric usually mounted and used to separate coarse from finer parts.', '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5340', 'HARDWARE, COMMERCIAL', '2011-10-01', null, 'Hardware', 'Access Covers; Bumpers; Casters; Cabinet and Door Hardware; Clevises; Hinges; Latches; Straps and Strapping; Turnbuckles; Webbed Straps.', 'Weapons System Hardware (5342).', 'Common hardware designed primarily for commercial use will be classified in this FSC. Hardware is the physical, tangible, and permanent components of end items that may not be classified elsewhere. It consists also of common items that are commonly used in construction and/or manufacturing (e.g., hinges, door locks).', '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5342', 'HARDWARE, WEAPON SYSTEM', '1998-10-01', null, 'Hardware, Weapon System', 'Adapters; Anchor Plates and Straps; Anodes; Bellows; Couplings; Control Rods; Access Doors; Fairleads; Mounts; Tie Rods; Yokes.', 'Commercial Hardware (FSC 5340).', 'Hardware designed for weapon systems unique applications will be classified in this FSC.', '53 - HARDWARE AND ABRASIVES', null, '14.0', 'Sustainment S&E', '14.4', 'Supply Parts'),
  ('5345', 'DISKS AND STONES, ABRASIVE', '1978-11-15', null, 'Disks and Stones, Abrasive', 'Abrasive Belts and Belting; Hones; Abrasive Wheels, Multiapplication.', 'Dental Abrasives; Abrasive Cones, and other Abrasive Attachments for equipment.', null, '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5350', 'ABRASIVE MATERIALS', '1978-10-15', null, 'Abrasive Materials', 'Cloth; Papers; Powders; Abrasive Polishing Compounds; Metal Finishing Abrasives; Industrial Diamonds; Diamond Dust; Rouge.', null, null, '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5355', 'KNOBS AND POINTERS', '1979-08-15', null, 'Knobs and Pointers', 'Knobs, including Calibrated Knobs; Dials, Scale.', null, null, '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5360', 'COIL, FLAT, LEAF, AND WIRE SPRINGS', '1978-10-15', null, 'Coil, Flat, Leaf, and Wire Springs', 'Compression Springs; Torsion Springs; Leaf Spring Assemblies; Flat Springs; Extension Springs.', null, 'All springs, including specially designed will be classified in this FSC. A spring is an elastic mechanical device that regains its original shape after being compressed, extended or deflected.', '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
  ('5365', 'BUSHINGS, RINGS, SHIMS, AND SPACERS', '2011-10-01', null, 'Bushings, Rings, Shims and Spacers', 'Externally Threaded Rings; Keyed and Serrated Lock Rings; Dee Rings; Instrument Retaining Rings; Shim Sets and Assortments; Plate Spacers; Ring Spacers; Sleeve Spacers; Stepped Spacers; Spacer Sets and Assortments; Sleeve Bushings; Machine Threaded Bushings; Machine Threaded Plugs.', 'Sleeve Bearings (FSC 3120); Pipe Threaded Plugs (FSC 4730); Piston Rings (FSC 2520, 2805, 2810, 2815, 2825, 2990, 3040, 4310 and 4820); Retaining Rings (FSC 5325); Shim Stock (FSC 9515).', 'All items, including specially designed, will be classified in this FSC. a. A bushing is cylindrical in shape, hollow, and designed primarily to be inserted into a hole to reduce the effective inside diameter of the hole, and to protect the body structure about the hole, and to protect the body structure about the hole from damage resulting from stress, strain, and vibration. b. A ring is cylindrical in shape, usually flat with a center hole. Rings are multi-applicational. See specific item name for designated usage. c. A shim is a thin, sometimes tapered, piece of material used to fill in space between things. See specific item name for dimensional parameters. d. A spacer is a device for holding two members at a given distance from each other.', '53 - HARDWARE AND ABRASIVES', null, '5.0', 'Industrial Products & Services', '5.3', 'Hardware & Tools'),
