  ('5419', 'COLLECTIVE MODULAR SUPPORT SYSTEM', '1991-10-01', null, 'Collective Modular Support System', 'Self-Contained habitat, containing facilities normally expected in a "Rest and Recreational" area, such as; billeting, food services, laundry, shower/hygiene services, recreational and support services that enhance morale and welfare.', null, null, '54 - PREFAB STRUCTURES/SCAFFOLDING', null, '4.0', 'Facilities & Construction', '4.1', 'Construction Related Materials'),
