  ('5670', 'BUILDING COMPONENTS, PREFABRICATED', '1978-11-15', null, 'Building Components, Prefabricated', 'Door Frames; Window Frames; Window Sashes; Eave Troughs (gutters); Gratings; Grilles, Shutters; Fixed Fire Escapes; Mounted Partitions.', 'Plumbing and Associated Components such as Sinks; Wallboard and Items Classified as Furniture.', 'Items specified as Wooden are classified in FSC 5520.', '56 - CONSTRUCTION AND BUILDING MATERIAL', null, '4.0', 'Facilities & Construction', '4.1', 'Construction Related Materials'),
  ('5675', 'NONWOOD CONSTRUCTION LUMBER AND RELATED MATERIALS', '2011-10-01', null, 'Nonwood Construction Lumber and Related Materials', 'Nonwood Dimensional Lumber; Flooring; Special Turning and Carvings; Nonwood Veneer.', 'Millwork and Wood Veneer (FSC''s 5520 and 5530); Items specified as Wooden (FSC 5510).', null, '56 - CONSTRUCTION AND BUILDING MATERIAL', null, '4.0', 'Facilities & Construction', '4.1', 'Construction Related Materials'),
  ('5680', 'MISCELLANEOUS CONSTRUCTION MATERIALS', '2011-10-01', null, 'Miscellaneous Construction Materials', 'Expanded Metal Lath; Airplane Landing Mats; Traction Mats.', null, null, '56 - CONSTRUCTION AND BUILDING MATERIAL', null, '4.0', 'Facilities & Construction', '4.3', 'Facility Related Materials'),
  ('58', 'COMM/DETECT/COHERENT RADIATION', '1979-10-01', null, null, null, null, 'Excludes oscillator items which should be classified in FSC 5955 or 5963; fiber optic items which should be classified in Group 60; electronic modules as defined under Class 5963; and electrical cable, cord and wire assemblies, harnesses and sets, related to FSG 58 equipment (see FSC 5995). In group 58, more than in any other group, it frequently happens that the same name is listed as an index entry in each of several classes. In addition, that name may also appear as an entry in groups other than 58. Each such entry refers to a distinctly different part or assembly, even though the different items have the same name. The listing of the same name in two or more classes indicates that, in one form, the part or assembly covered by the name is applicable to the equipment covered by one class, and in another form is applicable to the equipment covered by another class. For example, the item name CODER, AUDIO FREQUENCY is applicable to two distinctly different assemblies, one of which has an application in cryptologic equipment, covered by class 5810, and the other in radar equipment covered by class 5840. Consequently the name CODER, AUDIO FREQUENCY is an entry under each of the two classes. When an item identification bears a name which is indexed under more than one class of group 58, or in group 58 and in some other group, the item will be classified in the same class as its next higher assembly in the manner described in the Department of Defense, Federal Logistics Information System (FLIS) Procedures Manual, DoD 4100.39-M. Also excluded from this group are data transmission and communications equipment such as terminals, sensors, and other devices designed for use with a configuration of ADPE.', null, null, null, null, null, null),
  ('5805', 'TELEPHONE AND TELEGRAPH EQUIPMENT', '2022-04-02', null, 'Telephone and Telegraph Equipment', null, 'Office phones purchased under IT Category, 7G20 and 7G21.', null, '58 - COMM/DETECT/COHERENT RADIATION', null, null, null, null, null),
  ('5810', 'COMMUNICATIONS SECURITY EQUIPMENT AND COMPONENTS', '2011-10-01', null, 'Communications Security Equipment and Components', null, null, null, '58 - COMM/DETECT/COHERENT RADIATION', 'P', '3.0', 'Security and Protection', null, null),
  ('5811', 'OTHER CRYPTOLOGIC EQUIPMENT AND COMPONENTS', '2022-04-02', null, 'Other Cryptologic Equipment and Components', null, null, null, '58 - COMM/DETECT/COHERENT RADIATION', null, '6.0', 'Office Management', '6.1', 'Office Management Products'),
