  ('5825', 'RADIO NAVIGATION EQUIPMENT, EXCEPT AIRBORNE', '2011-10-01', null, 'Radio Navigation Equipment, Except Airborne', 'Loran Equipment; Shoran Equipment; Direction Finding Equipment.', null, null, '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.1', 'Communication Equipment'),
  ('5826', 'RADIO NAVIGATION EQUIPMENT, AIRBORNE', '2011-10-01', null, 'Radio Navigation Equipment, Airborne', 'Loran Equipment; Shoran Equipment; Direction Finding Equipment.', null, null, '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.1', 'Communication Equipment'),
  ('5830', 'INTERCOMMUNICATION AND PUBLIC ADDRESS SYSTEMS, EXCEPT AIRBORNE', '2011-10-01', null, 'Intercommunication and Public Address Systems, Except Airborne', 'Wired Audio Systems; Office Type Systems; Shipboard Systems; Tank Systems.', null, null, '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.1', 'Communication Equipment'),
  ('5831', 'INTERCOMMUNICATION AND PUBLIC ADDRESS SYSTEMS, AIRBORNE', '2011-10-01', null, 'Intercommunication and Public Address Systems, Airborne', null, null, null, '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.1', 'Communication Equipment'),
  ('5835', 'SOUND RECORDING AND REPRODUCING EQUIPMENT', '2011-10-01', null, 'Sound Recording and Reproducing Equipment', 'Phonographs, Home Type; Dictating Machines.', 'Phonographs, Home Type; Dictating Machines.', null, '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.1', 'Communication Equipment'),
  ('5836', 'VIDEO RECORDING AND REPRODUCING EQUIPMENT', '2011-10-01', null, 'Video Recording and Reproducing Equipment', null, null, 'This class includes, and is restricted to electronic video equipment such as video monitors, televisions, cameras, printers and recorders/ reproducers used with miscellaneous communication equipment. Also included is associated equipment such as cleaners, splicers, rewinders, reels and tapes designed for use with video recording-reproducing equipment. Excluded from the class is photographic type equipment (Group 67), ADP type computer monitors (Group 70), and video equipment which includes radio receivers/transmitters (properly classified in more specific classes in Group 58).', '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.1', 'Communication Equipment'),
  ('5840', 'RADAR EQUIPMENT, EXCEPT AIRBORNE', '1978-10-15', null, 'Radar Equipment, Except Airborne', null, null, 'Radar assemblies and subassemblies designed specifically for use with fire control equipment or guided missiles are excluded from this class and are included in the appropriate classes of group 12 or group 14.', '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.2', 'Detection & Coherent Radiation Eq'),
  ('5841', 'RADAR EQUIPMENT, AIRBORNE', '1978-10-15', null, 'Radar Equipment, Airborne', null, null, 'Radar assemblies and subassemblies designed specifically for use with fire control equipment or guided missiles are excluded from this class and are included in the appropriate classes of group 12 or group 14.', '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.2', 'Detection & Coherent Radiation Eq'),
  ('5845', 'UNDERWATER SOUND EQUIPMENT', '1978-10-15', null, 'Underwater Sound Equipment', 'Sonar Equipment; Underwater Listening Equipment; Sonobuoys; Sonobuoy Launchers; Fathometers; Sonar Equipment.', null, 'This class excludes items specifically designed for fire control sonar systems.', '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.2', 'Detection & Coherent Radiation Eq'),
  ('5850', 'VISIBLE AND INVISIBLE LIGHT COMMUNICATION EQUIPMENT', '2022-04-02', null, 'Visible and Invisible Light Communication Equipment', 'Heliographs.', null, 'This class includes only communication types of infrared equipment. Excluded from this class are infrared assemblies, subassemblies, and components designed specifically for use in fire control systems, guided missile systems, test and maintenance specialized equipment, night vision equipment, and other noncommunication types of equipment.', '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.2', 'Detection & Coherent Radiation Eq'),
  ('5855', 'NIGHT VISION EQUIPMENT, EMITTED AND REFLECTED RADIATION', '2011-10-01', null, 'Night Vision Equipment, Emitted and Reflected Radiation', 'Sighting and Observation Devices; Target Detectors, Locators, Remote Viewing Systems utilizing heat radiation emitted from object(s), associated Radiation Sources, Image Converters and Image Intensifiers, Optical Cells and other components designed for Night Vision Equipment. Holders and Lens used with Infrared Equipment are also included in this FSC.', 'Optical sighting devices which incorporate both day and night viewing characteristics within an integral unit for fire control purposes, nonnight vision type items designed for use with guided missiles, communications, or laboratory equipment, and Optical Elements, such, as Lens, Prisms, Windows.', 'This class includes image forming devices and associated aids, their subassemblies and components, utilizing passive and/or active techniques for detection, observation, and identification of terrain and objects at night, while maintaining concealment afforded by darkness. Includes items having multiapplication for purposes of fire control, and/or night observation, and/or detection. Excluded from this class are items for which more specific classifications are suitable as prescribed by the structure and indexes of the FSC.', '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.4', 'Night Vision Eq'),
  ('5860', 'STIMULATED COHERENT RADIATION DEVICES, COMPONENTS, AND ACCESSORIES', '2011-10-01', null, 'Stimulated Coherent Radiation Devices, Components, and Accessories', null, null, 'This class includes, and is restricted to, devices the operation of which is based on principles involving the stimulated emission of radiation, and to associated components and accessories directly related to stimulated coherent radiation techniques. The methods for producing the radiation are those obtained by LASER (Light Amplification by Stimulated Emission of Radiation) and by MASER (Microwave and/or Molecular Amplification by Stimulated Emission of Radiation) techniques. Only those items specifically designed for stimulated coherent radiation applications, and having no other application, are to be included in this class. Assemblies or major systems containing such devices are excluded from this class.', '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.2', 'Detection & Coherent Radiation Eq'),
  ('5865', 'ELECTRONIC COUNTERMEASURES, COUNTER-COUNTERMEASURES AND QUICK REACTION CAPABILITY EQUIPMENT', '2011-10-01', null, 'Electronic Countermeasures, Counter-Countermeasures and Quick Reaction Capability Equipment', 'Electronic Countermeasures, Electronic Counter-Countermeasures, Electronic Support Measures, and Quick Reaction Capability Equipment and components specially designed therefor which are not classifiable elsewhere in the FSC structure. Excluded from this class are nonelectronic items which are properly classified in more specific classes in accordance with the FSC structure and indexes.', null, 'This class includes, and is restricted to, passive and active electronic equipment, systems, and subsystems designed to prevent or reduce an enemy''s effective use of radiated electromagnetic energy or designed to insure our own effective use of radiated electromagnetic energy.', '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.2', 'Detection & Coherent Radiation Eq'),
  ('5895', 'MISCELLANEOUS COMMUNICATION EQUIPMENT', '2022-04-02', null, 'Miscellaneous Communication Equipment', 'Modems.', 'Electronic Countermeasures Equipment.', 'This class includes miscellaneous communication equipment that is not classified in more specific classes. (See the NOTE for FSG 58.)', '58 - COMM/DETECT/COHERENT RADIATION', null, '13.0', 'Electronic & Communication Equipment', '13.2', 'Detection & Coherent Radiation Eq'),
  ('59', 'ELECTRICAL/ELECTRONIC EQPT COMPNTS', '1979-10-01', null, null, null, null, 'Mounting hardware, included in classes of this group, includes such specially designed items as brackets, holders, retainers, etc. Excluded from classes in this group are such hardware items as screws (FSC 5305), bolts (FSC 5306), studs (FSC 5307), washers (FSC 5310), rivets (FSC 5320), and other common items indexed to specific classes, other than in group 59. The FSC indexes and structure will govern the classification of items used on or with mounting hardware cited above.', null, null, null, null, null, null),
  ('5905', 'RESISTORS', '1978-10-15', null, 'Resistors', 'Varistors; Resistive Ballast Tubes; Rheostats; Resistor Networks; Resistor Mounting Hardware; Thermistors.', 'Resistance Wire.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5910', 'CAPACITORS', '1978-10-15', null, 'Capacitors', 'Interference Filter Capacitors; Capacitor Mounting Hardware.', 'Semiconductor Devices and Associated Hardware.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5915', 'FILTERS AND NETWORKS', '1978-10-15', null, 'Filters and Networks', null, null, 'This class includes those filters and networks which consist of a combination of resistors, capacitors, or coils, but not a combination of resistors only (classified in 5905). capacitors only (classified in 5910), or coils only (classified in 5950).', '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5920', 'FUSES, ARRESTORS, ABSORBERS, AND PROTECTORS', '2011-10-01', null, 'Fuses, Arresters, Absorbers, and Protectors', 'Fuseholders; Fuse Boxes; Fuse Posts; Fuse Links; Fuse blocks; Current Limiters. Corona Balls, Electrostatic Dischargers.', 'Circuit Breakers.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5925', 'CIRCUIT BREAKERS', '1978-10-15', null, 'Circuit Breakers', 'Circuit Breakers and Cutouts.', 'Relays.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5930', 'SWITCHES', '1978-10-15', null, 'Switches', 'Rotary, Knife, Toggle. Push Button, Mercury, Thermostatic, and Differential Pressure Switches.', 'Switchgear.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5935', 'CONNECTORS, ELECTRICAL', '1978-10-15', null, 'Connectors, Electrical', 'Plugs; Jacks; Receptacles; Electronic Component Sockets and Associated Accessories.', 'Interconnectors, Fiber Optic.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5940', 'LUGS, TERMINALS, AND TERMINAL STRIPS', '2011-10-01', null, 'Lugs, Terminals, and Terminal Strips', 'Binding Posts; Battery Clips; Stud Terminals; Test Clips.', 'Caps, Electrical; Clips Electrical; and Contacts, Electrical.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5945', 'RELAYS AND SOLENOIDS', '1978-10-15', null, 'Relays and Solenoids', 'Electromagnetic Actuators.', 'Contactors.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5950', 'COILS AND TRANSFORMERS', '1978-10-15', null, 'Coils and Transformers', 'Coils, except ignition and magneto; coil assemblies; magnetic amplifiers; reactors; transformers.', null, null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5955', 'OSCILLATORS AND PIEZOELECTRIC CRYSTALS', '2011-10-01', null, 'Oscillators and Piezoelectric Crystals', 'Crystal Units, Processed Unmounted Crystals, Crystal Controlled Oscillators and Noncrystal Controlled Oscillators.', 'Crystal Controlled Oscillators and Noncrystal Controlled Oscillators which meet the definition of the term. "electronic module" as defined for FSC 5963 and Microcircuits.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5960', 'ELECTRON TUBES AND ASSOCIATED HARDWARE', '2011-10-01', null, 'Electron Tubes and Associated Hardware', 'Rectifying Tubes; Photoelectric Tubes; Electron Vibrator Tubes.', 'Transistors; Tube Sockets; X-ray Tubes; Semiconductor Devices and Associated Hardware.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5961', 'SEMICONDUCTOR DEVICES AND ASSOCIATED HARDWARE', '2011-10-01', null, 'Semiconductor Devices and Associated Hardware', 'Semiconductor Assemblies; Semiconductor Diodes; Semiconductor Rectifiers, Semiconductor Thyristors; Transistors; Unitized Semiconductors; Associated Hardware except Sockets.', 'Microcircuits; Optoelectronic Devices and Associated Hardware.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5962', 'MICROCIRCUITS, ELECTRONIC', '1978-10-15', null, 'Microcircuits, Electronic', 'Integrated Circuit Devices; Integrated Circuit Modules; Integrated Electronic Devices: Hybrid, Magnetic, Molecular, Opto-Electronic, and Thin Film.', 'Single Circuit Elements such as Capacitors; Resistors; Diodes and Transistors; Printed Circuit Boards and- Circuit Card Assemblies; and Filters and Networks.', '(1) A microcircuit is defined as follows: A small circuit having a high equivalent circuit element density, which is considered as a single part composed of interconnected elements placed and/or formed on or within a single substrate to perform an electronic circuit function. The elements may be on or within a semiconductor material substrate; may consist of conductive film(s) formed on an insulating substrate; or may be a combination of one or both of these types with discrete elements. (2) The term "microcircuit", as applied to circuit devices included in this class, is delimited to exclude items consisting solely of interconnected "microcomponents" (discrete miniaturized components). Also excluded are items fabricated in the form of monolithic thick-film or thin-film structures that in themselves are not functional electronic circuits (e.g., capacitors, resistors, transistors, or "arrays" thereof).', '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5963', 'ELECTRONIC MODULES', '1980-03-15', null, 'Electronic Modules', 'Microcircuits; Electronic Test Equipment Plug-In Units.', 'Microcircuits; Electronic Test Equipment Plug-In Units.', 'The term "electronic module" as used in this class designates an electronic component designed for use in various equipment or end item applications, and capable of controlling voltage and/or current to produce gain, oscillation, switching or similar integral electronic functions. It consists of a collection of miniaturized electronic parts and/or elements in a single replaceable package with plug-in mounting which will also complete the required electrical connections. It is not normally subject to disassembly as distinguished from such items as CIRCUIT CARD ASSEMBLY and ELECTRONIC COMPONENTS ASSEMBLY. These modules conform to industry or government specifications/standards that define all physical dimensions and electrical parameters required to promote commonality and ensure proper operational performance.', '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5965', 'HEADSETS, HANDSETS, MICROPHONES AND SPEAKERS', '2011-10-01', null, 'Headsets, Handsets, Microphones and Speakers', null, null, null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5970', 'ELECTRICAL INSULATORS AND INSULATING MATERIALS', '2011-10-01', null, 'Electrical Insulators and Insulating Materials', 'Tube, Knob, Cleat, Strain, and Standoff Insulators; Feed Thru Insulators; Bead Insulators; Varnish Cambrie Tape; Friction Tape.', null, null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5975', 'ELECTRICAL HARDWARE AND SUPPLIES', '1978-10-15', null, 'Electrical Hardware and Supplies', 'Conduit; Raceways; Face Plates; Condulets; Outlet and Junction Boxes; Pole Line Hardware, not elsewhere classifiable.', null, null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5977', 'ELECTRICAL CONTACT BRUSHES AND ELECTRODES', '2011-10-01', null, 'Electrical Contact Brushes and Electrodes', 'Brushes for electrical rotating equipment; Carbon Stock for Brushes; Brush Arm and Holders; Lighting Electrodes.', 'Anodes; Cathodes, Welding Electrodes.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5980', 'OPTOELECTRONIC DEVICES AND ASSOCIATED HARDWARE', '2011-10-01', null, 'Optoelectronic Devices and Associated Hardware', 'Optoelectronic devices and assemblies which display numeric, alphanumeric, symbolic, or graphic information emitters, and nondisplay optoelectronic devices, such as couplers, detectors, and switches which perform an active function in an electronic system.', 'Electric lighting fixtures, lamps, and associated hardware.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5985', 'ANTENNAS, WAVEGUIDES, AND RELATED EQUIPMENT', '2011-10-01', null, 'Antennas, Waveguide, and Related Equipment', 'Aerials; Mast; Tower Equipment; Attenuators; Couplers; Transmission Lines.', 'Tower Structures.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5990', 'SYNCHROS AND RESOLVERS', '1978-10-15', null, 'Synchros and Resolvers', 'Synchro Systems; Servo Mechanisms.', 'Synchro Systems; Servo Mechanisms.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5995', 'CABLE, CORD, AND WIRE ASSEMBLIES: COMMUNICATION EQUIPMENT', '2011-10-01', null, 'Cable, Cord, and Wire Assemblies: Communication Equipment', 'Cable Assemblies, Fiber Optic', 'Cable Assemblies, Fiber Optic', 'This class includes only those types of cable, cord, and wire assemblies and sets (and wiring harnesses) used on or with equipment and components covered by groups 58 and 59. Cable, cord, wire assemblies, and sets (wiring harnesses) used on or with equipment classified in FSC groups other than groups 58 or 59 are classified in FSC class 6150 if multiapplication, or classified with the next higher classifiable assembly if specially designed.', '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5996', 'AMPLIFIERS', '1991-10-01', null, 'Amplifiers', 'Audio Amplifiers, Complementary Amplifiers, Amplifiers, Operational Amplifiers, Power Amplifiers, Radio Frequency Amplifiers, Signal Amplifiers, and Video Amplifiers.', 'Multi-functional items such as Amplifier-Detector, Amplifier-Mixer and microcircuit devices.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5998', 'ELECTRICAL AND ELECTRONIC ASSEMBLIES, BOARDS, CARDS, AND ASSOCIATED HARDWARE', '2011-10-01', null, 'Electrical and Electronic Assemblies; Boards, Cards, and Associated Hardware', 'circuit card and electronic component assemblies which can be identified to a more definitive Approved Item Name.', 'circuit card and electronic component assemblies which can be identified to a more definitive Approved Item Name.', null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('5999', 'MISCELLANEOUS ELECTRICAL AND ELECTRONIC COMPONENTS', '2011-10-01', null, 'Miscellaneous Electrical and Electronic Components', 'Permanent Magnets and Magnetostriction Elements; Caps, Clips, and Contacts, Electrical.', null, null, '59 - ELECTRICAL/ELECTRONIC EQPT COMPNTS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6010', 'FIBER OPTIC CONDUCTORS', '2022-04-02', null, 'Fiber Optic Conductors', null, null, 'Included in this class are bulk discrete fibers.', '60 - FIBER OPTIC', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6015', 'FIBER OPTIC CABLES', '2022-04-02', null, 'Fiber Optic Cables', null, null, 'Included in this class are one or more discrete fiber optic conductors with a common protective covering in bulk form. May include electrical conductors/cables and/or reinforcing material.', '60 - FIBER OPTIC', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6020', 'FIBER OPTIC CABLE ASSEMBLIES AND HARNESSES', '2022-04-02', null, 'Fiber Optic Cable Assemblies and Harnesses', null, null, 'Included in this class are items used for communication and/or data transmission having one or more fiber optic conductors/cables with processed end(s) or terminated in fitting(s). Excluded from this class are items used for illumination and/or image transmission.', '60 - FIBER OPTIC', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6021', 'FIBER OPTIC SWITCHES', '2022-04-02', null, 'Fiber Optic Switches', null, null, 'Included in this class are switches used for line selection in fiber optic systems.', '60 - FIBER OPTIC', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6030', 'FIBER OPTIC DEVICES', '2022-04-02', null, 'Fiber Optic Devices', null, null, 'Included in this class are such items as transmitters, receivers, mutliplexers, demultiplexers, modulators, demodulators, repeaters, attenuators, filters, integrated optical circuits, and the like, used in fiber optic systems.', '60 - FIBER OPTIC', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6032', 'FIBER OPTIC LIGHT SOURCES AND PHOTO DETECTORS', '2022-04-02', null, 'Fiber Optic Light Sources and Photo Detectors', null, null, 'Included in this class are light emitting and laser diodes and photo detectors used in fiber optic systems.', '60 - FIBER OPTIC', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6035', 'FIBER OPTIC LIGHT TRANSFER AND IMAGE TRANSFER DEVICES', '2022-04-02', null, 'Fiber Optic Light Transfer and Image Transfer Devices', null, null, 'Included in this class are fiber optic devices used for illumination and/or image transmission. Excluded from this class are items used for communication and/or data transmission.', '60 - FIBER OPTIC', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6060', 'FIBER OPTIC INTERCONNECTORS', '2022-04-02', null, 'Fiber Optic Interconnectors', 'Electrical connectors', 'Electrical connectors', 'Included in this class are all types of fiber optic terminations, such as connectors, dividers, couplers, rotary and nonrotary joints, splitters, mixers and splicers and the like.', '60 - FIBER OPTIC', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6070', 'FIBER OPTIC ACCESSORIES AND SUPPLIES', '2022-04-02', null, 'Fiber Optic Accessories and Supplies', null, null, 'Included in this class are mode stripping materials, index matching materials and other related supplies. Excluded from this class are hardware and supplies common to both electrical and fiber optic applications which are classifiable in FSC 5975.', '60 - FIBER OPTIC', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6080', 'FIBER OPTIC KITS AND SETS', '2022-04-02', null, 'Fiber Optic Kits and Sets', 'tool kits and sets which are classifiable in FSC 5180; test set/ instruments classifiable in FSG 66; and end item sets/ equipment utilizing fiber optic components which are classifiable in the applicable equipment FSC.', 'tool kits and sets which are classifiable in FSC 5180; test set/ instruments classifiable in FSG 66; and end item sets/ equipment utilizing fiber optic components which are classifiable in the applicable equipment FSC.', 'Includes kits and sets which consists of fiber optic components only; fiber optic components and related parts; fiber optic components and related tools; or fiber optic components, related parts and related tools.', '60 - FIBER OPTIC', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6099', 'MISCELLANEOUS FIBER OPTIC COMPONENTS', '2022-04-02', null, 'Miscellaneous Fiber Optic Components', null, null, 'Included in this, class are fiber optic items which are not classifiable in a more specific class. (See the "Note" for FSG 60.)', '60 - FIBER OPTIC', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('61', 'ELECTRIC WIRE, POWER DISTRIB EQPT', '1979-10-01', null, null, null, null, null, null, null, null, null, null, null),
  ('6105', 'MOTORS, ELECTRICAL', '1978-10-15', null, 'Motors, Electrical', 'Starting Motors for Engines', 'Starting Motors for Engines', null, '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6110', 'ELECTRICAL CONTROL EQUIPMENT', '1978-10-15', null, 'Electrical Control Equipment', 'Contactors: Motor Controllers; Power Servomechanisms; Switchgear; Voltage Regulators.', 'Automatic Pilot Mechanisms; Relays; Resistors.', null, '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6115', 'GENERATORS AND GENERATOR SETS, ELECTRICAL', '2011-10-01', null, 'Generators and Generator Sets, Electrical', 'Engine, Turbine, Wind, and Hand Driven Generator Sets and Auxiliary Aircraft Generators.', 'Motor-Converters: Motor-Generator Sets; Engine Generators; Engine Accessory Generators.', null, '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6116', 'FUEL CELL POWER UNITS, COMPONENTS, AND ACCESSORIES', '2011-10-01', null, 'Fuel Cell Power Units, Components, and Accessories', 'Complete Functioning Fuel Cell Power Units; Fuel Cells: Fuel Cell Assemblies or Modules; Fuel Cell Reactant Chambers; Fuel Feed Mechanism; Electrolyte Heaters; Heat Exchangers; and other internal components peculiar to, and used exclusively on or with, Fuel Cell Power Units classified in this class.', 'Primary Batteries (FSC 6135); Secondary Batteries (FSC 6140); Generators and Generating Sets (FSC 6115); and items for which more suitable classes are specifically prescribed by the indexes and structure of the FSC.', 'This class includes items that are designed to produce an electromotive force directly from an oxidation-reduction type of chemical reaction. A complete power unit must include tanks, pumps, and associated control equipment, and requires a continuous, uninterrupted supply of liquid or gaseous fuel and oxidizers.', '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6117', 'SOLAR ELECTRIC POWER SYSTEMS', '1991-07-15', null, 'Solar Electric Power Systems', null, null, 'This class includes items which are designed for the direct conversion of solar energy into electrical power.', '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '4.0', 'Facilities & Construction', '4.3', 'Facility Related Materials'),
  ('6120', 'TRANSFORMERS: DISTRIBUTION AND POWER STATION', '2011-10-01', null, 'Transformers: Distribution and Power Station', 'Potential and Current Transformers.', 'Potential and Current Transformers.', 'This class includes transformers with a kilovolt-ampere rating above 1 kva.', '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '4.0', 'Facilities & Construction', '4.3', 'Facility Related Materials'),
  ('6125', 'CONVERTERS, ELECTRICAL, ROTATING', '1978-10-15', null, 'Converters, Electrical, Rotating', 'Complete Battery Charging Equipment, Rotating; Dynamotors; Motor Converters; Motor-Generator Sets; Phase Converters; Rotating Equipment; Synchronous Converters.', 'Nonrotating Equipment.', 'This class includes devices employing mechanical rotation of changing electrical energy from one form to another (i.e., AC to AC, DC to DC, AC to DC, DC to AC). Excluded from this class are electrical generators and generator sets (FSC 6115).', '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6130', 'CONVERTERS, ELECTRICAL, NONROTATING', '1978-10-15', null, 'Converters, Electrical, Nonrotating', 'Complete Battery Charging Equipment, Nonrotating; Power Sup-plies, Multiapplication.', 'Rectifying Tubes; (FSC 5960); Rectifying Crystals (FSC 5961); Rotating Equipment (FSC 6125); Transformers (FSC 5950); and Semiconductor Devices and Associated Hardware (FSC 5961).', 'This class includes devices employing a means other than mechanical rotation for changing electrical energy from one form to another (i.e., AC to AC, DC to DC, AC to DC, and DC to AC).', '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6135', 'BATTERIES, NONRECHARGEABLE', '1978-10-15', null, 'Batteries, Nonrechargeable', 'Cells and Dry Batteries; Nuclear Batteries.', null, null, '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6140', 'BATTERIES, RECHARGEABLE', '1978-10-15', null, 'Batteries, Rechargeable', 'Rechargeable Cells and Batteries.', null, null, '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6145', 'WIRE AND CABLE, ELECTRICAL', '1978-10-15', null, 'Wire and Cable, Electrical', 'Insulated and Noninsulated, Wire and Cable, such as, Antenna Wire, Coaxial Cable, Fuse and Resistance Wire, and Magnet Wire.', 'Radio Frequency Transmission Line (FSC 5985); Fiber Optic Cable (FSC 6015); Communication Cable Assemblies; (FSC 5995); Distribution and Power Transmission Cable Assemblies (FSC 6150).', 'This class includes only bulk electrical wire and cable. Excluded from this class are electrical wire and cable items of definite length either with processed ends, or terminated in fittings', '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6150', 'MISCELLANEOUS ELECTRIC POWER AND DISTRIBUTION EQUIPMENT', '2011-10-01', null, 'Miscellaneous Electric Power and Distribution Equipment', 'Appliance and Extension Cords; Electric Power and Distribution Cable with Attachments, Multiapplication; Common Components of Electrical Rotating Equipment, such as End Bells and Frames.', null, null, '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6160', 'MISCELLANEOUS BATTERY RETAINING FIXTURES, LINERS AND ANCILLARY ITEMS', '2011-10-01', null, 'Miscellaneous Battery Retaining Fixtures and Liners', 'Battery Boxes, Covers, Liners, Racks, Retainers, and Trays.', null, null, '61 - ELECTRIC WIRE, POWER DISTRIB EQPT', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('62', 'LIGHTING FIXTURES, LAMPS', '1979-10-01', null, null, null, null, null, null, null, null, null, null, null),
  ('6210', 'INDOOR AND OUTDOOR ELECTRIC LIGHTING FIXTURES', '2011-10-01', null, 'Indoor and Outdoor Electric Lighting Fixtures', 'Airport, Railroad Platform, Stadium, and Street Lighting Fixtures.', 'Nonelectrical Outdoor Fixtures; Signal Fixtures; Nonelectrical Indoor Fixtures.', null, '62 - LIGHTING FIXTURES, LAMPS', null, '4.0', 'Facilities & Construction', '4.3', 'Facility Related Materials'),
  ('6220', 'ELECTRIC VEHICULAR LIGHTS AND FIXTURES', '2011-10-01', null, 'Electric Vehicular Lights and Fixtures', 'Automotive, Marine, Railroad, and Aircraft Lights and Fixtures.', 'Nonelectrical Vehicular Fixtures.', null, '62 - LIGHTING FIXTURES, LAMPS', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6230', 'ELECTRIC PORTABLE AND HAND LIGHTING EQUIPMENT', '2011-10-01', null, 'Electric Portable and Hand Lighting Equipment', 'Floodlights; Searchlights; Extension Lights.', 'Nonelectrical Portable and Hand Lighting Equipment; Signal and Alarm Equipment.', null, '62 - LIGHTING FIXTURES, LAMPS', null, '4.0', 'Facilities & Construction', '4.3', 'Facility Related Materials'),
  ('6240', 'ELECTRIC LAMPS', '1978-10-15', null, 'Electric Lamps', 'Fluorescent Lamps; Incandescent Lamps, Large and Miniature; Mercury Lamps; Sodium Lamps.', null, null, '62 - LIGHTING FIXTURES, LAMPS', null, '4.0', 'Facilities & Construction', '4.3', 'Facility Related Materials'),
  ('6250', 'BALLASTS, LAMPHOLDERS, AND STARTERS', '1978-12-15', null, 'Ballasts, Lampholders, and Starters', null, null, null, '62 - LIGHTING FIXTURES, LAMPS', null, '4.0', 'Facilities & Construction', '4.3', 'Facility Related Materials'),
  ('6260', 'NONELECTRICAL LIGHTING FIXTURES', '1978-10-15', null, 'Nonelectrical Lighting Fixtures', 'Lanterns, Nonelectrical; Hand and Portable Carbide Lamps; Candles.', null, null, '62 - LIGHTING FIXTURES, LAMPS', null, '4.0', 'Facilities & Construction', '4.3', 'Facility Related Materials'),
