  ('6320', 'SHIPBOARD ALARM AND SIGNAL SYSTEMS', '2011-10-01', null, 'Shipboard Alarm and Signals Systems', null, null, null, '63 - ALARM, SIGNAL, SECURITY DETECTION', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6330', 'RAILROAD SIGNAL AND WARNING DEVICES', '1978-12-15', null, 'Railroad Signal and Warning Devices', 'Railroad Gates; Flasher Lights; Block Signals.', 'Semaphore Flag Signals.', null, '63 - ALARM, SIGNAL, SECURITY DETECTION', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6340', 'AIRCRAFT ALARM AND SIGNAL SYSTEMS', '1978-10-15', null, 'Aircraft Alarm and Signal Systems', 'Oxygen Pressure Signals and Warning Devices; such as Air Pressure Warning Signals, Aircraft Crew Warning Signals, Altitude Warning Signals, Alarm Controls, Audible Landing Gear Alarms.', 'Aircraft Engine Oil and Fuel Warning Devices.', null, '63 - ALARM, SIGNAL, SECURITY DETECTION', null, '13.0', 'Electronic & Communication Equipment', '13.3', 'Electrical & Electronics Equipment'),
  ('6350', 'MISCELLANEOUS ALARM, SIGNAL, AND SECURITY DETECTION SYSTEMS', '2011-10-01', null, 'Miscellaneous Alarm, Signal, and Security Detection Systems', 'Anti-intrusion Alarm Systems; Foghorns; Gongs; Chimes; Bells; Burglar Alarm Systems; Fire Alarms; Police Alarm Systems; Sounding Devices; Manual Gas Alarms; Landing Wands.', 'Loran; Radar; Sonar; Engine Oil and Fuel Warning Devices; Aircraft Oxygen Warning Devices.', null, '63 - ALARM, SIGNAL, SECURITY DETECTION', null, '3.0', 'Security and Protection', '3.2', 'Security Systems'),
  ('65', 'MEDICAL/DENTAL/VETERINARY EQPT/SUPP', '1979-10-01', null, null, null, null, null, null, null, null, null, null, null),
  ('6505', 'DRUGS AND BIOLOGICALS', '1978-10-15', null, 'Drugs and Biologicals', 'All drugs, medicinal grade chemicals, and biologicals subject to the Federal Food, Drug and Cosmetic Act, Department of Agriculture (Veterinary Drugs and Biologicals), listed in the Monograph Section of the U.S. Pharmacopeia or the National Formulary or covered by the United States Adopted Names (USAN).', 'Medicated cosmetics and toiletries classifiable in FSC 6508 and in vitro diagnostic substances and reagents classifiable in FSC 6550.', null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.1', 'Drugs and Pharmaceutical Products'),
  ('6506', 'BLOOD AND BLOOD PRODUCTS', '2024-04-30', null, 'BLOOD AND BLOOD PRODUCTS', 'Blood and Blood Products', 'Other laboratory/reference lab testing (Q301), medical laboratory professionals (Q515)', null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, null, null, null, null),
  ('6508', 'MEDICATED COSMETICS AND TOILETRIES', '1978-11-15', null, 'Medicated Cosmetics and Toiletries', 'medicated cosmetics and toiletries that have been determined to be drugs in accordance with the Federal Food, Drug, and Cosmetic Act.', 'nonmedicated cosmetics and toiletries which are classifiable in group 85.', null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6509', 'DRUGS AND BIOLOGICALS, VETERINARY USE', '2005-05-01', null, 'Drugs and Biologicals, Veterinary Use.', 'All Drugs, medicinal grade chemical, and Biologicals subject to the provisions of the Department of Agriculture (Veterinary Drugs and Biologicals) specifically formulated for Veterinary use. Other Nations may apply their own legal documents.', 'Drugs and Biologicals specifically formulated for Human use classifiable in FSC 6505.', null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6510', 'SURGICAL DRESSING MATERIALS', '1978-10-15', null, 'Surgical Dressing Materials', 'Bandages, Compresses, Dressings, Gauze, Pads, Sponges, and impregnated surgical dressing materials.', null, null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6515', 'MEDICAL AND SURGICAL INSTRUMENTS, EQUIPMENT, AND SUPPLIES', '2011-10-01', null, 'Medical and Surgical Instruments, Equipment, and Supplies', 'Anesthesia Apparatus; Blood Transfusion Apparatus; Oxygen Therapy Apparatus; Respirators; Orthopedic Supplies; Arch Supports; Clinical Thermometers; Sutures; Hearing Aids; Veterinary Equipment, Endoscopes, Fiber Optic.', 'Ophthalmic Instruments, Equipment, and Supplies; Non-Medical Endoscopes.', null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6520', 'DENTAL INSTRUMENTS, EQUIPMENT, AND SUPPLIES', '2011-10-01', null, 'Dental Instruments, Equipment, and Supplies', 'Dental Engines; Dental Laboratory Equipment; Operating Chairs; Orthodontic Appliances; Teeth; Dental Metals; Dental Abrasives; Dental Laboratory Furniture.', null, null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6525', 'IMAGING EQUIPMENT AND SUPPLIES: MEDICAL, DENTAL, VETERINARY', '2011-10-01', null, 'X-Ray Equipment and Supplies: Medical, Dental, Veterinary', 'Medical X-Ray Film; Medical X-Ray Film Viewing Equipment; Medical X-Ray Film Processing and Finishing Equipment and Supplies; X-Ray Tubes.', 'Industrial X-Ray Equipment.', null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6530', 'HOSPITAL FURNITURE, EQUIPMENT, UTENSILS, AND SUPPLIES', '2011-10-01', null, 'Hospital Furniture, Equipment, Utensils, and Supplies', 'Orthopedic Equipment; Operating Lights; Physiotherapy Equipment; Sterilizers; Wheel Chairs; Litters; Hospital Beds; Restraint Equipment.', null, null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6532', 'HOSPITAL AND SURGICAL CLOTHING AND RELATED SPECIAL PURPOSE ITEMS', '2011-10-01', null, 'Hospital and Surgical Clothing and Related Special Purpose Items', 'Only those clothing items which are required exclusively for use in hospital operations, or in medical or dental facilities, which have no functional counterpart elsewhere in Federal Organizations Participating in the Federal Catalog System.', 'General purpose items of clothing and fabricated textile material.', null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6540', 'OPHTHALMIC INSTRUMENTS, EQUIPMENT, AND SUPPLIES', '2011-10-01', null, 'Ophthalmic Instruments, Equipment, and Supplies', 'Ophthalmic Lens Cutting and Grinding Machine; Ophthalmic Lenses and Lens Blanks; Spectacle Frames; Ophthalmological and Optometric Instruments, Equipment, and Supplies', 'Optical Lens Cutting and Grinding Machines: Ophthalmoscope and Otoscope Set; Surgical Instruments and Supplies that can be used by other medical disciplines; i.e., sutures, eye pads, eye shields, eye bath, and the like.', null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6545', 'REPLENISHABLE FIELD MEDICAL SETS, KITS, AND OUTFITS', '2011-10-01', null, 'Replenishable Field Medical Sets, Kits, and Outfits', 'Sets and kits which can be logically classified in another FSC Class in Group 65, such as Insect Sting Kit; Otoscope and Ophthalmoscope Set; In Vitro Diagnostic Test Kits; and the like.', 'Sets and kits which can be logically classified in another FSC Class in Group 65, such as Insect Sting Kit; Otoscope and Ophthalmoscope Set; In Vitro Diagnostic Test Kits; and the like.', null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6550', 'IN VITRO DIAGNOSTIC SUBSTANCES, REAGENTS, TEST KITS AND SETS', '2011-10-01', null, 'In Vitro Diagnostic Substances, Reagents, Test Kits and Sets', 'In vitro diagnostic aids, such as test tablets, test slides, test strips, test cards, test papers, test solutions, reagents; sets and kits designated for in vitro qualitative and quantitative tests on specimens, such as blood, urine, feces, and the like, for the purposes of aiding in the medical diagnosis of disease, determining body organ dysfunction, or other abnormal conditions.', 'in vitro diagnostic substances classifiable in FSC 6505.', null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6555', 'HUMAN TISSUE AND CADAVERS', '2024-04-30', null, null, 'Human tissues, animal tissues and full cadavers/cadaver body parts', 'Other surgical implants (non-human) (6515 Medical and Surgical Instruments and Supplies), laboratory testing services (Q301), training/ training instruction on cadavers or live tissue handling (U006 Education/Training- Vocational/Technical)', null, '65 - MEDICAL/DENTAL/VETERINARY EQPT/SUPP', null, null, null, null, null),
  ('66', 'INSTRUMENTS AND LABORATORY EQPT', '1979-10-01', null, null, null, null, 'Infrared assemblies (including sub-assemblies and components) designed specifically for use as or with instruments and laboratory equipment are included in the classes of this group. Also included are computers (including computer assemblies, computer systems and components) designed specifically for use with instruments and laboratory equipment', null, null, null, null, null, null)
INSERT INTO v2.psc_codes (code, name, start_date, end_date, full_name, includes, excludes, notes, parent_code, category, level_1_code, level_1_name, level_2_code, level_2_name) VALUES
  ('6605', 'NAVIGATIONAL INSTRUMENTS', '1978-10-15', null, 'Navigational Instruments', 'Azimuths; Sextants; Octants; Compasses; Plotting Boards; Underwater Log Equipment; Air Position Indicators; Drift Meters.', null, null, '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
  ('6610', 'FLIGHT INSTRUMENTS', '1978-10-15', null, 'Flight Instruments', 'Air Speed Indicators; Rate of Climb Indicators; Bank and Turn-Indicators; Pilot Tubes, Gyro Horizon Indicators; Attitude Gyro Indicators.', 'Navigational Instruments (FSC 6605).', null, '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
  ('6615', 'AUTOMATIC PILOT MECHANISMS AND AIRBORNE GYRO COMPONENTS', '2011-10-01', null, 'Automatic Pilot Mechanisms and Airborne Gyro Components', 'Automatic Pilot Regulators; Directional, Vertical, Bank and Turn, and Hydraulic Surface Gyro Controls; Airborne and Shipborne Automatic Pilot Mechanisms; Helicopter Automatic Stabilization Equipment.', 'Automatic Pilot Training Devices (FSC 6930); Automatic Pilot Mechanisms, Guided Missile (FSC 1420).', 'Included in this class are gyro components of guided missiles. Excluded are complete gyro mechanisms and nonairborne gyro components, both of which are classified in the same classes as their next higher assemblies.', '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
  ('6620', 'ENGINE INSTRUMENTS', '1978-10-15', null, 'Engine Instruments', 'All Engine Instruments, including Aircraft, Marine, and Vehicular; Fuel Pressure Gages; Manifold Pressure Gages; Oil Pressure Gages; Fuel Mixture Indicators; Engine Oil and Fuel Warning Devices.', null, 'Instruments designed for use on both engines and other than engines are not included in this class and should be classified in the appropriate instruments class of group 66.', '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
  ('6625', 'ELECTRICAL AND ELECTRONIC PROPERTIES MEASURING AND TESTING INSTRUMENTS', '2011-10-01', null, 'Electrical and Electronic Properties Measuring and Testing Instruments', 'Test Leads and Test Lead Attachments; Test instruments designed for communication equipment; Test instruments designed for use with electronic equipment classified in two or more FSC groups.', 'Radiac Equipment.', 'This class includes all "basic" types of electrical and electronic test instruments, such as ammeters, voltmeters, ohmmeters, multimeters, and similar instruments, even if specially designed. Excluded from this class by the modifier "except specially designed" are test instruments, other than "basic" instruments, which are specially designed for use with atomic ordnance, fire control, guided missile, motor vehicle, aircraft, or photographic equipment. Such specially designed test instruments are to be classified in other classes in the Federal Supply Classification. This class includes communications test equipment, infrared test equipment designed for communication, and night vision maintenance and test specialized equipment.', '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
  ('6630', 'CHEMICAL ANALYSIS INSTRUMENTS', '1978-10-15', null, 'Chemical Analysis Instruments', 'Acidity (pH) Meters; Gas Analyzers; Alkalinity Measuring Instruments; Colorimeters.', 'Gas Detecting Equipment; Manual Gas Alarms; Chemicals; In Vitro Diagnostic Substances and Reagents.', null, '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
  ('6632', 'ANALYSIS INSTRUMENTS, MEDICAL LABORATORY USE', '2021-10-30', null, 'Analysis Instruments, Medical Laboratory Use', 'All analysers and instrumentation used in a medical/clinical setting for the purpose of aiding in the medical diagnosis of disease.  Types of instrumentation include immunochemistry, clinical chemistry, coagulation, hematology, clinical microbiology, urinalysis, differential counters, histology, cytology equipment, and point of care analysers. Examples include instrumentation performing the following analysis: blood cell, blood serum, urine, fecal, tissue slide staining, molecular infectious disease, tissue cells, polymerase chain reaction, serum electrophoresis, and DNA.  Related supporting components and parts are also included.', 'Non-medical use instrumentation.  Examples include: gas detecting equipment, manual gas alarms, air quality monitoring equipment, chemicals, in vitro diagnostic substances, reagents, water monitors, water quality instruments, general use meters, stack emission measuring equipment, Ph and ion-selective meters, titrators and titration systems, and all other nonmedical analysis instrumentation. Also excludes general use laboratory equipment and supplies such as beakers, flasks, test tubes, balances, scales.  Note: For clinical laboratory reagents see PSC Code 6550.', null, '66 - INSTRUMENTS AND LABORATORY EQPT', null, '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6635', 'PHYSICAL PROPERTIES TESTING AND INSPECTION', '2011-10-01', null, 'Physical Properties Testing and Inspection', 'Destructive and Nondestructive Inspection Equipment such as Fluorescent Penetrant Inspection Units; Magnetic Inspection Units; Industrial X-Ray Machines; Industrial X-Ray Film; Tensiometers; Material Hardness Testers.', 'General purpose Measuring Tools (FSC 5210) and Precision Measuring Tools and Inspection Gages (FSC 5220).', null, '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
  ('6636', 'ENVIRONMENTAL CHAMBERS AND RELATED EQUIPMENT', '2011-10-01', null, 'Environmental Chambers and Related Equipment', 'Chambers; Wind Tunnels; Enclosures specifically designed to simulate an environmental condition; Weatherometers; Fadeometers; Specially designed equipment and components exclusively related to environmental chambers.', 'General purpose prefabricated buildings, chambers, panels, and components (FSC 5410); Controlled Environmental Conditioning Kits and Sets (FSC 4240); Baths (FSC 4510); Ovens (FSC 7310); Kilns (FSC 3630); Radiosonde Baseline Check Sets (FSC 6660); Divers Recompression Chambers (FSC 4220); Altitude Training Decompression Chambers (FSC 6930); and chambers used as training devices (FSC 6930); Checkout and Test Equipment (FSC 6625); Chemical Analysis Instruments (FSC 6630); Electrical and Electronic Properties Measuring and Testing Instruments (FSC 6625); Meteorological Instruments (FSC 6660).', 'This class includes only those environmental chambers used exclusively to perform controlled tests, under simulated conditions, to determine physical damage and/or changes in operating characteristics for equipment and components such as Humidity, Immersion, Moisture; Altitude; Explosion; Thermal Shock; Sand and Dust; Flammability; Seal. Environmental chambers included in this class provide data regarding service life and behavior of various items equivalent to actual service conditions existing in the field.', '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
  ('6640', 'LABORATORY EQUIPMENT AND SUPPLIES', '1978-10-15', null, 'Laboratory Equipment and Supplies', 'Laboratory Glassware; Laboratory Funnels; Laboratory Furnaces; Glass Beads; Laboratory White Sand; Litmus Paper; Paper Filters; Insect Transfixion Pins; Laboratory Glass Wool; Laboratory Furniture, except Dental Laboratory.', 'Instruments covered by other classes in group 66; Dental Laboratory Equipment; Laboratory Scales and Balances; In Vitro Diagnostic Substances and Reagents.', null, '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
  ('6645', 'TIME MEASURING INSTRUMENTS', '1978-10-15', null, 'Time Measuring Instruments', 'Clocks; Job Recording Devices; Time Recorders; Time Stamps; Watch and Clock Movements; Watches.', null, null, '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
  ('6650', 'OPTICAL INSTRUMENTS, TEST EQUIPMENT, COMPONENTS AND ACCESSORIES', '2011-10-01', null, 'Optical Instruments, Test Equipment, Components and Accessories', 'Binoculars; Magnifiers; Microscopes; Periscopes; Telescopes. Optical Elements, such as Lens, Prisms, Windows; Optical Benches and associated devices; Endoscopes, Fiber Optics (non-medical).', 'Fire Control Instruments, Optical; Surveying Instruments, Optical; Photogrammetric Instruments; Octants and Sextants; Optical Instruments Integrated with Fire Control Equipment; Ophthalmological Instruments; Electronic Fiber Optic Test Equipment; Medical Endoscopes.', null, '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
