  ('6680', 'LIQUID AND GAS FLOW, LIQUID LEVEL, AND MECHANICAL MOTION MEASURING INSTRUMENTS', '2011-10-01', null, 'Liquid and Gas Flow, Liquid Level, and Mechanical Motion Measuring Instruments', 'Liquid Level Float Instruments; Revolution Counters; Speedometers; Rotation Measuring Instruments and Apparatus; Oxygen Flow Indicators; Tachometers, including Engine Tachometers.', 'Combination Instruments; (FSC 6695); Meteorological Instruments (FSC 6660); and Automatic Control Valves (FSG 48).', null, '66 - INSTRUMENTS AND LABORATORY EQPT', null, '5.0', 'Industrial Products & Services', '5.4', 'Test & Measurement Supplies'),
