  ('6750', 'PHOTOGRAPHIC SUPPLIES', '1978-10-15', null, 'Photographic Supplies', 'Sensitized Photographic Paper; Special Purpose Photographic Chemicals; Unprocessed Film; Photoflash Lamps.', 'X-Ray Film (Medical Class 6525 or Industrial Class 6653); Electrographic (Facsimile) Paper for direct electrostatic printing or copying (FSC 7530).', null, '67 - PHOTOGRAPHIC EQPT', null, '16.0', 'Miscellaneous S&E', '16.2', 'S&E Not Classifed Elsewhere'),
