  ('6770', 'FILM, PROCESSED', '1978-10-15', null, 'Film, Processed', 'Motion Picture Film, Silent and Sound; Still Picture Film.', 'X-Ray Film (Medical class 6525 or Industrial class 6635); Training and Educational Film (FSC 6910); Processed Microfilm (FSC 7670).', null, '67 - PHOTOGRAPHIC EQPT', null, '16.0', 'Miscellaneous S&E', '16.2', 'S&E Not Classifed Elsewhere'),
  ('6780', 'PHOTOGRAPHIC SETS, KITS, AND OUTFITS', '2011-10-01', null, 'Photographic Sets, Kits, and Outfits', null, null, null, '67 - PHOTOGRAPHIC EQPT', null, '16.0', 'Miscellaneous S&E', '16.2', 'S&E Not Classifed Elsewhere'),
  ('68', 'CHEMICALS AND CHEMICAL PRODUCTS', '1979-10-01', null, null, null, null, 'In general, individual nonmedicinal chemical elements and compounds are classified in class 6810. Combinations (or mixtures) of chemical compounds, or chemicals prepared in a particular vehicle (other than water) are generally classified according to use, in classes other than 6810. For example, the chemical compound DDT, is classified in 6810, whereas DDT liquid spray, the insecticide is classified in 6840-Pest Control Agents and Disinfectants. Similarly, items of supply bearing nonchemical names such as BLEACH; INSECTICIDE, ROACH; and ANTIFREEZE are generally classified according to use, in classes other than 6810, whereas corresponding chemical compounds, such as sodium hypochlorite solution, chlordane, and ethylene glycol are classified in 6810. Medicinal chemicals are generally classified in 6505-Drugs and Biologicals; in vitro diagnostic substances and reagents are classified in 6550-In Vitro Diagnostic Substances, Reagents, Test Kits and Sets. Excluded from this group are liquid chemicals designed exclusively for use as propellant fuels and oxidizers.', null, null, null, null, null, null),
  ('6810', 'CHEMICALS', '1978-10-15', null, 'Chemicals', 'Naphtha Solvents; Water Softening Compounds; Tanning Materials, Natural or Synthetic; Dextrines and Starches; Inedible Gelatins; Acetone; Propellant Chemicals, Bulk not specialized solely for Guided Missile Use.', 'Medicinal Chemicals; Gases; Foundry Dextrines; Radiographic and photographic Chemicals; In Vitro Diagnostic Substances and Reagents.', null, '68 - CHEMICALS AND CHEMICAL PRODUCTS', null, '5.0', 'Industrial Products & Services', '5.6', 'Basic Materials'),
  ('6820', 'DYES', '1978-11-15', null, 'Dyes', 'Household Tints', null, null, '68 - CHEMICALS AND CHEMICAL PRODUCTS', null, '5.0', 'Industrial Products & Services', '5.6', 'Basic Materials'),
  ('6830', 'GASES: COMPRESSED AND LIQUEFIED', '2020-10-30', null, 'Gases: Compressed and Liquefied', 'Fuel Gases.', 'Military Chemical Gases; Medical Gases (for medical gases use code 6835); Empty Gas Cylinders and their caps, valves, and valve spare parts.', null, '68 - CHEMICALS AND CHEMICAL PRODUCTS', 'P', '5.0', 'Industrial Products & Services', '5.6', 'Basic Materials'),
  ('6835', 'MEDICAL GASES', '2020-10-30', null, 'Medical Gases', 'Medical gases are used for medical treatments and for use in the human body. Medical gas cylinders contain high purity gas; no other types of gases are allowed in the cylinder. Gases that make up the medical gas category are medical grades of carbon dioxide,  helium, nitrogen, nitrous oxide, oxygen, argon, and other miscellaneous medical gases. This definition also includes bulk oxygen that hospital use to dispense throughout the hospital via the piped in distribution system to the bedside.', null, null, '68 - CHEMICALS AND CHEMICAL PRODUCTS', 'P', '10.0', 'Medical', '10.2', 'Medical Equipment and Accessories and Supplies'),
  ('6840', 'PEST CONTROL AGENTS AND DISINFECTANTS', '2011-10-01', null, 'Pest Control Agents and Disinfectants', 'Insect Repellents; Fungicides; Insecticides; Rodenticides; Weed Killers.', 'Personal Deodorants.', null, '68 - CHEMICALS AND CHEMICAL PRODUCTS', null, '5.0', 'Industrial Products & Services', '5.6', 'Basic Materials'),
  ('6850', 'MISCELLANEOUS CHEMICAL SPECIALTIES', '1978-10-15', null, 'Miscellaneous Chemical Specialties', 'Antifogging Compounds; Wetting Agents; Etching and Fountain Solutions for Lithographing; Blanket Repair Solutions for Lithographing; Antifreeze.', null, null, '68 - CHEMICALS AND CHEMICAL PRODUCTS', null, '14.0', 'Sustainment S&E', '14.3', 'Materials'),
  ('69', 'TRAINING AIDS AND DEVICES', '1979-10-01', null, null, null, null, 'Included are computers (including computer assemblies, computer systems and components) designed specifically for use as, or with training aids and devices.', null, null, null, null, null, null),
  ('6910', 'TRAINING AIDS', '1978-10-15', null, 'Training Aids', 'Mockups; Cutaway Models; Scale Models; Training Films; Training Aid Maps; Navigational Training Aids; Flight Instrument Training Aids; Aircraft Instrument Training Aids; Vehicle Training Aids; Engine Instrument Training Aids; Hydraulic System Training Aids; Cutaway, Mockup, or Sectionalized Ammunition only; Training Equipment normally used in classroom training.', 'Drill, Dummy, Exercise, Practice, or Simulated Ammunition and Weapons.', null, '69 - TRAINING AIDS AND DEVICES', null, '14.0', 'Sustainment S&E', '14.6', 'Training Aids and Devices'),
  ('6920', 'ARMAMENT TRAINING DEVICES', '1978-10-15', null, 'Armament Training Devices', 'Bombing Trainers; Gunnery Trainers; Tow Targets; Gunnery Targets; Guided Missile Training Sets.', 'Target Drones; Drones for such use as training, surveillance, missile evaluation, and photographic reconnaissance; Atomic Ordnance Training Devices; Training Aids; Drill, Dummy, Exercise, Practice, or Simulated Ammunition and Weapons.', null, '69 - TRAINING AIDS AND DEVICES', null, '14.0', 'Sustainment S&E', '14.6', 'Training Aids and Devices'),
  ('6930', 'OPERATION TRAINING DEVICES', '1978-10-15', null, 'Operation Training Devices', 'Link Trainers; Automatic Pilot Training Devices; Drift Meter Training Devices; Celestial Navigation Trainers; Dead Reckoning Navigation Trainers; Instrument Flying and Landing Trainers; Terrain Projection Trainers; All operational training devices except communication and armament.', 'Training Aids', null, '69 - TRAINING AIDS AND DEVICES', null, '14.0', 'Sustainment S&E', '14.6', 'Training Aids and Devices'),
  ('6940', 'COMMUNICATION TRAINING DEVICES', '1978-10-15', null, 'Communication Training Devices', 'Supersonic Radar Trainers; Navigational Radar Trainers; Search and Detecting Radar Trainers; Code Practice Equipment.', 'Training Aids.', null, '69 - TRAINING AIDS AND DEVICES', null, '14.0', 'Sustainment S&E', '14.6', 'Training Aids and Devices'),
  ('7', 'IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', '2020-10-30', null, null, null, null, null, null, null, null, null, null, null),
  ('7A', 'IT AND TELECOM - APLLICATIONS', '2020-10-30', null, null, null, null, null, '7 - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('7A20', 'IT AND TELECOM - APPLICATION DEVELOPMENT SOFTWARE (PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Application development software delivered by perpetual license, consisting of analysis, design, development, code, test and release packages associated with application development projects.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', 'Excludes end-user productivity software.', null, '7A - IT AND TELECOM - APLLICATIONS', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7A21', 'IT AND TELECOM - BUSINESS APPLICATION SOFTWARE (PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Business Application off-the-shelf software delivered by perpetual license, which also encompasses enterprise level software enabling mission capability and business operational support.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', 'Excludes end-user productivity software.', null, '7A - IT AND TELECOM - APLLICATIONS', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7B', 'IT AND TELECOM - COMPUTE', '2020-10-30', null, null, null, null, null, '7 - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('7B20', 'IT AND TELECOM - HIGH PERFORMANCE COMPUTE (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Hardware, software, and other equipment needed for specialized High Performance Computing (HPC) systems used in solving complex computational problems through massive concurrent use of computing resources and parallel processing techniques.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7B - IT AND TELECOM - COMPUTE', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7B21', 'IT AND TELECOM - COMPUTE: MAINFRAME (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Computing hardware and software products for traditional mainframe computers and operations running legacy operating systems.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7B - IT AND TELECOM - COMPUTE', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7B22', 'IT AND TELECOM - COMPUTE: SERVERS (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Computing hardware and software products for servers and converged appliances, such as physical and virtual server environments, tools, operating systems (Windows, Linux, UNIX) and virtualization software.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', 'Excludes products for High Performance Computing.', null, '7B - IT AND TELECOM - COMPUTE', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7C', 'IT AND TELECOM - DATA CENTER', '2020-10-30', null, null, null, null, null, '7 - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('7C20', 'IT AND TELECOM - DATA CENTER PRODUCTS (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Hardware, software, and other equipment for tiered or Enterprise data center facilities that house and protect critical IT equipment.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7C - IT AND TELECOM - DATA CENTER', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7C21', 'IT AND TELECOM - OTHER DATA CENTER FACILITIES PRODUCTS (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Hardware, software, and other equipment needed to support non-tiered data center facilities; computer rooms, MDF/Telco closets, such as racks, cabling, and management systems.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7C - IT AND TELECOM - DATA CENTER', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7D', 'IT AND TELECOM - DELIVERY', '2020-10-30', null, null, null, null, null, '7 - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('7D20', 'IT AND TELECOM - SERVICE DELIVERY MANAGEMENT (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Hardware and software needed for delivery processes including IT Service Management (ITSM), Project Program and Portfolio (PPM), and Operations Centers (NOC, GOC). ITSM processes include incident, problem and change management services as part of the ITSM program. IT Project Management includes support for agile and continuous improvement/development (CI/CD).', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', 'Excludes the Tier 1 and 2 Help Desk products.', null, '7D - IT AND TELECOM - DELIVERY', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7E', 'IT AND TELECOM - END USER', '2020-10-30', null, null, null, null, null, '7 - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('7E20', 'IT and Telecom - End User: Help Desk;Tier 1-2,Workspace,Print,Output,Productivity Tools (HW/Perp SW)', '2022-04-02', null, 'Hardware, software, and other equipment for end user client computing including Tier 1 and 2 help/service desk, deskside support, adds/moves/changes, workspace technical support, audio/video (A/V, VTC) conferencing, workspace, collaboration and productivity software, printers and other central printing or output needs. A/V and VTC includes equipment typically used in conference rooms and dedicated telepresence rooms to enable workforce communications. Workspace includes physical desktops, laptops, thin client, and peripherals (monitors, mouses, keyboards). Helpdesk and Deskside support includes hardware, software and equipment needed to troubleshoot, repair, and manage client computing devices. Collaboration and productivity software includes tools used to author, create, collaborate and share documents and other content.', 'Software for e-mail, communications, messaging, word processing, spreadsheets, presentations, desktop publishing, graphics and others. Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7E - IT AND TELECOM - END USER', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7E21', 'IT AND TELECOM - MOBILE DEVICE PRODUCTS (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Mobile devices such as tablets, smart phones (iOS, Android, Windows Mobile) and peripherals that support a mobile workforce accessing corporate resources.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7E - IT AND TELECOM - END USER', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7F', 'IT AND TELECOM - IT MANAGEMENT', '2020-10-30', null, null, null, null, null, '7 - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('7F20', 'IT AND TELECOM - IT MANAGEMENT TOOLS/PRODUCTS (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Hardware and software products supporting IT Management services. Includes Enterprise Architecture (EA), Financial Management, and Strategic Planning. EA includes services supporting business, information, application and technical architecture to drive standardization, integration and efficiency among business technology solutions. Financial Management includes services involved in the planning, budgeting, spend management and chargeback of IT expenditures and the costing of IT products and services. IT Management and Strategic Planning include senior professional and administrative support services facilitating centralized IT strategy and planning.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7F - IT AND TELECOM - IT MANAGEMENT', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7G', 'IT AND TELECOM - NETWORK', '2020-10-30', null, null, null, null, null, '7 - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('7G20', 'IT AND TELECOM - NETWORK: ANALOG VOICE PRODUCTS (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Legacy analog voice communications equipment, hardware, and software used to connect end users to the organization''s voice systems. Includes analog transmission and transport equipment, physical communications infrastructure carrying analog signals over copper wiring (outside and inside plant), products and tools that enable or distribute voice services through on-premise analog equipment including PBX, voicemail, and handsets.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7G - IT AND TELECOM - NETWORK', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7G21', 'IT AND TELECOM - NETWORK: DIGITAL NETWORK PRODUCTS (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Digital network communications hardware, software, and other equipment used within the core data centers and work areas, connecting end users to the organization''s Local Area Network (LAN). Wide Area Network (WAN) digital transmission equipment, supporting hardware and software directly connecting data centers, offices and third parties. Includes 1) external digital network transport equipment (Outside Plant) physical communications infrastructure connecting to LAN/WAN end points 2) copper and fiber communications systems, and 3) cellular infrastructure such as towers, repeaters, switching systems dedicated for cellular communication. Products and tools that enable or distribute voice services through on-premise digital equipment including PBX, VoIP, voicemail and handsets.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7G - IT AND TELECOM - NETWORK', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7G22', 'IT AND TELECOM - NETWORK: SATELLITE AND RF COMMUNICATIONS PRODUCTS (HW, PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Hardware and software for dedicated satellite and RF (microwave) communications equipment carrying data network circuits, and associated access facilities. Radio and TV signal generation, broadcast, and distribution components, handheld 2-way radio, and other RF communications systems.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7G - IT AND TELECOM - NETWORK', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7H', 'IT AND TELECOM - PLATFORM', '2020-10-30', null, null, null, null, null, '7 - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('7H20', 'IT AND TELECOM - PLATFORM PRODUCTS: DATABASE, MAINFRAME, MIDDLEWARE (HW, PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Hardware, software, and other equipment needed for local database instances, distributed platform, application and system integration resources enabling cross application development, communications and information sharing. Includes Mainframe database and middleware products and tools.', 'Mainframe database and middleware products and tools. Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7H - IT AND TELECOM - PLATFORM', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7J', 'IT AND TELECOM - SECURITY AND COMPLIANCE', '2020-10-30', null, null, null, null, null, '7 - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('7J20', 'IT AND TELECOM - SECURITY AND COMPLIANCE PRODUCTS (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Hardware and perpetual software licenses for IT Security products providing Continuous Diagnostics and Mitigation (CDM) for real-time operational security such as vulnerability scanning, cyber security, managing firewalls, intrusion prevention systems, and security information and event management (SIEM). Also covers IT Disaster Recovery tools to enable backup and recovery; dedicated failover facilities, generators, UPS systems.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', 'DR designated equipment is included directly in its own sub-tower (e.g., extra servers for DR are included in Compute tower, etc.). The implementation actions defined by security policies (e.g. mitigating security breaches by applying patches) are not included in the Security sub-tower and are part of the respective towers where the actions take place (e.g. Compute, Storage, Network).', null, '7J -IT AND TELECOM - SECURITY AND COMPLIANCE', 'P', '1.0', 'IT', '1.1', 'Product'),
  ('7K', 'IT AND TELECOM - STORAGE', '2020-10-30', null, null, null, null, null, '7 - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('7K20', 'IT AND TELECOM - STORAGE PRODUCTS (HARDWARE AND PERPETUAL LICENSE SOFTWARE)', '2020-10-30', null, 'Hardware, software, and other equipment needed for specialized High Performance Computing (HPC) systems used in solving complex computational problems through massive concurrent use of computing resources and parallel processing techniques.', 'Software that is licensed for use indefinitely. This can also be referred to as perpetual, indefinite, permanent, continuous, or ever lasting.', null, null, '7K - IT AND TELECOM - STORAGE', 'P', '1.0', 'IT', '1.1', 'Product'),
