  ('8110', 'DRUMS AND CANS', '1978-10-15', null, 'Drums and Cans', 'Barrels; Kegs, Shipping and Storage Pails; Collapsible Tubes; Mailing and Filing Tubes; Closures for Drums and Cans.', null, null, '81 - CONTAINERS/PACKAGING/PACKING SUPPL', null, '7.0', 'Transportation and Logistics Services', '7.1', 'Package Delivery & Packaging'),
  ('8115', 'BOXES, CARTONS, AND CRATES', '1978-10-15', null, 'Boxes, Cartons, and Crates', 'Shoe Boxes; Beer Cases; Pill Boxes; Piano Cases; Engine Boxes; Bombsight Boxes.', 'Special boxes, packages, and containers designed primarily for shipping, storage and handling of ammunition, nuclear ordnance, explosives, guided missiles, military chemical agents; and repairable /reusable containers specially designed for specialized equipment such as the "Shipping and Storage Containers" for components of aircraft, space vehicles, automotive vehicles, ships, ground communication equipment.', null, '81 - CONTAINERS/PACKAGING/PACKING SUPPL', null, '7.0', 'Transportation and Logistics Services', '7.1', 'Package Delivery & Packaging'),
  ('8120', 'COMMERCIAL AND INDUSTRIAL GAS CYLINDERS', '2011-10-01', null, 'Commercial and Industrial Gas Cylinders', 'filled gas cylinders and items related to gaseous and liquefied gaseous dispensing systems, both mobile and installed. All components of installed gas dispensing systems are classified by "application" or "function" with the end equipment for which designed.', 'filled gas cylinders and items related to gaseous and liquefied gaseous dispensing systems, both mobile and installed. All components of installed gas dispensing systems are classified by "application" or "function" with the end equipment for which designed.', 'This class includes empty commercial and industrial gas cylinders and their caps, valves, and valve spare parts.', '81 - CONTAINERS/PACKAGING/PACKING SUPPL', null, '7.0', 'Transportation and Logistics Services', '7.1', 'Package Delivery & Packaging'),
  ('8125', 'BOTTLES AND JARS', '1979-01-15', null, 'Bottles and Jars', 'Shipping Jugs and Carboys; Ampoules.', null, null, '81 - CONTAINERS/PACKAGING/PACKING SUPPL', null, '7.0', 'Transportation and Logistics Services', '7.1', 'Package Delivery & Packaging'),
  ('8130', 'REELS AND SPOOLS', '1978-11-15', null, 'Reels and Spools', null, null, null, '81 - CONTAINERS/PACKAGING/PACKING SUPPL', null, '7.0', 'Transportation and Logistics Services', '7.1', 'Package Delivery & Packaging'),
  ('8135', 'PACKAGING AND PACKING BULK MATERIALS', '2011-10-01', null, 'Packaging and Packing Bulk Materials', 'Wrapping Paper; Moisture Vapor Barrier Paper; Excelsior; Wadding for Packing; Corrugated Paper; Baling Bands, Baling Ties; Shipping Tags; Gummed Paper Tape; Separators; Box Liners; Packaging Staples; Baling Wire; Preformed Cushioning Inserts;', 'Adhesives; Aluminum Foil other than for food handling and processing.', null, '81 - CONTAINERS/PACKAGING/PACKING SUPPL', null, '7.0', 'Transportation and Logistics Services', '7.1', 'Package Delivery & Packaging'),
  ('8140', 'AMMUNITION AND NUCLEAR ORDNANCE BOXES, PACKAGES AND SPECIAL CONTAINERS', '2011-10-01', null, 'Ammunition and Nuclear Ordnance Boxes, Packages and Special Containers', 'All shipping and storage containers specially designed for guided missiles, major missile sections, missile warheads, and other guided missile components.', 'General Purpose Containers, Shipping and storage reusable/repairable containers specially designed for components of aircraft, space vehicles, automotive vehicles, ships, and ground communication equipment.', 'This class includes only containers and fittings which are specifically designed for the storage, handling, and shipping of ammunition, explosives, and military chemical agents.', '81 - CONTAINERS/PACKAGING/PACKING SUPPL', null, '14.0', 'Sustainment S&E', '14.3', 'Materials'),
  ('8145', 'SPECIALIZED SHIPPING AND STORAGE CONTAINERS', '2011-10-01', null, 'Specialized Shipping and Storage Containers', 'Specially designed components (not elsewhere classifiable) peculiar to special shipping and storage containers as delimited under this class.', 'General purpose containers; specially designed containers for ammunition, nuclear ordnance, explosives, military chemical agents and guided missile components. Excluded from this class are items for which more specific classifications are suitable. The FSC indexes and structure will govern the classification of those items permitted classification in a single class only.', 'This class includes only reusable and repairable containers specially designed for shipping and storage of specialized equipment; i.e., shipping and storage containers for components of aircraft, space vehicles, automotive vehicles, ships, ground communication equipment, etc.', '81 - CONTAINERS/PACKAGING/PACKING SUPPL', null, '7.0', 'Transportation and Logistics Services', '7.1', 'Package Delivery & Packaging'),
  ('8150', 'FREIGHT CONTAINERS', '2011-10-01', null, null, 'GENERAL PURPOSE, DRY BULK, AMMUNITION GRADE, NAMED CARGO, THERMAL, OPEN-TOP, PLATFORM, TANK AND AIR/SURFACE CONTAINERS.', 'SHIPPING AND STORAGE REUSABLE/REPAIRABLE CONTAINERS SPECIALLY DESIGNED FOR COMPONENTS OF AIRCRAFT, SPACE VEHICLES, AUTOMOTIVE VEHICLES, SHIPS, AND GROUND COMMUNICATION EQUIPMENT. ALSO EXCLUDES SPECIAL BOXES, PACKAGES AND CONTAINERS DESIGNED PRIMARILY FOR SHIPPING, STORAGE AND HANDLING OF AMMUNITION, NUCLEAR ORDNANCE, EXPLOSIVES, GUIDED MISSILES, AND MILITARY CHEMICAL AGENTS.', 'THIS CLASS INCLUDES ONLY INTERNATIONAL ORGANIZATION FOR STANDARDIZATION (ISO) CONFIGURED CONTAINERS DESIGNED TO FACILITATE THE REPEATED CARRIAGE OF GOODS BY MULTIPLE MODES OF TRANSPORTATION WITHOUT INTERMEDIATE RELOADING.', '81 - CONTAINERS/PACKAGING/PACKING SUPPL', null, '7.0', 'Transportation and Logistics Services', '7.1', 'Package Delivery & Packaging'),
