  ('9505', 'WIRE, NONELECTRICAL', '1978-10-15', null, 'Wire, Nonelectrical', 'Wire having electrical resistivity or conductivity rating (FSC 6145).', 'Wire having electrical resistivity or conductivity rating (FSC 6145).', 'This class contains bulk material only. Specially designed items should be placed in a more appropriate class. Wire is a thin, flexible, continuous length of metal, usually of circular cross-section.', '95 - METAL BARS, SHEETS, SHAPES', null, '5.0', 'Industrial Products & Services', '5.6', 'Basic Materials'),
  ('9510', 'BARS AND RODS', '1978-10-15', null, 'Bars and Rods', 'Metal Bars and Rods', 'Muck Bar (FSC 9640); Rods for Wire (FSC 9640); Sheet Bar (FSC 9640); Threaded Rods (FSC 5306); Grooved Rod (FSC 5340).', 'This class contains bulk material only. Specially designed items should be placed in a more appropriate class. a. Bars are elongated pieces of metal of simple uniform cross-sections usually rectangular, circular, or hexagonal produced by forging or hotrolling, also known as barstock. b. Rods are thin round metal bar, differentiated by dimensional parameters, listed in the item name definition.', '95 - METAL BARS, SHEETS, SHAPES', null, '5.0', 'Industrial Products & Services', '5.6', 'Basic Materials'),
  ('9515', 'PLATE, SHEET, STRIP, FOIL, AND LEAF', '1978-10-15', null, 'Plate, Sheet, Strip, Foil, and Leaf', 'Armor Plate; Black Plate; Floor Plate; Leaf; Perforated Sheet and Strip; Shim Stock.', 'Bale Ties (FSC 8135); Baling Bands (FSC 8135); Mending Plates (FSC 5340); Mounting Plates (FSC 5340); T Plates (FSC 5340).', 'This class contains bulk material only. Specially designed items should be placed in a more appropriate class. The items covered by this class are all similar in that they are flat, generally rolled metal, the difference is covered by dimensional parameters in the item name definition.', '95 - METAL BARS, SHEETS, SHAPES', null, '5.0', 'Industrial Products & Services', '5.6', 'Basic Materials'),
  ('9520', 'STRUCTURAL SHAPES', '1978-10-15', null, 'Structural Shapes', 'Bar Size Shapes (under 3 inches); Metal Piles and Piling; Angles; Channels; Tees; Zees.', 'Plate, Sheet and Strip Materials (FSC 9515).', 'This class contains bulk material only. Specially designed items should be placed in a more appropriate class. This class includes items usually used in building, bridge and similar construction, such as, I beams, angles, and the like.', '95 - METAL BARS, SHEETS, SHAPES', null, '5.0', 'Industrial Products & Services', '5.6', 'Basic Materials'),
