  ('D', 'IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', '2020-10-30', null, null, null, null, null, null, null, null, null, null, null),
  ('DA', 'IT AND TELECOM - APLLICATIONS', '2020-10-30', null, null, null, null, null, 'D - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('DA01', 'IT AND TELECOM - BUSINESS APPLICATION/APPLICATION DEVELOPMENT SUPPORT SERVICES (LABOR)', '2020-10-30', null, 'Support services for activities involved with application development and support to include analysis, design, development, coding, testing, and release packaging, as well as support of off-the-shelf Business Applications.', 'User Research, Human Center Design, Development/Security/Operations (DevSecOps), Customer Experience (UX)', null, 'Application development for new software projects and support for existing applications.', 'DA - IT AND TELECOM - APPLICATIONS', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DA10', 'IT AND TELECOM - BUSINESS APPLICATION/APPLICATION DEVELOPMENT SOFTWARE AS A SERVICE', '2020-10-30', null, 'Support services, delivered as a service contract (SaaS or Subscription) involved with the analysis, design, development, code, test and release packaging services associated with application development projects, as well as off-the-shelf Business software.', 'Software that is licensed for use over a defined period of time. This can also be referred to term, temporary, provisional, or short-term.', 'End-user productivity software.', 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DA - IT AND TELECOM - APPLICATIONS', 'As a Service or S', '1.0', 'IT', '1.2', 'Capability As a Service'),
  ('DB', 'IT AND TELECOM - COMPUTE', '2020-10-30', null, null, null, null, null, 'D - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('DB01', 'IT AND TELECOM - HIGH PERFORMANCE COMPUTING (HPC) SUPPORT SERVICES (LABOR)', '2020-10-30', null, 'Support services for specialized High Performance Computing (HPC) systems used in solving complex computational problems through massive concurrent use of computing resources and parallel processing techniques.', null, null, 'HPC technology is applied in areas such as scientific and industrial research, product engineering and development, and complex business modeling, simulation and analysis.', 'DB - IT AND TELECOM - COMPUTE', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DB02', 'IT AND TELECOM - COMPUTE SUPPORT SERVICES, NON-HPC (LABOR)', '2020-10-30', null, 'Computing support services for physical and virtual servers operating stand-alone, virtually, or in public/private cloud environments. Includes support services for traditional mainframe computers and operations running legacy operating systems.', null, 'Support for High Performance Computing.', null, 'DB - IT AND TELECOM - COMPUTE', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DB10', 'IT AND TELECOM - COMPUTE AS A SERVICE: MAINFRAME/SERVERS', '2020-10-30', null, 'Computing delivered as a service in a public or private cloud environment, such as services for traditional mainframe computers and operations running Windows, Linux, converged infrastructure or UNIX operating systems.', 'Software that is licensed for use over a defined period of time. This can also be referred to term, temporary, provisional, or short-term.', 'Support for High Performance Computing.', 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DB - IT AND TELECOM - COMPUTE', 'As a Service or S', '1.0', 'IT', '1.2', 'Capability As a Service'),
  ('DC', 'IT AND TELECOM - DATA CENTER', '2020-10-30', null, null, null, null, null, 'D - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('DC01', 'IT AND TELECOM - DATA CENTER SUPPORT SERVICES (LABOR)', '2020-10-30', null, 'Support services for data center facilities that house and protect critical IT equipment including the space, power, environment controls, racks, cabling and "smart hand" support. Includes tiered and non-tiered computer rooms, MDF/Telco closets and other facilities that house IT equipment.', null, null, null, 'DC - IT AND TELECOM - DATA CENTER', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DC10', 'IT AND TELECOM - DATA CENTER AS A SERVICE', '2020-10-30', null, 'Data center services delivered as a service contract. Offsite data center facilities using the resources provided by 3rd parties. May be part of an Infrastructure as a Service offering.', 'Co-located (Colo) services, Data Center as a Service (DCaaS), and Managed Service Provider (MSP) data centers. Software that is licensed for use over a defined period of time. This can also be referred to term, temporary, provisional, or short-term.', null, 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DC - IT AND TELECOM - DATA CENTER', 'As a Service or S', '1.0', 'IT', '1.2', 'Capability As a Service'),
  ('DD', 'IT AND TELECOM - DELIVERY', '2020-10-30', null, null, null, null, null, 'D - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('DD01', 'IT AND TELECOM - SERVICE DELIVERY SUPPORT SERVICES: ITSM, OPERATIONS CENTER, PROJECT/PM (LABOR)', '2020-10-30', null, 'Support services for delivery processes including IT Service Management (ITSM), Project Program and Portfolio (PPM), and Operations Centers (NOC, GOC). ITSM processes include incident, problem and change management services as part of the ITSM program. IT Project Management includes support for agile and continuous improvement/development (CI/CD).', null, 'Tier 1 and 2 Help Desk.', null, 'DD - IT AND TELECOM - DELIVERY', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DE', 'IT AND TELECOM - END USER', '2020-10-30', null, null, null, null, null, 'D - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('DE01', 'IT and Telecom - End User: Help Desk; Tier 1-2, Workspace, Print, Output, Productivity Tools (Labor)', '2022-04-02', null, 'Support services for end user client computing including Tier 1 and 2 help/service desk, deskside support, adds/moves/changes, workspace, collaboration, and productivity software technical support, audio/video (A/V, VTC) conferencing, and printer support. A/V and VTC includes support services typically used in conference rooms and dedicated telepresence rooms to enable workforce communications. Printer support includes Managed Print Services (MPS) for multifunction printers (print, scan, fax, copy), and other central printing or output support services.', null, 'Mobile device support.', null, 'DE - IT AND TELECOM - END USER', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DE02', 'IT AND TELECOM - MOBILE DEVICE SUPPORT SERVICES (LABOR)', '2020-10-30', null, 'Support services for mobile devices such as tablets, smart phones (iOS, Android, Windows Mobile) that support a mobile workforce accessing corporate resources. Includes mobile service management, logistics, technical support, system and configuration management services related to the devices.', null, null, null, 'DE - IT AND TELECOM - END USER', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DE10', 'IT and Telecom - End User as a Service: Help Desk;Tier 1-2,Workspace,Print,Output,Productivity Tools', '2022-04-02', null, 'End user client computing delivered as a service. Includes software and support tools delivered as a service contract and used for End User support such as Tier 1 and 2 help/service desk, deskside support, adds/moves/changes, workspace technical support, audio/video (A/V, VTC) conferencing, and print services. A/V and VTC include services typically used in conference rooms and dedicated telepresence rooms to enable workforce communications. Print services include Managed Print Services (MPS) for multifunction printers (print, scan, fax, copy), and other central printing or output support services. Workspace includes Desktop as a Service (DaaS) and Workspace as a Service (WaaS) delivered via public cloud or 3rd party providers. Client compute equipment provisioned by service contract. Also includes client related productivity software accessed as a service (SaaS), used to author, create, collaborate and share documents and other content.', 'Software for e-mail, communications, messaging, word processing, spreadsheets, presentations, desktop publishing, graphics and others.', null, 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DE - IT AND TELECOM - END USER', 'As a Service or S', '1.0', 'IT', '1.2', 'Capability As a Service'),
  ('DE11', 'IT AND TELECOM - MOBILE DEVICE AS A SERVICE', '2020-10-30', null, 'Mobility support delivered as a service (Managed Mobility Services - MMS) for mobile devices such as tablets, smart phones (iOS, Android, Windows Mobile) that support a mobile workforce accessing corporate resources.', 'Mobile service management, logistics, help/service desk, technical support, system and configuration management services. Software that is licensed for use over a defined period of time. This can also be referred to term, temporary, provisional, or short-term.', 'Cellular services; see Cloud Network as a Service.', 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DE - IT AND TELECOM - END USER', 'As a Service or S', '1.0', 'IT', '1.2', 'Capability As a Service'),
  ('DF', 'IT AND TELECOM - IT MANAGEMENT', '2020-10-30', null, null, null, null, null, 'D - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('DF01', 'IT AND TELECOM - IT MANAGEMENT SUPPORT SERVICES (LABOR)', '2020-10-30', null, 'Support services for IT Management to include Enterprise Architecture (EA), Financial Management, and Strategic Planning. EA includes services supporting business, information, application and technical architecture to drive standardization, integration and efficiency among business technology solutions. Financial Management includes services involved in the planning, budgeting, spend management and chargeback of IT expenditures and the costing of IT products and services. IT Management and Strategic Planning include senior professional and administrative support services facilitating centralized IT strategy and planning.', null, null, null, 'DF - IT AND TELECOM - IT MANAGEMENT', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DF10', 'IT AND TELECOM - IT MANAGEMENT AS A SERVICE', '2020-10-30', null, 'IT Management tools and services delivered as a service, by subscription, or service contract. Includes Enterprise Architecture (EA), Financial Management, and Strategic Planning. EA includes services supporting business, information, application and technical architecture to drive standardization, integration and efficiency among business technology solutions. Financial Management includes services involved in the planning, budgeting, spend management and chargeback of IT expenditures and the costing of IT products and services. IT Management and Strategic Planning include senior professional and administrative support services facilitating centralized IT strategy and planning.', 'Software that is licensed for use over a defined period of time. This can also be referred to term, temporary, provisional, or short-term.', null, 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DF - IT AND TELECOM - IT MANAGEMENT', 'As a Service or S', '1.0', 'IT', '1.2', 'Capability As a Service'),
  ('DG', 'IT AND TELECOM - NETWORK', '2020-10-30', null, null, null, null, null, 'D - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('DG01', 'IT AND TELECOM - NETWORK SUPPORT SERVICES (LABOR)', '2020-10-30', null, 'Support services for physical and wireless networks connecting equipment within the core data centers and work areas, connecting end users to the organization''s broader networks, as well as Wide Area Network equipment, hardware and software directly connecting into data centers, offices and third parties. Support services which enable or distribute voice services through on-premise equipment including PBX, VoIP, voicemail and handsets. Also provides support for transport services for data and voice network circuits and associated access facilities and services; includes dedicated and virtual data networks and internet access. Support services for external (Outside Plant) physical communications infrastructure connecting to LAN/WAN end points. Mobile infrastructure support such as cabled communication network, cellular towers, repeaters, switching systems dedicated for cellular communication', null, null, null, 'DG - IT AND TELECOM - NETWORK', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DG10', 'IT AND TELECOM - NETWORK AS A SERVICE', '2020-10-30', null, 'Network services delivered as a service, by subscription, or service contract. Physical and wireless networks managed as a service connected to and from core data centers, work areas, and offices connecting end users to the organization''s broader networks. Network services delivered in connection with other IaaS and PaaS services. Cloud based network management services and Software Defined Networks (SDN) accessed by service contract or subscriptions.', 'Software that is licensed for use over a defined period of time. This can also be referred to term, temporary, provisional, or short-term.', null, 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DG - IT AND TELECOM - NETWORK', 'As a Service or S', '1.0', 'IT', '1.2', 'Capability As a Service'),
  ('DG11', 'IT and Telecom - Network: Satellite Communications and Telecom Access Services', '2022-04-02', null, 'Telecom access and other usage billing services. Includes satellite communications access, internet, cellular services, landline and telephone services. Transport services for data and voice network circuits and associated access facilities and services; includes dedicated and virtual data networks.', 'Includes dedicated and virtual data networks, usage associated with standard telephone calls, and 800 number service.Software that is licensed for use over a defined period of time. This can also be referred to term, temporary, provisional, or short-term.', null, 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DG - IT AND TELECOM - NETWORK', 'As a Service or S', '1.0', 'IT', '1.2', 'Capability As a Service'),
  ('DH', 'IT AND TELECOM - PLATFORM', '2020-10-30', null, null, null, null, null, 'D - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('DH01', 'IT AND TELECOM - PLATFORM SUPPORT SERVICES: DATABASE, MAINFRAME, MIDDLEWARE (LABOR)', '2020-10-30', null, 'Support services focused on local database instances, including DBAs, DBMS, and operational support. Also supports distributed platform, application and system integration resources enabling cross application development, communications and information sharing. Includes Mainframe database and middleware support.', null, null, null, 'DH - IT AND TELECOM - PLATFORM', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DH10', 'IT AND TELECOM - PLATFORM AS A SERVICE: DATABASE, MAINFRAME, MIDDLEWARE', '2020-10-30', null, 'Platform delivered as a service for databases and middleware. A distributed platform, application and system integration resources enabling cross application development, communications and information sharing.', 'Mainframe database and middleware delivered as a service. Software that is licensed for use over a defined period of time. This can also be referred to term, temporary, provisional, or short-term.', null, 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DH - IT AND TELECOM - PLATFORM', 'As a Service or S', '1.0', 'IT', '1.2', 'Capability As a Service'),
  ('DJ', 'IT AND TELECOM - SECURITY AND COMPLIANCE', '2020-10-30', null, null, null, null, null, 'D - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('DJ01', 'IT AND TELECOM - SECURITY AND COMPLIANCE SUPPORT SERVICES (LABOR)', '2022-04-02', null, 'Support services focused on supporting security policies/controls, processes, measuring compliance of relevant legal/compliance requirements, to include Section 508, and responding to security breaches. Also provides support for IT Security systems providing Continuous Diagnostics and Mitigation (CDM) for real-time Cyber Security and protection such as vulnerability scanning, managing firewalls, intrusion prevention systems, and security information and event management (SIEM). Includes Disaster Recovery (DR) services to support DR policy, process and means, dedicated failover facilities and perform DR testing.', null, 'The implementation actions defined by Compliance policy (e.g. implementing controls like multi-factor authentication) are not included in the Compliance sub-tower and are part of the respective towers where the actions take place (e.g. Compute, Storage, Network, Application, End User).', null, 'DJ - IT AND TELECOM - SECURITY AND COMPLIANCE', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DJ10', 'IT AND TELECOM - SECURITY AND COMPLIANCE AS A SERVICE', '2022-04-02', null, 'Security and Compliance support delivered as a service, by subscription, or service contract. Includes support of security policies/controls, processes, measuring compliance of relevant legal/compliance requirements, to include Section 508, and responding to security breaches. Also provides support for IT Security systems providing Continuous Diagnostics and Mitigation (CDM) for real-time Cyber Security and protection such as vulnerability scanning, managing firewalls, intrusion prevention systems, and security information and event management (SIEM). Includes Disaster Recovery (DR) services to support DR policy, process and means, dedicated failover facilities and perform DR testing.', 'Software that is licensed for use over a defined period of time. This can also be referred to term, temporary, provisional, or short-term.', 'The implementation actions defined by Disaster Recovery policy (e.g. building DR servers) are not included in the Disaster & Recovery sub-tower and are part of the respective towers where the actions take place (e.g. Compute, Storage, Network).', 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DJ - IT AND TELECOM - SECURITY AND COMPLIANCE', 'As a Service or S', '1.0', 'IT', '1.2', 'Capability As a Service'),
  ('DK', 'IT AND TELECOM - STORAGE', '2020-10-30', null, null, null, null, null, 'D - IT AND TELECOM - INFORMATION TECHNOLOGY AND TELECOMMUNICATIONS', null, null, null, null, null),
  ('DK01', 'IT AND TELECOM - STORAGE SUPPORT SERVICES (LABOR)', '2020-10-30', null, 'Support services used for 1) offline storage; archive, backup & recovery to manage data loss, data corruption, disaster recovery and compliance requirements of the distributed storage 2) Mainframe storage system services and 3) local storage such as SAN, NAS and similar technologies for the distributed compute infrastructure.', null, null, 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DK - IT AND TELECOM - STORAGE', 'S', '1.0', 'IT', '1.3', 'IT Professional Service (Labor)'),
  ('DK10', 'IT AND TELECOM - STORAGE AS A SERVICE', '2020-10-30', null, 'Cloud solutions delivered as a service.', 'Mainframe storage as a service. Software that is licensed for use over a defined period of time. This can also be referred to term, temporary, provisional, or short-term.', null, 'Software as a Service, Service Contracts, Subscription based software provisioning, and device rentals are considered services.', 'DK - IT AND TELECOM - STORAGE', 'As a Service or S', '1.0', 'IT', '1.2', 'Capability As a Service'),
