  ('Q', 'MEDICAL SERVICES', '1979-10-01', null, null, null, null, null, null, null, null, null, null, null),
  ('Q1', 'DEPENDENT MEDICARE SERVICES', '1979-10-01', null, null, null, null, null, 'Q - MEDICAL SERVICES', null, null, null, null, null),
  ('Q101', 'MEDICAL- DEPENDENT MEDICARE', '2011-10-01', null, 'Dependent Medicare Services', null, null, null, 'Q1 - DEPENDENT MEDICARE SERVICES', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q2', 'GENERAL HEALTH CARE SERVICES', '1979-10-01', null, null, null, null, null, 'Q - MEDICAL SERVICES', null, null, null, null, null),
  ('Q201', 'MEDICAL- MANAGED HEALTHCARE', '2024-04-30', null, 'MEDICAL- MANAGED HEALTHCARE', 'Services that provide more than one medical discipline in a comprehensive contract requirement. Examples include DoD TRICARE Contracts and VA Community Care Contracts.', 'Services that focus on one specific discipline or more than one discipline that are not part of a contract for comprehensive managed care services.  For those services, select the specific code related to the specific discipline.  If more than one discipline is being provided, choose the code that represents the preponderance of spend.  For specific services for which no code is provided choose the hierarchical code such as Internal Medicine or Surgery.', 'Managed Care  support services that provide a comprehensive array of healthcare services. Services are all inclusive and may include inpatient and/or outpatient services.', 'Q2 - GENERAL HEALTH CARE SERVICES', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q3', 'LABORATORY TESTING SERVICES', '1979-10-01', null, null, null, null, null, 'Q - MEDICAL SERVICES', null, null, null, null, null),
  ('Q301', 'REFERENCE LABORATORY TESTING', '2024-04-30', null, 'Reference Laboratory Testing', 'All services performed in a reference laboratory.  Services can be comprehensive or specific and generally include the following: blood counts, coagulation, clinical biochemistry, histopathology, cytopathology, molecular diagnostics, genetic testing, drug testing, etc.', 'Hematology/Oncology (Q508), Services of a Pathologist, Laboratory Technician or Technologist (Q515), equipment (6632 or 6640), and reagents and test kits (6550).', null, 'Q3 - LABORATORY TESTING SERVICES', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q4', 'NURSING, NURSING HOME, EVAL/SCREEN', '1979-10-01', null, null, null, null, null, 'Q - MEDICAL SERVICES', null, null, null, null, null),
  ('Q401', 'MEDICAL- NURSING', '2024-04-30', null, 'Nursing', 'Registered nurses (RNs), all specialities, that provide direct care to patients (synchronous and asynchronous). This includes RN Case Management, RN Surgical Case Reviewer, Licensed Practical/Vocational Nurses (LPN/LVN), LPN/LVN Case Management, Medical Assistant, Nursing Assistant, Advanced Practice Registered Nurses (APRN {NP}), in all sub-specialties, and Clinical Nurse Specialists (also APRNs) in all sub-specialities.', 'RN’s/LPN’s/LVN’s that work in a support position with no patient care. These positions include, RN/LPN/LVN Utilization Management, RN Medical Board Liaison, RN/LPN/LVN in Referral Management (all of these would use PSC Q701, Specialized Medical Support). Psychiatric Technician (use PSC Q519 Behavioral & Mental health), Emergency Medical Technicians and Paramedics (use PSC Q529, Emergency Medicine Services). With these changes to includes and excludes, all Federal Agencies DoD, VA, HHS, and other Department/Agencies will be able to better clarify spend visibility and supplementary guidance.', null, 'Q4 - NURSING, NURSING HOME, EVAL/SCREEN', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q402', 'NURSING HOME, LONG-TERM & ADULT DAY CARE SERVICES', '2024-04-30', null, 'Nursing Home, Long-Term & Adult Day Care Services', 'Nursing home care, Long-Term Healthcare (in facility & home), Adult/Geriatric Day Care programs.', 'Any nursing personnel (Q401, Nursing), Family Practice or Internal Medicine Physicians {including gerontologists} (Q509 Family Practice & Internal Medicine Services), Managed Care contracts (Q201 General Healthcare), Physical and/or Occupational Therapy (Q518 Physical Medicine & Rehabilitation), Behavioral & Mental Health Services (Q519).', null, 'Q4 - NURSING, NURSING HOME, EVAL/SCREEN', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q403', 'MEDICAL- EVALUATION/SCREENING', '2024-04-30', null, 'Medical Evaluation and Screening Services', 'Healthcare provider services to complete the following: physical examinations to determine Fitness for duty, Military Entrance exams, Reserve and National Guard exams, Aerospace Exams, Disability Evaluation exams, Occupational Health Screening exams (not the providers), Public Health Screening Services (not providers).', 'Managed Healthcare Contracts (Q201), Occupational and Public Healthcare Providers (Q533), Family, Internal Medicine and Aerospace Physicians (Q509)', null, 'Q4 - NURSING, NURSING HOME, EVAL/SCREEN', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q5', 'MEDICAL, DENTAL, AND SURGICAL SVCS', '1979-10-01', null, null, null, null, null, 'Q - MEDICAL SERVICES', null, null, null, null, null),
  ('Q501', 'MEDICAL- ANESTHESIOLOGY', '2024-04-30', null, 'Anesthesiology Services', 'Anesthesiologists (MD); Anesthesiology Technicians, and Pain Services', 'Pharmacology (pharmacologists), pharmaceuticals related services (Q517); registered nurse; nursing assistant; medical assistant (Q401), Certified Registered Nurse Anesthetists (CRNA) (Q401)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q502', 'CARDIOLOGY', '2024-04-30', null, 'Cardiology', 'Physicians (MD & DO) and Physician Assistants working in Cardiology and Interventional Cardiology, Cardiac Catheterization Technologist, Cardiovascular/Echocardiographer Technologist, and telemetry technicians.', 'Cardiothoracic Surgeons (Q524), Interventional Radiologist (Q522), Vascular Surgeons (Q523 Surgery), Registered nurses (RNs), Licensed Practical/Vocational Nurses (LPN/LVN), Medical Assistant, Nursing Assistant, Advanced Practice Registered Nurses (APRN), and Clinical Nurse Specialists (also APRNs) (Q401, Nursing), Surgical Technologist (Q523 Surgery), Radiology Technician or Technologist (Q522 Radiology) and Medical and Surgical Equipment, Instruments and Supplies (6515).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q503', 'MEDICAL- DENTISTRY', '2024-04-30', null, 'Dentistry Services', 'Family/General Dentists, pediatric dentistry, endodontist, periodontist, prosthodontist, oral & maxillofacial pathologist, oral and maxillofacial surgeon, oral surgery technicians, dental hygienist, dental assistants, and dental laboratory technicians.', 'Radiology Technicians and Assistants (Q522 Radiology), Registered Nurses, Advanced Practice Registered Nurses, Clinical Nurse Specialists, Licensed Practical Nurses/Licensed Vocational Nurses, Medical and Nursing Assistants (Q401 Nursing), Operating Room Technicians (Q523 Surgery), Dental Instruments, Equipment, and Supplies (6520), and Dental Imaging Equipment and Dental Imaging Supplies (6525).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q504', 'MEDICAL- DERMATOLOGY', '2024-04-30', null, 'Dermatology Services', 'Dermatology Physicians who specialize in adult & pediatric dermatology, Physicians Assistants who specialize in dermatology, Dermatopathologist, dermatologic technicians/technologists.', 'Family & Internal Medicine Physicians (both MD’s and DO’s) (Q509), Family & Internal Medicine Physician Assistants (Q509), Pediatricians/Pediatrics (Q516), Plastic Surgeons (Q523 Surgery), Otolaryngologist/ENT (Q514), Advanced Practice Registered Nurses, Clinical Nurse Specialists, Registered Nurses, Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401-Nursing).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q505', 'MEDICAL- GASTROENTEROLOGY', '2024-04-30', null, 'Gastroenterology Services', 'Physicians (MD & DO) and Physician Assistants working in adult and pediatric Gastroenterology (GI).', 'Colorectal, General or Trauma Surgeons (Q523 Surgery), Family or Internal Medicine Physicians (Q509), Registered nurses (RNs), Licensed Practical/Vocational Nurses (LPN/LVN), Medical Assistant, Nursing Assistant, Advanced Practice Registered Nurses (APRN), and Clinical Nurse Specialists (also APRNs) (Q401, Nursing), Surgical Technologist (Q523 Surgery), Radiology Technician or Technologist (Q522 Radiology) and Medical and Surgical Equipment, Instruments and Supplies (6515).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q507', 'OBSTETRICS & GYNECOLOGY', '2024-04-30', null, 'Obstetrics & Gynecology', 'Physicians (MD & DO) and Physician Assistants working in Obstetrics & Gynecology.', 'Registered nurses (RNs), all specialities, that provide direct care to patients (synchronous and asynchronous). This includes RN Case Management, RN Surgical Case Reviewer, Licensed Practical/Vocational Nurses (LPN/LVN), LPN/LVN Case Management, Medical Assistant, Nursing Assistant, Advanced Practice Registered Nurses (APRN {NP}), in all sub-specialties including Certified Nurse Midwives, and Clinical Nurse Specialists (also APRNs) in all sub-specialities (Q401, Nursing). Urogynecology (Q525 Urology) and Physical Therapists working in pelvic floor dysfunction therapy (Q518 Physical Medicine & Rehabilitation), Pediatrician (Q516 Pediatrics), Reproductive Endocrinologists (Q530 Endocrinology), Gynecologic Oncology Services (Q508 Hematology & Oncology).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q508', 'HEMATOLOGY & ONCOLOGY', '2024-04-30', null, 'Hematology & Oncology', 'Hematologists and Oncologists (both MD’s and DO’s) and physician assistants that specialize in hematology and/or oncology for adults and children.', 'Advanced Practice Registered Nurses, Clinical Nurse Specialists, Registered Nurses, Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401-Nursing), Family & Internal Medicine Services (Q509), Pediatric Medicine (Q516), Surgical Oncologists (Q523 Surgery), Pediatric Surgical Oncologists (Q523), Radiation Oncology (Q522 Radiology).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q509', 'FAMILY & INTERNAL MEDICINE SERVICES', '2024-04-30', null, 'Family & Internal Medicine Services', 'Family & Internal Medicine Physicians (both MD’s and DO’s), Family & Internal Medicine Physician Assistants, Aerospace Medicine Physicians & Services, Preventive Medicine Physicians & Services, Allergy/Immunology Physicians & Services, Infectious Disease Physicians & Services, Rheumatology Physicians & Services, Gerontology Physicians', 'Advanced Practice Registered Nurses, Clinical Nurse Specialists, Registered Nurses, Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401-Nursing), Psychiatrists (Q 519 Behavioral & Mental Health), Pediatrics (Q516), Dermatology (Q504), Endocrinology (Q530), Gastroenterology (Q505), Hematology & Oncology (Q508), Obstetrics & Gynecology (Q507), Cardiology (Q502), Neurology (Q510)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q510', 'MEDICAL- NEUROLOGY', '2024-04-30', null, 'Neurology Services', 'Neurologist, Neurology Services, Neurology Technician, Neurology Stroke Physician Services, Electroencephalographic Technologist (EEG); Neurophysiologic Intraoperative Monitoring Technologist (CNIM); Long Term Monitoring Technologists (CLTM); Autonomic Testing Professionals (CAP) Neurophysiological Monitoring Services, Neuromonitoring Services, Sleep Medicine Services.', 'Excludes Neurosurgeons/Neurosurgery, Neurosurgery technicians (Q523), Physical Medicine & Rehabilitation Physicians/Physiatrists (Q518), Orthopaedic Surgeons (Q523, Family Practice Physicians, Hospice and/or Palliative Care Physicians (Q509). These specialties will be included with their respective medical category. Neurological/neurosurgical instruments, equipment, supplies such as EEG Equipment, Neurostimulators, and Spinal Implants should be aligned to 6515 - Medical/Surgical Equipment, Instruments, and Supplies.', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q511', 'OPHTHALMOLOGY & OPTOMETRY', '2024-04-30', null, 'Ophthalmology & Optometry', 'Ophthalmologists, Optometrists, Opticians, Ophthalmology & Optometry Technicians', 'Plastic Surgeons specializing in eye surgery (Q523 Surgery), General or Trauma surgeons (Q523 Surgery), Otolaryngology/ENT Surgeons (Q514), Surgical Technicians (Q523 Surgery), Anesthesia (Q501), Registered Nurses (RNs), LPNs/LVNs, Advanced Practice Registered Nurses, and Clinical Nurse Specialists (Q401 Nursing), Ophthalmic Instruments, Equipment & Supplies (6540), Medical and Surgical Instruments, Equipment, and Supplies (6515).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q513', 'ORTHOPEDIC SURGERY SERVICES', '2024-04-30', null, 'Orthopedic Surgery Services', 'Orthopedic surgeons and physician assistants specializing in orthopedics, orthopedic technicians, orthopedic cast technicians, orthotist/prosthetist.', 'Advanced Practice Registered Nurses, Clinical Nurse Specialists, Registered Nurses (all specialties), Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401-Nursing), all other surgical specialties (Q523 Surgery), Surgical Technicians (Q523 Surgery), medical and surgical instruments, equipment & supplies (6515), imaging equipment and supplies (6525), and any services under Physical Medicine and Rehabilitation (Q518).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q514', 'MEDICAL- OTOLARYNGOLOGY', '2024-04-30', null, 'Otolaryngology Services', 'Otolaryngologists (ENT) Physicians who specialize in adult & pediatric ENT, Physicians Assistants who specialize in ENT, ENT technicians/technologists, audiologists and audiology technicians/ technologists.', 'Family & Internal Medicine Physicians (both MD’s and DO’s) (Q509), Pediatricians/Pediatrics (Q516), Advanced Practice Registered Nurses, Clinical Nurse Specialists, Registered Nurses, Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401-Nursing), Speech Therapists and Physical and Occupational Therapists (Q518 Physical Medicine & Rehabilitation).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q515', 'MEDICAL- PATHOLOGY', '2024-04-30', null, 'Pathology Services', 'Services directly provided by a Pathologist, this may include surgical pathology, cytopathology, and forensic pathology, etc. Also includes technicians related to pathology such as Cytotechnologists, Phlebotomy Technicians, Medical Laboratory Technicians, Histotechnicians, Medical Laboratory Technologists, and Medical Laboratory Assistants.', 'All services performed by a reference laboratory (Q301). Hematology/Oncology (Q508), Laboratory equipment (6632 or 6640).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q516', 'MEDICAL- PEDIATRIC', '2024-04-30', null, 'Pediatric Services', 'Pediatricians and physician assistants specializing in pediatric primary medicine, medicine sub-specialties and early childhood assessments.', 'Advanced Practice Registered Nurses (all), Clinical Nurse Specialists, Registered Nurses, Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401-Nursing), Pediatric surgical sub-specialties, (all fall under Q523, Surgery), Pediatric Psychiatry/Psychology (Q519 Behavioral & Mental Health), Pediatric Dentistry (Q503).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q517', 'PHARMACY SERVICES', '2024-04-30', null, 'Pharmacy Services', 'Pharmacists, Clinical Pharmacists, Pharmacologists, Pharmacy Technicians, Virtual Pharmacy Services', 'Drugs and Biologicals (6505), Medicated Cosmetics and Toiletries (6508), Drugs and Biologicals, Veterinary Use (6509), Medical and Surgical Instruments, Equipment and Supplies {i.e. Medication dispensing machines} (6515), Hospital Furniture, Equipment, Utensils and Supplies {i.e. pharmacy specific furniture} (6530), Pharmacy Software (DA10)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q518', 'MEDICAL- PHYSICAL MEDICINE/REHABILITATION', '2024-04-30', null, 'Physical Medicine and Rehabilitation Services', 'Physical Medicine & Rehabilitation Physicians/Physiatrists, Speech Therapists, Occupational Therapists (OT), Physical Therapists (PT), Occupational Therapy Assistants (OTA), Physical Therapy Assistants (PTA)', 'Excludes Neurologists, Neurosurgeons/Neurosurgery, Neurology/Neurosurgery technicians (EEG, EMG testing) Orthopaedic Surgeons, Family Practice Physicians, Hospice and/or Palliative Care Physicians. These specialties will be included with their respective medical category.', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q519', 'BEHAVIORAL AND MENTAL HEALTH', '2024-04-30', null, 'Behavioral and Mental Health', 'All inpatient and outpatient clinical behavioral and mental health professionals: Psychiatrists, Clinical Psychologists, Advanced Practice Registered Nurses/Nurse Practitioners (certified in psychiatric/mental health), Certified Drug and Substance Counselor, Marriage and Family Counselor, Psychiatric Technician, Psychometrist, Recreational Therapist, Registered Art Therapist. Also includes psychiatric evaluation services.', 'Excludes Licensed Clinical Social Workers and Social Workers in Case Management (covered under Social Work PSC Q528). If there is a requirement for mental or behavioral health Occupational Therapists (OT), Physical Therapists (PT) or OT or PT assistants, this can be found under Q518, Physical Medicine/Rehabilitation Medicine (PM&R). Registered Nurses (RN, psychiatric specialty) and Licensed Practical/Vocational Nurses (LPNs/LVNs, psychiatric specialty), can be found in Q401 Medical-Nursing. Last, Q519 excludes non-clinical services covered under G series codes.', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q520', 'MEDICAL- PODIATRY', '2024-04-30', null, 'Podiatry Services', 'Doctor of Podiatric Medicine (DPM); podiatrist', '(Q518); Dermatology (Q504)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q521', 'MEDICAL- PULMONARY', '2024-04-30', null, 'Pulmonary Services', 'Pulmonary medicine', 'Otolaryngology (Q514); Cardiology (Q502)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q522', 'MEDICAL- RADIOLOGY', '2024-04-30', null, 'Radiology Services', 'Radiologists, Interventional Radiologists, Radiology Technicians and Assistants, Diagnostic Medical Sonographer (Ultrasound Technicians), Fluoroscopy Technologists, Computed Tomography (CT) Technologists, Magnetic Resonance Imaging (MRI) Technologists, Radiation Oncologist, Radiation Therapy, Certified Medical Dosimetrist, Medical Physicist and Radiation Safety Officer.', 'Radiology Equipment (6525), Nuclear Medicine Physicians & Technologists (Q527 Nuclear Medicine), Cardiac Catheterization Lab (Q502 Cardiology)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q523', 'MEDICAL- SURGERY', '2024-04-30', null, 'Surgery Services', 'General, Trauma, Colorectal, Plastics/Reconstructive, Vascular, Neurosurgeons, Transplant, Oncologic Surgery, Pediatric Surgery, Perfusionists, Surgical Technician (ST), Central Sterile Supply Technicians (CST)/Sterile Processing Department (SPD)Technicians, purchased sterile processing services.', 'Anesthesiology (Q501), Anesthesia Technicians (501), Pain Management Services (Q501), Certified Registered Nurse Anesthetists, Advanced Practice Registered Nurses, Clinical Nurse Specialists, Registered Nurses (all specialties), Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401-Nursing), Obstetrics & Gynecology (Q507), Oral Surgeons (Q503-Dentistry), Orthopedic Surgeon & Technician (Q513) Podiatry (Q520), Ophthalmology Surgeon &Technician (Q511) Otolaryngology Physician &Technician (Q514), Interventional Radiology (Q522 Radiology), Cardio-Thoracic Surgery (Q524), Urologist & Urology Technician (Q525), Interventional Cardiology (Q502 Cardiology)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q524', 'CARDIOTHORACIC SURGERY', '2024-04-30', null, 'Cardiothoracic Surgery', 'Cardiothoracic Surgeons/Physicians (both MD’s and DO’s), Physician Assistants in the cardiothoracic specialty.', 'Cardiologists, Cardiology medical specialties & Interventional/Cath Lab, (Q502 Cardiology), Vascular Surgeons (Q523 Surgery) Pulmonary Physicians (Q521 Pulmonary), Registered Nurses, Licensed Practical Nurses, Advanced Practice Registered Nurses, Clinical Nurse Specialists, Medical & Nursing Assistants (Q401 Nursing), Cardiothoracic Surgical Technicians (Q523 Surgery), medical and surgical instruments, equipment and supplies (6515).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q525', 'MEDICAL- UROLOGY', '2024-04-30', null, 'Urology Services', 'Urology Surgeons (both MD’s and DO’s) (includes general urology surgeons, urogynecology, neurourology, pediatric urology and urologic oncologic surgery), Physician Assistants in the urologic specialty, and urology technicians.', 'Obstetrics & Gynecology (Q507), General/Trauma surgeons (Q523), Registered Nurses, Licensed Practical Nurses, Advanced Practice Registered Nurses, Clinical Nurse Specialists, Medical & Nursing Assistants (Q401 Nursing), Surgical Technicians (Q523 Surgery), Medical and Surgical Instruments, Equipment and Supplies (6515).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q527', 'MEDICAL- NUCLEAR MEDICINE', '2024-04-30', null, 'Nuclear Medicine', 'Nuclear Medicine Physicians & Technologists (Q527 Nuclear Medicine Radiologists), Physician Assistants that work in Nuclear Medicine.', 'General Radiologist and Radiology Technicians and Assistants, Diagnostic Medical Sonographer (Ultrasound Technicians), Fluoroscopy Technologists, Computed Tomography (CT) Technologists, Magnetic Resonance Imaging (MRI) Technologists, Interventional Radiologists, Radiation Oncologist, Radiation Therapy, Certified Medical Dosimetrist, Medical Physicist and Radiation Safety Officer (all in Q522 Radiology), Cardiac Catheterization Lab (Q502 Cardiology), Radiology Equipment (6525), Registered Nurses, Advanced Practice Registered Nurses, Clinical Nurse Specialists, Licensed Practical Nurses/Licensed Vocational Nurses, Medical and Nursing Assistants (Q401 Nursing).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q528', 'SOCIAL WORK', '2024-04-30', null, 'Social Work', 'Licensed Clinical Social Workers, Social Workers in Case Management, and clinical social work for mental and behavioral health treatment and substance abuse treatment.', 'All inpatient and outpatient clinical behavioral and mental health professionals under Q519 Behavioral and Mental Health, which includes Psychiatrists, Clinical Psychologists, Advanced Practice Registered Nurses/Nurse Practitioners (certified in psychiatric/mental health), Certified Drug and Substance Counselor, Marriage and Family Counselor, Psychiatric Technician, Psychometrist, Recreational Therapist, Registered Art Therapist. Nurse Case Managers would use PSC Q401, Nursing. Also excludes Residential Re-Entry and Residential Housing Services (G004)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q529', 'EMERGENCY MEDICINE SERVICES', '2024-04-30', null, 'Emergency Medicine Services', 'Emergency Medicine Physicians (both MD’s and DO’s), Emergency Medicine Physician Assistants, Emergency Medical Technician (EMT), Advanced Emergency Medical Technician, Paramedics, purchased Emergency Medical Services (EMS (EMT/Paramedic pre-hospital) and purchased patient care during transport. Emergency Medicine physicians and physician assistants may specialize in various subspecialties however if their primary training is in emergency medicine they will be captured under this PSC, Emergency Medicine Services.', 'Advanced Practice Registered Nurses (all, including ER specialty), Clinical Nurse Specialists, Registered Nurses (all, including ER specialty), Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401, Nursing), medical and medical sub-specialty providers/services (Q509 Family & Internal Medicine Services), surgical subspecialty providers/services (Q523 Surgery), pediatric and pediatric sub-specialty providers/services (Q516)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q530', 'ENDOCRINOLOGY MEDICINE SERVICES', '2024-04-30', null, 'Endocrinology Medicine Services', 'Endocrinologists (both MD’s and DO’s), Physician Assistants specializing in endocrinology', 'Advanced Practice Registered Nurses (all specialties), Clinical Nurse Specialists, Registered Nurses, Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401-Nursing), Pediatrics (Q516), Family & Internal Medicine Services (Q509), endocrine equipment for disease processes {diabetes, high blood pressure, etc.} (6515 Medical & Surgical Instruments, Equipment, and Supplies), endocrine drugs and biologicals (6505 Drugs & Biologicals)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q531', 'NEPHROLOGY MEDICINE SERVICES', '2024-04-30', null, 'Nephrology Medicine Services', 'Nephrologists (both MD’s and DO’s), Physician Assistants specializing in nephrology, Dialysis/hemodialysis technicians, contracted dialysis and hemodialysis service.', 'Advanced Practice Registered Nurses (all specialties), Clinical Nurse Specialists, Registered Nurses, Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401-Nursing), Pediatrics (Q516), Family & Internal Medicine Services (Q509), dialysis and nephrology specific equipment (6515 Medical & Surgical Instruments, Equipment, and Supplies), nephrology specific drugs and biologicals (6505 Drugs & Biologicals)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q532', 'CHIROPRACTIC & ACUPUNCTURE SERVICES', '2024-04-30', null, 'Chiropractic & Acupuncture Services', 'Chiropractors and acupuncturists', 'Advanced Practice Registered Nurses, Clinical Nurse Specialists, Registered Nurses (all specialties), Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401-Nursing), Physiatrists, Occupational and Physical Therapists (Q518 Physical Medicine and Rehabilitation), Orthopedics, Orthopedic Technicians and Orthotists (Q513 Orthopedics), Acupuncture training, as with all other technical training programs, use (U006 Education/Training- Vocational/Technical).', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q533', 'OCCUPATIONAL & PUBLIC HEALTH SERVICES', '2024-04-30', null, 'Occupational & Public Health Services', 'Occupational & Public Health Physicians (both MD’s and DO’s), Occupational & Public Health Physician Assistants, Medical & Health Services Managers, Industrial Hygienists, Environmental Scientists & Specialists, Health & Safety Engineers, Biostatisticians for Occupational & Public health, Epidemiologists, Health Educators, Emergency Management Director, Social and Community Service Manager.', 'Family Practice & Internal Medicine Physicians (Q509), Preventive Medicine Physicians & Services (Q509), Infectious Disease (Q509), Emergency Medicine Physicians/Physician Assistants, Emergency Medical Technicians and Paramedics (Q529 Emergency Medicine Services), Advanced Practice Registered Nurses, Clinical Nurse Specialists, Registered Nurses (all specialties), Licensed Practical/Vocational Nurses, Nursing/ Medical Assistants (all fall under Q401-Nursing), Psychologists (Q519 Behavioral & Mental Health), Occupational and Physical Therapists (Q518 Physical Medicine and Rehabilitation)', null, 'Q5 - MEDICAL, DENTAL, AND SURGICAL SVCS', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q6', 'CERTIFIED MEDICAL SUPPORT', '2015-10-01', null, 'Certified Medical Support', null, null, null, 'Q - MEDICAL SERVICES', null, null, null, null, null),
  ('Q601', 'MEDICAL CODING AND AUDITING', '2024-04-30', null, 'Medical Coding and Auditing', 'Services directly provided by a Medical Coder or Auditor; Medical Coding; Medical Coding Auditor; Ambulatory Procedure Coders; Outpatient Auditing Services; Medical Auditing Specialist; Outpatient Medical Coders', 'Coding and auditing outside of Medical field. Coder; Audit readiness; IP Auditors; Internal Audit; Coding Books; Professional Coding/ Auditing Services; Support – Management: Auditing (R704)', null, 'Q6 - CERTIFIED MEDICAL SUPPORT', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q602', 'MEDICAL RECORDS', '2024-04-30', null, 'Medical Records', 'Services directly provided by a Medical Record Keeper. Medical Records Support; Medical Records Technician/Clerk; Medical Records Storage Services; Medical Records Storage and Management', 'Physical Records Management Storage (R616); Electronic Records Management (R617); Financial Records; Legal Records, Medical Appointing (Q801)', null, 'Q6 - CERTIFIED MEDICAL SUPPORT', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q603', 'MEDICAL TRANSCRIPTIONS', '2024-04-30', null, 'Medical Transcriptions', 'Medical Transcription Services; Medical Transcriptionist; Healthcare Transcription Services; Medical Language Specialist Services', 'General Non-medical Transcription Services; Administrative Transcription (R603); Legal Transcription Services; Support – Administrative: Translation and Interpreting (R608)', null, 'Q6 - CERTIFIED MEDICAL SUPPORT', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q7', 'SPECIALIZED TECHNICAL/ MEDICAL SUPPORT', '2015-10-01', null, 'Specialized Technical/ Medical Support', null, null, null, 'Q - MEDICAL SERVICES', null, null, null, null, null),
  ('Q701', 'SPECIALIZED MEDICAL SUPPORT', '2024-04-30', null, 'Specialized Medical Support', 'Healthcare professionals and programs that do NOT provide direct patient care. This includes but may not be limited to, medical utilization management personnel, medical clinical quality management professionals (for medical credentialing & privileging), health risk management, medical evaluation board personnel, healthcare benefits programs/personnel, health safety programs, patient safety & medical quality program personnel, medical quality assurance programs, medical library, patient advocacy/ liaison programs, medical billing, third party liability, tumor registrar, patient referral management.', 'Any healthcare professional or program that provides direct patient care, whether virtual or in person. The services will be placed in the PSC that best aligns with the care delivery, Occupational and Public Health (Q533)', null, 'Q7 - SPECIALIZED TECHNICAL/ MEDICAL SUPPORT', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q702', 'TECHNICAL MEDICAL SUPPORT', '2024-04-30', null, 'Technical Medical Support', 'Medical Logistics, Biomedical Equipment (Medical Equipment Technician), Medical Supply, Medical Writer/Technical Writer', 'Occupational/Public Health Technicians (Q533), Medical coding (Q601), Medical Billing (Q701), Histology technician (Q515), Wellness/Health Coordinator and Health Coach (Q533), Technical Representative-Medical, Dental, and Veterinary Equipment and Supplies (L065), Sterile Processing Technician (Q523), Medical Technologist (Q515), Physical Therapist (Q518), Non-Medical Technical Support (R425)', null, 'Q7 - SPECIALIZED TECHNICAL/ MEDICAL SUPPORT', null, '10.0', 'Medical', '10.3', 'Healthcare Services'),
  ('Q8', 'CLERICAL MEDICAL SUPPORT', '2015-10-01', null, 'Clerical Medical Support', null, null, null, 'Q - MEDICAL SERVICES', null, null, null, null, null),
